// 驾考科目一 2026新规题库 Part 5 (1046-1320题)
var Q = Q || [];
Q.push(
// ═══════════════════════════════════════════════════════════════
// 一、记分管理综合 (points) — 75题 (1046-1120)
// ═══════════════════════════════════════════════════════════════
{id:1046,cat:"points",type:"choice",q:"2022年记分体系改革取消了哪个记分档次？",opts:["1分","2分","3分","6分"],ans:1,exp:"2022年4月1日起记分体系调整为12/9/6/3/1五档，取消了原有的2分档。新增9分档填补12分和6分之间的空白。2026年继续执行此体系。",tip:"口诀：2022改革——废2分，增9分。记住12/9/6/3/1五档。"},
{id:1047,cat:"points",type:"judgment",q:"2022年记分调整中，准驾车型不符由12分降为9分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"准驾车型不符（如C1驾驶摩托车）在2022年由12分降为9分，是记分改革中降幅最大的调整之一。注意：无证驾驶（从未取得驾驶证）不属于记分范畴，直接行政处罚。",tip:"口诀：准驾不符=9分（不再12分）。C1开摩托=有C1但没D证=9分。"},
{id:1048,cat:"points",type:"choice",q:"驾驶机动车在高速公路、城市快速路上违法停车的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"高速和快速路违法停车在2022年由6分提高到9分。普通道路违法停车视情况记1分或只罚款。高速停车风险极高，处罚加重与此匹配。",tip:"口诀：高速快速路停车=9分（翻倍加重）。普通路=1分。停车分值天地之差。"},
{id:1049,cat:"points",type:"judgment",q:"驾驶机动车时拨打接听手持电话，在高速公路和城市快速路上记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"拨打接听手持电话在普通道路记3分，在高速公路和城市快速路上记9分（2022年加重）。3分仅适用于普通道路，高速快速路处罚更重。",tip:"口诀：开车打电话——普通路3分，高速快速路9分。高速上手机=9分大出血。"},
{id:1050,cat:"points",type:"choice",q:"驾驶机动车遇前方排队或缓行时，借道超车或占用对面车道穿插等候的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"排队加塞（穿插等候）一次记3分。2022年由原2分调整为3分。加塞不仅违规，还破坏交通秩序、引发冲突。",tip:"口诀：加塞插队=3分。老实排队是美德，插队扣分又丢人。"},
{id:1051,cat:"points",type:"judgment",q:"驾驶人在一个记分周期内累积记分达到12分后，拒不参加学习也不接受考试的，公安机关交通管理部门将公告其驾驶证停止使用。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"记满12分的驾驶人应参加7天学习和科目一考试。如果驾驶人拒不参加学习和考试，驾驶证将被公告停止使用——意味驾驶证暂时失效，驾车将被视为无证驾驶。",tip:"口诀：12分了不学不考=驾驶证被公告停用。停用后再开车=无证驾驶。"},
{id:1052,cat:"points",type:"choice",q:"机动车驾驶人在实习期内发生的道路交通安全违法行为，记分是否计入实习期结束后的下一个记分周期？",opts:["不计入","计入实习期所在记分周期，与非实习期相同","双倍计入","延长实习期才计入"],ans:1,exp:"实习期内发生的违法记分与正常记分周期制度完全一致，计入当前记分周期。实习期内记满12分的，注销其实习准驾车型驾驶资格。延长实习期仅适用于大中型客货车驾驶人。",tip:"口诀：实习期记分不变（不翻倍、不延期计入），正常记。但12分满=注销实习驾照。"},
{id:1053,cat:"points",type:"judgment",q:"持有大型客车、重型牵引挂车驾驶证的驾驶人在实习期内记6分以上但未达到12分的，实习期延长一年。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"AB类（大中型客货车）驾驶证实习期内记6分以上未满12分的，实习期延长一年。在延长实习期内再次记6分以上未满12分的，注销准驾车型资格。C类驾驶证无此规定。",tip:"口诀：A/B证实习期记6-11分=实习期延长1年。延长后又记6分=注销。C证没这规矩。"},
{id:1054,cat:"points",type:"choice",q:"驾驶人在一个记分周期内有两次以上达到12分或累积达到24分以上的，需参加什么考试？",opts:["只需重考科目一","科目一+科目三道路驾驶技能","科目一+科目二","全部科目重考"],ans:1,exp:"一个周期内两次12分或24分以上=科目一+科目三（道路驾驶技能）考试。这比单次12分（仅科目一）更严格，体现了分级管理的原则——累积越多，惩戒越重。",tip:"口诀：12分=学7天+考科一；24分+（或两次12分）=学+考科一+科三路考。"},
{id:1055,cat:"points",type:"judgment",q:"机动车驾驶人在记分周期内累积记分未满12分，但尚有罚款未缴纳的，记分可以予以清除。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"罚款未缴纳=记分不清零！记分转入下一周期。罚款缴纳是记分清零的必要前提。许多驾驶人忽视了这一点，导致记分累积到下一周期，增加了被扣证的风险。",tip:"口诀：罚款没交=记分带到来年。分清了钱没清=分白清。交罚款是关键！"},
{id:1056,cat:"points",type:"choice",q:"学法减分一个记分周期内最多可减免几分？",opts:["3分","6分","9分","12分"],ans:1,exp:"学法减分一个周期最多减免6分。每次学习30分钟（网上）并通过考试（20题答对18题）可减免1分；参加线下交通安全公益活动1小时也可减免1分。学法减分不能预存，即减即生效。",tip:"口诀：学法减分=周期封顶6分。网上学半小时+答题=减1分。一年最多减6次。"},
{id:1057,cat:"points",type:"judgment",q:"学法减分可以用于抵扣已经发生的所有记分，包括12分的严重违法行为。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分有适用范围限制：仅可用于减免记分分值在6分以下（含6分）的交通违法行为。12分违法行为（如酒驾、高速倒车等）不能用学法减分抵扣。",tip:"口诀：学法减分有门槛——只能减免6分及以下的违法行为记分。12分档次的不给减。"},
{id:1058,cat:"points",type:"choice",q:"以下哪种情形可以申请学法减分？",opts:["驾驶证被扣留期间","上一个记分周期有两次以上满分记录","本记分周期内累积记分未满12分的驾驶人","驾驶证逾期未换证期间"],ans:2,exp:"学法减分申请条件：本周期记分未满12分、驾驶证未被扣留/暂扣/吊销/注销、无满分记录（上周期且本周期无满分）。驾驶证异常状态期间不得申请。",tip:"口诀：学法减分前提=证正常+分未满12+无满分史。证被扣了别想减。"},
{id:1059,cat:"points",type:"judgment",q:"通过学法减分考试合格后，系统将在24小时内自动减免记分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"网上学法减分考试合格后，系统一般在24小时内自动完成记分减免。考试不合格的，可以在24小时内申请补考，补考最多2次。",tip:"口诀：学法减分通过=24小时内自动到账。没通过=24小时内可补考2次。"},
{id:1060,cat:"points",type:"choice",q:"机动车驾驶人在实习期内能否通过学法减分减免记分？",opts:["可以，与正式期相同","不可以","可以减但不超过3分","只有C类驾驶证可以"],ans:1,exp:"实习期内驾驶人不得申请学法减分。实习期驾驶人驾驶经验不足，更应严格要求。同时，驾驶证处于实习期属于限制状态，不符合学法减分申请条件。",tip:"口诀：实习期=不能学法减分。新手没有减免特权，老老实实不违规。"},
{id:1061,cat:"points",type:"choice",q:"驾驶校车、中型以上载客载货汽车、危险品运输车在高速公路以外的道路上超速50%以上的，一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:1,exp:"营运/专用车辆（校车、大中型客货车、危化品车）在普通道路超速50%以上记9分。这些车辆自重大、载人多/货物危，事故后果更严重，处罚针对性更强。私家车在普通路超速50%以上记6分。",tip:"口诀：营运车超速50%以上——高速12分，普通路9分。私家车超50%——高速12分，普通路6分。"},
{id:1062,cat:"points",type:"judgment",q:"驾驶机动车载运爆炸物品、易燃易爆化学物品等危险物品，未按指定时间、路线、速度行驶或未悬挂警示标志的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"危险品运输未按规定行驶（时间/路线/速度不符）或未悬挂警示标志=记6分。若未取得危化品运输许可擅自运输，则构成更严重的违法行为。",tip:"口诀：危化品车不按规定走=6分。时间路线速度一个都不能错。"},
{id:1063,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶时，驾驶人未按规定系安全带的，一次记几分？",opts:["不记分，仅罚款","1分","3分","6分"],ans:1,exp:"驾驶人未系安全带一次记1分并处罚款。乘车人未系安全带处警告或罚款（不记分）。2022年起纳入记分管理，以强化安全带的规范使用。",tip:"口诀：驾驶人不系安全带=1分+罚款。乘客不系=只罚款不记分。"},
{id:1064,cat:"points",type:"judgment",q:"驾驶机动车在高速公路上行驶低于规定最低时速的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路低于最低限速（一般60km/h）行驶的一次记3分。龟速行驶与超速同样危险——速度差过大导致后车频繁变道，增加碰撞风险。2022年新增此记分项。",tip:"口诀：高速太慢=3分。快速车道龟速党，记分罚款不冤枉。"},
{id:1065,cat:"points",type:"choice",q:"机动车驾驶人造成致人死亡或轻伤以上交通事故后逃逸、尚不构成犯罪的，一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:2,exp:"致人死伤后逃逸（尚不构成犯罪）=12分。若构成交通肇事罪，则吊销驾驶证并终身禁驾，且追究刑事责任。逃逸性质极其恶劣，处罚最重。",tip:"口诀：伤人逃逸=12分起步。构成犯罪=吊销+终身禁驾+坐牢。出了事别跑。"},
{id:1066,cat:"points",type:"judgment",q:"驾驶机动车造成财产损失交通事故后逃逸、尚不构成犯罪的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"财产损失交通事故后逃逸（无人身伤亡、不构成犯罪）=记6分。与致人死伤逃逸（12分）区分。无论是人身还是财产事故，逃逸都是错上加错。",tip:"口诀：撞车逃逸=6分；撞人逃逸=12分。逃逸成本永远比老老实实处理高。"},
{id:1067,cat:"points",type:"choice",q:"使用伪造、变造的机动车号牌、行驶证、驾驶证、校车标牌或者使用其他机动车号牌、行驶证的，一次记多少分？",opts:["6分","9分","12分","吊销驾照并处拘留"],ans:2,exp:"使用假牌假证=12分+收缴+扣留车辆+15日以下拘留+2000-5000元罚款。与遮挡真牌（9分）有本质区别——造假=12分，遮真=9分。",tip:"口诀：假牌假证=12分+拘留+罚款（造假是重罪）。真牌遮挡=9分。假VS真牌区别大。"},
{id:1068,cat:"points",type:"judgment",q:"代替实际驾驶人接受交通违法行为处罚和记分牟取经济利益的，被替人记12分，代替人也记12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"买卖分双方均记12分——这是2022年新增的严厉处罚。同时没收违法所得，并纳入信用记录。替人消分=自毁驾照+钱财两空。",tip:"口诀：买分卖分双方都12分+罚款。代扣分赚钱=驾照清零+信用污点。得不偿失。"},
{id:1069,cat:"points",type:"choice",q:"驾驶机动车在道路上违反道路交通信号灯通行的（闯红灯），一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"闯红灯一次记6分。值得注意的是2022年改革中闯红灯维持6分未变——它是交通违法中最常见的高分值记分项之一。黄灯抢行同样危险，虽然不记分但可能引发严重事故。",tip:"口诀：闯红灯=6分（铁打的，一直没变过）。宁等三分不抢一秒。"},
{id:1070,cat:"points",type:"judgment",q:"驾驶机动车在道路上行驶时，驾驶人未按规定系安全带一次记1分，乘车人未系安全带也记1分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"驾驶人未系安全带记1分；乘车人未系安全带处警告或罚款但不记分。记分是针对驾驶人的违法行为记录，乘客不记分只罚款。",tip:"口诀：驾驶人不系=1分+罚款；乘客不系=只罚款不记分。要记分只记驾驶人的。"},
{id:1071,cat:"points",type:"choice",q:"以下哪项违法行为一次记9分？",opts:["驾驶与准驾车型不符的机动车","饮酒后驾驶机动车","使用伪造号牌","造成事故后逃逸致人死亡"],ans:0,exp:"准驾车型不符=9分（2022年由12分降为9分）。酒后驾车=12分，伪造号牌=12分，致人死亡逃逸构成犯罪=吊销+终身禁驾。准驾不符是唯一记9分的选项。",tip:"口诀：9分的代表=准驾不符。酒驾/假牌/逃逸全是12分级别。"},
{id:1072,cat:"points",type:"judgment",q:"驾驶证被依法扣留、暂扣期间，不得申请学法减分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"学法减分申请条件之一：驾驶证状态正常（未被扣留、暂扣、吊销、注销）。驾驶证异常状态期间不能申请学法减分，必须先处理完导致异常的事项。",tip:"口诀：证不正常（扣了/暂了）=别想学法减分。先恢复证正常再说。"},
{id:1073,cat:"points",type:"choice",q:"一个记分周期内,记分达到12分后,按规定参加满分学习和考试,考试合格后记分予以清除并发还驾驶证。如果考试不合格，怎么办？",opts:["驾驶证被吊销","10日后重新预约考试，直至合格","直接降级处理","永久扣留驾驶证"],ans:1,exp:"满分学习考试不合格的，10日后可重新预约考试。考试次数不限，但驾驶证在此期间持续处于扣留状态，不得开车。拒不参加学习或考试=驾驶证被公告停用。",tip:"口诀：满分考试不过=10天后重考，考到过为止。但没考过之前不能开车。"},
{id:1074,cat:"points",type:"judgment",q:"记分周期为12个月，从机动车驾驶证初次领取之日起计算。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"记分周期=初次领证日期起12个月。例如某驾驶人4月15日领证，其记分周期为每年4月15日至次年4月14日。不是按自然年（1月1日-12月31日）计算。",tip:"口诀：记分周期=从你拿驾照那天起算12个月。不是1月1日！每个人周期不同。"},
{id:1075,cat:"points",type:"choice",q:"驾驶人将机动车交由未取得机动车驾驶证的人驾驶的，除罚款外还会面临什么处罚？",opts:["记6分","记12分","可以吊销驾驶证","记9分"],ans:2,exp:"将车交给无证人驾驶=罚款200-2000元+可以并处吊销驾驶证。这不是记分问题，而是直接吊销驾照的严重违法。出借车辆前务必核实对方是否有有效驾驶证。",tip:"口诀：借车给无证人开=可以吊销你驾照！不是记分是吊销。借车前看证！"},
{id:1076,cat:"points",type:"judgment",q:"驾驶人在一个记分周期内累积记分达到12分，公安机关扣留驾驶证后，驾驶人只要缴纳罚款就可以领回驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"12分=扣证+参加7天学习+通过科目一考试，三者缺一不可才能领回驾驶证。只缴罚款不参加学习和考试，不能领回驾驶证。",tip:"口诀：12分=扣证+学7天+考科一→合格才还证。光交钱不行，得学+考。"},
{id:1077,cat:"points",type:"choice",q:"以下哪种情形不会被记12分？",opts:["醉酒驾驶机动车","造成致人死亡的交通事故后逃逸尚不构成犯罪","使用伪造的机动车号牌","驾驶时拨打接听手持电话"],ans:3,exp:"驾驶时拨打手持电话=普通路3分/高速9分，不是12分。醉酒驾车、致人死亡逃逸、使用伪造号牌均为12分。注意区分分值等级。",tip:"口诀：打电话不是12分！（普通3/高速9）。酒驾/假牌/伤人逃逸才是12分级别。"},
{id:1078,cat:"points",type:"judgment",q:"驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记12分，并吊销驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速倒车/逆行/掉头记12分，但不直接吊销驾驶证——记12分后扣留驾驶证，需参加满分学习和考试。吊销和扣留不同：扣留是暂时性的，吊销是永久性的。",tip:"口诀：高速倒逆掉=12分+扣证（不是吊销！）。扣留=暂时的，吊销=永久的。区别很大。"},
{id:1079,cat:"points",type:"choice",q:"驾驶机动车运载超限的不可解体物品未悬挂明显标志的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:2,exp:"载运超限物品未挂标志=记6分。包括未按规定时间路线行驶、未悬挂明显超限标志等。超限运输本身需要特殊审批，未按规定执行安全隐患极大。",tip:"口诀：超限运输不按规定=6分。大件超限运输=先审批+按指定路线+挂标志。"},
{id:1080,cat:"points",type:"judgment",q:"驾驶校车在高速公路上超速20%以上未达50%的，一次记12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"校车载有学生在高速上超速20%以上=12分。校车承载学生安全，超速处罚极为严厉。校车在普通道路超速20%以上未达50%记6分，超速50%以上记9分。",tip:"口诀：校车高速超速20%以上=12分！孩子的生命安全=最高保护等级。"},
{id:1081,cat:"points",type:"choice",q:"驾驶人在驾驶证丢失、损毁、超过有效期或被依法扣留、暂扣期间，能否申请学法减分？",opts:["可以","不可以","只能申请一次","需要交警批准"],ans:1,exp:"驾驶证处于任何异常状态（丢失/损毁/过期/扣留/暂扣）均不能申请学法减分。学法减分要求驾驶证状态完全正常有效。",tip:"口诀：证不正常=学法减分免谈。先把证的问题解决了再来。"},
{id:1082,cat:"points",type:"judgment",q:"学法减分学习考试不合格的，可以在24小时内申请补考，补考次数不限。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分考试不合格，24小时内可申请补考，但补考最多2次（即总共3次机会）。并非不限次数。3次都不合格需重新申请学习。",tip:"口诀：学法减分补考最多2次（共3次机会）。3次不过=从头学起。"},
{id:1083,cat:"points",type:"choice",q:"外国驻华使领馆人员、国际组织驻华代表机构人员的驾驶证累计记分制度与中国公民有何不同？",opts:["不适用记分制度","适用相同的记分制度","单独记分减半","只警告不记分"],ans:1,exp:"在中国境内驾驶机动车的外交人员同样适用中国道路交通安全法律法规和记分制度，无豁免特权。享有外交豁免权并不包括交通违法豁免。",tip:"口诀：外国人在中国开车=跟中国人一样记分！没有外交豁免记分特权。"},
{id:1084,cat:"points",type:"judgment",q:"持境外驾驶证申领中国驾驶证的，境外驾驶证上的记分记录不计入中国驾驶证记分周期。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"境外驾驶证记分记录不转入中国记分系统。但持境外驾驶证换领中国驾驶证时，如有严重违法记录可能影响换领审批。新领的中国驾驶证从零开始记分。",tip:"口诀：境外分不带入境内（从零开始）。但换证时严重违法记录可能影响审批。"},
{id:1085,cat:"points",type:"choice",q:"驾驶机动车在高速公路上行驶，车速超过100km/h时，与同车道前车距离少于多少米属于违反安全距离规定？",opts:["50米","80米","100米","150米"],ans:2,exp:"车速>100km/h时安全距离应不少于100米；车速<100km/h时不少于50米。违反安全距离规定一次不记分但罚款，但因此引发事故将承担相应责任。",tip:"口诀：高速跟车距离——超100码至少100米，低于100码至少50米。100对100，50对50。"},
{id:1086,cat:"points",type:"judgment",q:"驾驶人在一个记分周期内记分虽未满12分但罚款未缴纳的，记分转入下一记分周期。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"罚款未缴=记分结转下一年。这是记分清零的关键前置条件。很多驾驶人不明就里，以为只要分清零就可以了，结果发现上一年度的记分被带到了新周期。",tip:"口诀：罚款不交=分清不零。交了钱分才清，否则带到下一年。"},
{id:1087,cat:"points",type:"choice",q:"以下哪项不属于2026年记12分的交通违法行为？",opts:["酒后驾车","使用伪造驾驶证","高速公路上倒车","驾驶货车超载30%"],ans:3,exp:"货车超载30%以上未达50%=记3分，超载50%以上记6分，均不是12分。只有货车超载100%以上在某些情形才可能记12分。酒后驾车、伪造驾驶证、高速倒车均为12分。",tip:"口诀：货车一般超载≠12分。酒驾/假证/高速倒车才是12分。超载看%分档。"},
{id:1088,cat:"points",type:"judgment",q:"机动车驾驶证被暂扣期间驾驶机动车的，一次记6分并处罚款，可以并处拘留。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"扣证期间开车=记6分+罚款200-2000元+可以并处15日以下拘留。这属于「无有效驾驶证驾驶机动车」的一种情形。扣证期间绝不能碰方向盘。",tip:"口诀：证扣了还开车=6分+罚款+可能拘留。扣证=无证状态，别侥幸。"},
{id:1089,cat:"points",type:"choice",q:"2022年记分改革中，原来是12分的哪些行为被降为了9分？",opts:["准驾车型不符、未悬挂号牌","酒后驾车","使用伪造号牌","高速倒车"],ans:0,exp:"准驾车型不符和未悬挂/遮挡号牌均由12分降为9分（2022年）。这是记分改革中最显著的变化之一。但使用伪造号牌、酒后驾车、高速倒车仍为12分。",tip:"口诀：12→9分两项：准驾不符+遮真牌。假牌/酒驾/高速倒车=仍12分不动。"},
{id:1090,cat:"points",type:"judgment",q:"在普通道路上驾驶机动车超速20%以上未达50%的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"普通道路超速20%-50%：普通载客汽车记3分；中型以上载客载货汽车、校车、危化品车记6分。高速/快速路超速20%-50%：普通车记6分，营运/专用车记12分。",tip:"口诀：普通路超20%-50%——私家车3分，营运车6分。高速上——私家车6分，营运车12分。"},
{id:1091,cat:"points",type:"choice",q:"驾驶人在连续两个记分周期内均累积记分满12分的，驾驶证将会面临什么处理？",opts:["吊销驾驶证","降级换证","满分学习后参加科目一和科目三考试","只需缴罚款"],ans:2,exp:"连续两周期满分=参加满分学习+科目一+科目三路考。对于AB类驾驶证，还可能面临最高准驾车型降级。屡次满分说明驾驶人安全意识和技能存在严重问题。",tip:"口诀：两次满分=学+科一+科三路考。AB证还可能降级。屡教不改的代价。"},
{id:1092,cat:"points",type:"judgment",q:"持有AB类（大中型客货车）驾驶证的驾驶人，在一个记分周期内只要有记分记录，就必须参加审验学习。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"AB类驾驶证有记分（哪怕1分）即须参加不少于3小时的审验学习（道路交通安全法律法规等）。没有记分的可免于审验。这是AB证与C证的显著区别之一。",tip:"口诀：A/B证=有分就要审验学习。哪怕1分也得学。C证没这要求。"},
{id:1093,cat:"points",type:"choice",q:"驾驶机动车在高速公路上以超过规定时速20%以上未达50%的速度行驶，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"高速超速20%-50%：普通载客汽车记6分；中型以上载客载货汽车、校车、危化品车记12分。超速50%以上：所有车辆均记12分。",tip:"口诀：高速超20%-50%——私家车6分，大车/校车/危化品12分。超50%——统统12分。"},
{id:1094,cat:"points",type:"judgment",q:"驾驶机动车在高速公路上超过规定时速50%以上，一次记12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速超速50%以上不分车型，一律记12分。超速50%以上意味着限速120时开到180以上，极其危险——制动距离呈几何级增长，任何突发情况都无法安全应对。",tip:"口诀：超速50%以上=12分全扣。50%是高压线，不管什么车碰了都12分。"},
{id:1095,cat:"points",type:"choice",q:"驾驶机动车在高速公路以外的道路上超速50%以上，私家车（非营运）的一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"普通路超速50%以上：普通私家车=6分；中型以上客货车/校车/危化品车=9分。与高速超50%（一律12分）区分。道路等级不同，处罚力度不同。",tip:"口诀：普通路超速50%以上——私家车6分，营运/专用车9分。高速超50%=统统12分。"},
{id:1096,cat:"points",type:"judgment",q:"学法减分只能通过网上学习考试的方式完成，不能通过参加交通安全公益活动减免。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分有两种方式：①网上学习考试（30分钟学习+20题考试，答对18题减1分）；②线下参加交通安全公益活动（1小时减1分）。两种方式效果等同，累计最多减6分。",tip:"口诀：学法减分双通道——网上学+考，或线下做公益。两路同效，累计最多减6分。"},
{id:1097,cat:"points",type:"choice",q:"驾驶证有效期超过多久未换证将被注销？",opts:["6个月","1年","2年","3年"],ans:1,exp:"超过有效期1年未换证=注销驾驶证。过期不满1年可正常换证；过期1年以上不满3年=重考科目一恢复；过期3年以上=全部作废需重考。",tip:"口诀：过期1年内可换，1-3年考科一，超3年重考全部。换证要及时。"},
{id:1098,cat:"points",type:"judgment",q:"在一个记分周期内累积记分达到12分的，其驾驶证将被吊销。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"12分=扣留（非吊销！）驾驶证+学习+考试。吊销适用于更严重情形（醉驾、二次酒驾、重大事故犯罪等）。扣留=暂时的（考试通过后发还）；吊销=永久的（需重新报考）。",tip:"口诀：12分=扣留不是吊销！扣留=通过考试能拿回，吊销=驾照永远没了要重考。"},
{id:1099,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶违反分道行驶规定（如不按导向车道行驶）的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"不按导向车道行驶（进入导向车道后不按箭头方向行驶）=记1分（2022年由2分降为1分）。压实线变道的违反禁止标线也记1分。闯红灯（违反信号灯）才是6分。",tip:"口诀：导向车道走错=1分。压线变道=1分。闯红灯=6分。分值对应危险程度。"},
{id:1100,cat:"points",type:"judgment",q:"驾驶机动车在道路上逆向行驶的，在普通道路和高速公路上均记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"逆向行驶记分标准：普通道路记3分，高速公路记12分。高速逆行极端危险——与来车方向完全相反，碰撞速度等于两车速度之和，一旦碰撞几乎必死。",tip:"口诀：逆行——普通路3分，高速12分。高速逆行是自杀式驾驶，12分是最低代价。"},
{id:1101,cat:"points",type:"choice",q:"驾驶人在道路上驾驶机动车，血液酒精含量达到多少以上属于饮酒后驾驶？",opts:["10mg/100ml","20mg/100ml","50mg/100ml","80mg/100ml"],ans:1,exp:"饮酒驾车=血液酒精含量20mg/100ml（含）以上且低于80mg/100ml——记12分+暂扣驾驶证6个月+罚款1000-2000元。醉酒驾车=80mg/100ml（含）以上=吊销驾照+追究刑事责任。",tip:"口诀：20-80=酒驾（12分+扣证半年）；≥80=醉驾（吊销+坐牢）。一口啤酒可能就超标。"},
{id:1102,cat:"points",type:"judgment",q:"机动车驾驶人在记分周期结束后30日内，累积记分未满12分且罚款已缴纳的，记分予以清除。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"记分清零是记分周期结束后自动清除，不需要记分周期结束后30日内再去做什么手续。前提是：①记分未满12分；②所有罚款已缴纳。不需要等到30日内。",tip:"口诀：分清零=周期结束自动清，不用等到30日。但罚款必须先交了。"},
{id:1103,cat:"points",type:"choice",q:"以下哪项不是学法减分的学习考试内容？",opts:["道路交通安全法律法规","交通安全文明驾驶常识","应急处置知识","车辆维修保养知识"],ans:3,exp:"学法减分内容为交通安全知识和法律法规，不包括车辆维修保养知识。学习考试涉及交通法规、安全文明驾驶、应急处置、交通事故救护等与安全驾驶直接相关的内容。",tip:"口诀：学法减分=学交通安全（法律+安全+应急+救护）。不教修车。"},
{id:1104,cat:"points",type:"judgment",q:"学法减分学习过程中系统会随机抓拍照片进行人脸比对，确保学习者为驾驶人本人。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"学法减分有严格的身份认证机制——学习过程中随机抓拍人脸比对，防止替学代考。连续3次比对失败将取消本次学习资格。考试时同样有人脸验证。",tip:"口诀：学法减分有人脸识别。别想找人替，系统全程盯着你。"},
{id:1105,cat:"points",type:"choice",q:"以下关于驾驶证记分的说法，哪项是正确的？",opts:["记分与驾驶人绑定，与车辆无关","记分与车辆绑定，换车就不记了","电子眼抓拍的违法行为只罚款不记分","现场处罚的不记分"],ans:0,exp:"记分与驾驶证（驾驶人）绑定，与车辆无关。无论是电子眼抓拍还是现场处罚，只要确认了驾驶人都需要记分。无法确认驾驶人的违法行为记在车辆上（部分情形）。",tip:"口诀：记分跟人走（驾驶证），不跟车走。不管你开哪辆车，分都记在你自己头上。"},
{id:1106,cat:"points",type:"judgment",q:"驾驶机动车在高速公路上行驶时，驾驶人未按规定使用安全带的，一次记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速上驾驶人不系安全带记1分+罚款。虽然分值不高，但高速上不系安全带一旦发生事故死亡率极高。安全带是保命带，高速上更要系。",tip:"口诀：高速不系安全带=1分。分不多但命要紧，系上才安心。"},
{id:1107,cat:"points",type:"choice",q:"机动车驾驶人在一个周期内累积记分达到12分后参加满分学习，学习时间不少于多少天？",opts:["3天","5天","7天","10天"],ans:2,exp:"满分学习不少于7天，内容包括道路交通安全法律法规、安全文明驾驶、应急处置等。大型客货车驾驶人满分学习不少于30天。学习结束后方可参加科目一考试。",tip:"口诀：满分学习=7天起步（C证）。A/B证=30天。学满天数才能考试。"},
{id:1108,cat:"points",type:"judgment",q:"驾驶机动车违反禁令标志指示的行为，一次记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"违反禁令标志（如禁行、禁停、禁转等）=记1分。2022年由原3分降为1分。注意与违反禁止标线（压实线等）区分——两者都是1分。闯红灯（违反信号灯）是6分。",tip:"口诀：禁行禁停禁转=1分。2022年从3分降下来，小违规轻处罚。"},
{id:1109,cat:"points",type:"choice",q:"在一个记分周期内，驾驶人在驾驶证被扣留状态下驾驶机动车的，一次记6分。如果该驾驶人在扣留期间又发生其他违法行为，如何处理？",opts:["只按最高分记一次","分别记分，合并计算","只记6分","不予追加记分"],ans:1,exp:"多个违法行为=分别记分+合并计算。扣留期间驾车上路本身一次记6分，如果同时有闯红灯行为再加6分，累积记12分。违法行为按项分别计算累加。",tip:"口诀：多项违法=分别记分、合并计算。一次出行可能记满12分。"},
{id:1110,cat:"points",type:"judgment",q:"机动车驾驶人在一个记分周期内累积记分未满12分且罚款已缴纳的，记分周期结束时记分予以清除，驾驶证自动恢复12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"记分清零=周期结束自动恢复满分12分。前提条件：本周期累积记分<12分且所有罚款已缴纳。任何一个条件不满足，记分不会清零。",tip:"口诀：分未满+钱交了=自动满血复活12分。一个条件不满足就带分过年。"},
{id:1111,cat:"points",type:"choice",q:"以下哪种交通违法行为会导致驾驶证被降级？",opts:["一个周期内记满12分（仅AB类驾驶证）","闯红灯一次","违规停车","未系安全带"],ans:0,exp:"AB类（大中型客货车）驾驶证一个周期内记满12分=最高准驾车型将被降级。降级后不能再驾驶原准驾车型的最高级别车辆。例如A1降为A3B1B2，不能再开大型客车。",tip:"口诀：A/B证记满12分=降级（最高准驾车型没了）。C证满12分=学习考试，不降级。"},
{id:1112,cat:"points",type:"judgment",q:"机动车驾驶人在一次被查处中同时存在多项交通违法行为，只按其中记分最高的一项记分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"多项违法=分别记分+合并计算，不是只记最高的一项。例如同时闯红灯（6分）+不系安全带（1分）=共记7分。合并计算可能导致一次出行就记满12分。",tip:"口诀：一次查多项=各项分别记分加起来。不是只记最高的那项。"},
{id:1113,cat:"points",type:"choice",q:"驾驶机动车载运危险物品未经批准，未按指定路线、时间、速度行驶的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"危化品运输不按规定=记6分。包括未按指定路线、时间、速度行驶，未悬挂警示标志，未经批准擅自运输等。若未取得危化品运输许可，性质更严重。",tip:"口诀：危化品运输不按规矩=6分。路线时间速度标志一个不能错。"},
{id:1114,cat:"points",type:"judgment",q:"学法减分考试合格后减免的记分，可以转移到下一个记分周期使用。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分=本周期有效，不结转。减免的记分只能在当前记分周期内使用，不能预存或结转。每个周期重新计算减免额度（最多6分）。",tip:"口诀：学法减分不过期也不存——当周期当用，过期作废。明年重新算额度。"},
{id:1115,cat:"points",type:"choice",q:"以下关于不同车型超速记分的说法，哪项正确？",opts:["所有车型超速记分标准相同","校车和危险品运输车的超速记分标准比普通私家车更严格","私家车超速处罚比校车更严","超速记分与车型无关"],ans:1,exp:"营运/专用车辆（校车、大中型客货车、危化品车）的超速记分标准比普通私家车严格——同样的超速幅度，营运车记分更高。这是基于潜在事故后果的差异化处罚原则。",tip:"口诀：超速记分看车型——校车/危化品/大客货车处罚更重，私家车相对轻。"},
{id:1116,cat:"points",type:"judgment",q:"驾驶机动车在道路上行驶，遇前方排队等候时在人行横道或网状线区域内停车等候的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"在人行横道、网状线（黄色网格线）区域内停车=记3分。这些区域是禁止以任何原因占用的——人行横道是行人通道，网状线是路口疏散区。堵车时应有意识留空这些区域。",tip:"口诀：堵车时停在斑马线或网格线上=3分。排队时抬头看线，黄网格和斑马线留空。"},
{id:1117,cat:"points",type:"choice",q:"驾驶机动车载货长度、宽度、高度超过规定的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"载货超长/超宽/超高=记1分+罚款。若超限严重且未办理超限运输许可，可能面临更重处罚（6分）。日常运输应严格控制在规定尺寸内。",tip:"口诀：货物超尺寸=1分。超限严重+无许可=6分。装货别贪多。"},
{id:1118,cat:"points",type:"judgment",q:"机动车驾驶人在实习期内累计记分达到12分的，注销其实习准驾车型驾驶资格。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"实习期内12分=注销实习驾照（非扣留）。与非实习期（扣留+学习+考试）的处理方式不同。实习期12分直接注销，需重新报名驾校全科重考。",tip:"口诀：实习期12分=注销实习驾照（直接没了！）。不是扣留是注销！一切从头来。"},
{id:1119,cat:"points",type:"choice",q:"以下哪种情况，驾驶人的记分应当在记分周期结束后30日内接受审验教育？",opts:["C1驾驶证记分未满12分","AB类驾驶证有记分记录","所有驾驶人有记分就审验","仅记满12分的才审验"],ans:1,exp:"AB类驾驶证有记分（哪怕1分）=须参加不少于3小时审验教育。C类驾驶证记分未满12分不需审验。校车驾驶人无论有无记分，每年均需审验。",tip:"口诀：AB证有分就要审验（学3小时）。C证没满12分不用审验。校车每年必审。"},
{id:1120,cat:"points",type:"judgment",q:"驾驶机动车不按规定使用灯光的，一次记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"不按规定使用灯光（如夜间不开灯、隧道不开灯、雨雾天不开灯等）=记1分。发生事故后不按规定使用灯光和设置警告标志的，记1分（事故本身另外记分）。",tip:"口诀：不开灯或灯用错=1分。夜间/隧道/雨雾天=要开灯。别在黑暗中行驶。"},
{id:1121,cat:"laws",type:"choice",q:"申请小型汽车（C1）驾驶证的最低年龄是多少？",opts:["16周岁","18周岁","20周岁","21周岁"],ans:1,exp:"C1/C2驾驶证申请最低年龄为18周岁。C5（残疾人专用小型自动挡载客汽车）也为18周岁。2026年取消了70周岁的报考年龄上限，但需通过记忆力、判断力、反应力「三力测试」。",tip:"口诀：C证18岁可考。2026年取消年龄上限但70岁以上加测「三力」。"},
{id:1122,cat:"laws",type:"choice",q:"申请大型客车（A1）驾驶证的最低年龄是多少？",opts:["20周岁","22周岁","24周岁","26周岁"],ans:1,exp:"A1（大型客车）申请最低年龄为22周岁，且需取得B1或B2（或A2）资格一定年限后方可增驾。A1对驾驶人年龄、驾龄和经验要求最高——毕竟要承担几十名乘客的生命安全。",tip:"口诀：A1=22岁起步，且要B证驾龄够才能增驾。大客车司机门槛最高。"},
{id:1123,cat:"laws",type:"judgment",q:"2026年起取消了申请小型汽车驾驶证70周岁的年龄上限，但70岁以上申请人需通过记忆力、判断力、反应力「三力测试」。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年全面取消C类驾驶证70周岁年龄上限。70岁以上申请人须通过「三力测试」（记忆力、判断力、反应力），测试合格方可报名。已有驾驶证的70岁以上驾驶人每年体检并提交证明。",tip:"口诀：70岁可以考驾照了（2026新规），但要过三力测试。老司机每年体检。"},
{id:1124,cat:"laws",type:"choice",q:"驾驶证科目一考试内容主要是什么？",opts:["场地驾驶技能","道路驾驶技能","道路交通安全法律法规和相关知识","安全文明驾驶常识"],ans:2,exp:"科目一=道路交通安全法律法规和相关知识（机考100题，90分及格）。科目二=场地驾驶技能；科目三=道路驾驶技能；科目三安全文明驾驶常识（俗称科目四）=安全文明驾驶知识。",tip:"口诀：科一=交通法规知识（电脑答题）；科二=场地实操；科三=路考；科四=安全文明知识。"},
{id:1125,cat:"laws",type:"choice",q:"驾驶证科目三安全文明驾驶常识考试（俗称科目四）的考试内容不包括以下哪项？",opts:["恶劣天气安全驾驶","紧急情况处置","交通信号识别","车辆机械原理与维修"],ans:3,exp:"科目三安全文明驾驶（科目四）内容包括：安全文明驾驶操作要求、恶劣天气和复杂道路安全驾驶、紧急情况处置、交通事故救护等。车辆机械原理与维修不在考试范围内。",tip:"口诀：科四=安全驾驶知识，不考修车技术。安全+应急+救护是重点。"},
{id:1126,cat:"laws",type:"judgment",q:"初次申领驾驶证可以直接申请A1大型客车驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"A1不能直接初申——必须通过增驾取得，需要持有B1或B2一定年限（通常3-5年）且无满分记录。C1可直接初申。A1门槛最高，保障大型客车驾驶人的经验和安全意识。",tip:"口诀：A1=必须增驾（不能初申）。先拿B证开几年，无事故无满分才能升。C1可以直接考。"},
{id:1127,cat:"laws",type:"choice",q:"驾驶证有效期满前多长时间内可以申请换证？",opts:["30日","60日","90日","180日"],ans:2,exp:"期满前90日内可申请换证。超过有效期不满1年的可正常换证；超过1年不满3年=重考科目一恢复；超过3年=全部作废重考。",tip:"口诀：换证提前90天（3个月）。过期1年内还能换，1-3年考科一，3年以上全废。"},
{id:1128,cat:"laws",type:"judgment",q:"机动车驾驶证遗失的，驾驶人应当向驾驶证核发地车辆管理所申请补发，不得异地办理。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"驾驶证补发可异地办理！2026年全国已实现驾驶证补换领等业务「一证通办」——可在全国任一车辆管理所办理，无需回到核发地。只需要身份证+照片+身体条件证明（如需）。",tip:"口诀：补驾照全国通办（2026年）。在哪丢在哪补，不用回老家。"},
{id:1129,cat:"laws",type:"choice",q:"机动车驾驶人信息发生变化（如姓名、住址变更）时，应当在多少日内向车辆管理所申请变更备案？",opts:["15日","30日","60日","90日"],ans:1,exp:"驾驶人信息变更应在30日内向车管所备案。包括姓名、身份证号、住址、联系方式等信息变化。未及时备案可能影响交通违法告知等通知的接收。",tip:"口诀：个人信息变了=30天内告诉车管所。电话号码换了更要及时更新。"},
{id:1130,cat:"laws",type:"choice",q:"以下哪类人员不得申请机动车驾驶证？",opts:["年满18周岁的高中生","红绿色盲患者","矫正视力达5.0的近视者","左下肢缺失但右下肢健全者"],ans:1,exp:"红绿色盲（无法分辨红黄绿灯颜色）=禁止申领驾驶证。红绿色弱（能分辨但不敏锐）经专门检查合格的可以申领。矫正视力达5.0的近视者、符合条件的残疾人均可申领相应车型驾驶证。",tip:"口诀：红绿色盲=不能考驾照。分不清红绿灯怎么开车？色弱经检查合格可以。"},
{id:1131,cat:"laws",type:"choice",q:"有器质性心脏病、癫痫病、眩晕症等妨碍安全驾驶疾病的人员，能否申领驾驶证？",opts:["可以申领","不可以申领","治愈后可申领，但需医疗机构出具证明","只可以申领C5残疾人专用驾驶证"],ans:2,exp:"患妨碍安全驾驶疾病的人员不得申领驾驶证。但如果疾病已治愈且不再影响安全驾驶，经县级以上医疗机构检查证明后可以申领。隐瞒病情申领的，一经发现注销驾驶证。",tip:"口诀：心脏病/癫痫/眩晕症=不能考驾照（除非治愈+医生证明）。隐瞒病情=注销。"},
{id:1132,cat:"laws",type:"judgment",q:"有吸食、注射毒品行为但已戒除满2年的人员可以申请驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"根据2026年规定，有吸毒史但已戒除满3年（非2年）且无复吸记录的人员，经医疗机构体检合格后可以申请驾驶证。3年内有吸毒记录的不得申领。",tip:"口诀：戒毒满3年才能考驾照（不是2年）。吸毒史=3年考验期。"},
{id:1133,cat:"laws",type:"choice",q:"机动车驾驶人在实习期内不得驾驶哪些车辆？",opts:["私家车","小型货车","公共汽车、营运客车、警车、消防车、救护车等特种车辆","自动挡轿车"],ans:2,exp:"实习期内不得驾驶公共汽车、营运客车、警车、消防车、救护车、工程救险车以及载有危险物品的机动车。驾驶原准驾车型的机动车不受此限。",tip:"口诀：实习期禁开=公交车/营运客车/特种车（警消救）/危化品车。普通私家车可以开。"},
{id:1134,cat:"laws",type:"judgment",q:"驾驶证被吊销后，在任何情况下都可以立即重新申领驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"吊销后重新申领有时间限制：一般吊销=满2年后可重新申领；醉驾吊销=满5年；醉驾营运车=满10年；交通肇事逃逸构成犯罪的=终身禁驾。不同情形等待期不同。",tip:"口诀：吊销≠永远不能考。一般2年，醉驾5年，醉驾营运10年，肇事逃逸犯罪=终身。"},
{id:1135,cat:"laws",type:"choice",q:"机动车驾驶人身体条件证明的有效期是多久？",opts:["3个月","6个月","12个月","2年"],ans:1,exp:"身体条件证明自出具之日起6个月内有效。办理驾驶证申领、换证等业务时，超过6个月的身体条件证明需要重新体检并开具。",tip:"口诀：体检证明有效期=6个月。过期了要重新体检。"},
{id:1136,cat:"laws",type:"judgment",q:"机动车所有人可以在车辆管理所管辖区域以外的城市办理注册登记（异地购车上牌）。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年全国推行私家车新车上牌免查验+异地办理。购买新车后可在全国任一城市办理注册登记，无需回到户籍地或居住地。跨省通办极大方便了异地购车。",tip:"口诀：新车全国通上牌（2026年）。在哪买在哪上，不用回老家。"},
{id:1137,cat:"laws",type:"choice",q:"小型汽车驾驶证的考试里程和项目要求中，科目三道路驾驶技能考试的考试里程不少于多少公里？",opts:["1公里","3公里","5公里","10公里"],ans:1,exp:"小型汽车科目三路考考试里程不少于3公里。大中型客货车不少于10公里。考试路段应包含多种道路条件和交通环境。2026年部分城市试行电子评判+人工评判结合的考试模式。",tip:"口诀：C证科三路考至少3公里。A/B证至少10公里。里程够长才能考察真实水平。"},
{id:1138,cat:"laws",type:"choice",q:"以下哪种情形会导致驾驶证被注销？",opts:["记分达到12分","闯红灯","超过驾驶证有效期1年以上未换证","驾驶与准驾车型不符的车辆"],ans:2,exp:"超过有效期1年未换证=注销驾驶证。闯红灯=记6分，准驾不符=记9分，记满12分=扣留（非注销）。注销情形还包括：驾驶人死亡/丧失行为能力、身体条件不适合驾驶等。",tip:"口诀：超期1年以上不换证=注销。记满12分=扣留不是注销。注销和扣留性质不同。"},
{id:1139,cat:"laws",type:"judgment",q:"机动车驾驶人可以在异地参加驾驶证满分学习考试，不必回到驾驶证核发地。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"满分学习和考试可在全国任一大中型城市车辆管理所进行，无需回到驾驶证核发地。2026年全国已实现满分教育跨省通办。",tip:"口诀：满分学习全国通（2026年）。扣了驾照在哪学在哪考，不一定回老家。"},
{id:1140,cat:"laws",type:"choice",q:"营运载客汽车（出租车、网约车）的强制报废年限或行驶里程是多少？",opts:["8年","10年","12年","15年"],ans:0,exp:"小型营运载客汽车（出租车）强制报废年限为8年。网约车行驶里程达到60万公里强制报废（无年限）。非营运私家车无强制报废年限，但行驶里程达60万公里引导报废。",tip:"口诀：出租车=8年报废。网约车=60万公里报废。私家车=无年限+60万公里引导报废。"},
{id:1141,cat:"laws",type:"judgment",q:"C1驾驶证可以驾驶所有蓝牌车辆，包括轻型载货汽车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"C1可驾驶小型微型载客汽车和轻型微型载货汽车（蓝牌），但并非「所有蓝牌车辆」——C1不能驾驶摩托车（需D/E/F证）、不能驾驶中型以上客车（需B/A证）、不能驾驶牵引车（需A2证）。",tip:"口诀：C1=蓝牌小车+小货车。不能开摩托+大客车+牵引车。蓝牌不等于全部能开。"},
{id:1142,cat:"laws",type:"choice",q:"以下哪项关于车辆年检的规定是正确的？",opts:["所有车辆都需要每年年检","新车6年内免上线检测，每2年申领检验标志","新车10年内都免检","营运车辆也享受免检政策"],ans:1,exp:"6年内非营运小型客车免上线检测，但需每2年申领检验合格标志（可通过12123APP在线申领）。6年以上10年以内的每2年上线检测1次；10年以上的每年上线检测1次。营运车辆不享受免检。",tip:"口诀：新车6年内免上线（2年领标即可）。6-10年每2年上线，10年以上每年上线。营运车不免检。"},
{id:1143,cat:"laws",type:"judgment",q:"机动车在抵押登记期间可以办理转让登记（过户）。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"抵押期间的车辆不得擅自转让。需要先解除抵押登记（还清贷款），然后才能办理转让登记。处于查封、扣押状态的车辆同样不得转让。",tip:"口诀：车在抵押中=不能过户。先还贷款→解抵押→再卖车。"},
{id:1144,cat:"laws",type:"choice",q:"机动车发生交通事故造成人身伤亡、财产损失的，由保险公司在交强险责任限额内予以赔偿。2026年交强险死亡伤残赔偿限额是多少？",opts:["11万元","18万元","20万元","22万元"],ans:1,exp:"2026年交强险赔偿限额：死亡伤残18万元、医疗费用1.8万元、财产损失2000元。超出部分由商业三者险补充。注意与2020年改革前的旧限额（12.2万）区分。",tip:"口诀：交强险限额=死残18万+医疗1.8万+财产2000。不够的靠商业险补。"},
{id:1145,cat:"laws",type:"judgment",q:"道路交通事故社会救助基金可以垫付受害人的全部损失。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"救助基金只垫付部分费用（抢救费、丧葬费），且有上限。不赔偿财产损失、精神损害等。基金资金来源包括交强险保费提取一定比例、财政补贴、社会捐赠等。基金垫付后有权向责任人追偿。",tip:"口诀：救助基金=垫付抢救费+丧葬费（不是全赔）。先救命后追偿。"},
{id:1146,cat:"laws",type:"choice",q:"交通警察对道路交通安全违法行为应当及时纠正。对于情节轻微、未影响道路通行的，如何处理？",opts:["必须罚款","必须记分","口头警告后放行","扣留车辆"],ans:2,exp:"情节轻微且未影响道路通行的违法行为=口头警告后放行。2026年推行的「首违警告」政策也属于此类柔性执法措施。但注意——轻微≠所有违法，严重违法仍严格处理。",tip:"口诀：小毛病没影响通行=口头警告就放。柔性执法≠不执法，严重违法必究。"},
{id:1147,cat:"laws",type:"judgment",q:"机动车所有人收到车辆召回通知后，应当在30日内将车辆送至指定地点配合召回维修。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"车辆召回具有强制性，所有人收到召回通知后应在规定期限内配合召回维修。拒不配合召回的，车辆不得上道路行驶。召回是保障车辆安全的法定制度。",tip:"口诀：召回通知=必须30天内去修。不去修的不能上路。召回是强制性的。"},
{id:1148,cat:"laws",type:"choice",q:"以下哪项关于交通技术监控设备（电子眼）记录的违法行为处理，说法正确？",opts:["电子眼记录的不予处罚","电子眼记录须经审核后录入系统，并向当事人告知","当事人无权查询电子眼记录","电子眼记录的可以不予处理"],ans:1,exp:"电子眼记录须经人工审核+录入系统+告知当事人（短信或APP通知）。当事人有权查询原始记录照片和视频。有异议的可提出行政复议。电子眼处罚与现场处罚具有同等法律效力。",tip:"口诀：电子眼记录=要审核+要告知+可查询+可复议。不是拍了就直接罚。"},
{id:1149,cat:"laws",type:"judgment",q:"公安机关交通管理部门对交通违法行为的行政处罚决定，当事人不服的可以申请行政复议或提起行政诉讼。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"当事人对行政处罚不服=60日内申请行政复议或6个月内提起行政诉讼。复议和诉讼期间行政处罚不停止执行（缴纳罚款等），除非当事人提供担保或法院裁定停止执行。",tip:"口诀：不服处罚=60天内复议或6个月内诉讼。复议诉讼期间罚款要先交。"},
{id:1150,cat:"laws",type:"choice",q:"机动车排放标准为强制性的国家标准。不符合排放标准的车辆，以下哪项说法正确？",opts:["可以继续上路行驶","不得上道路行驶，不予办理注册登记和转入登记","只需缴纳排污费即可上路","只在新车时检查，之后不查"],ans:1,exp:"不符合排放标准=不得上路+不予注册/转入登记。目前全国已全面实施国六B排放标准。在用车辆须定期进行排放检测，不合格不予通过年检。",tip:"口诀：排放不达标=不能上路+不能年检。国六B是现行标准。"},
{id:1151,cat:"laws",type:"choice",q:"机动车驾驶人在一个记分周期内有记分记录，但未满12分，驾驶证是否需要进行审验？",opts:["所有驾驶人都需要","AB类驾驶证驾驶人需要，C类不需要","C类驾驶证驾驶人需要","都不需要"],ans:1,exp:"AB类驾驶证有记分（哪怕1分）=须参加不少于3小时的审验教育。C类驾驶证记分未满12分不需审验。校车驾驶人无论有无记分每年均需审验。审验和换证是两个不同事项。",tip:"口诀：AB证有分就要审验，C证不满12分不用。校车每年必审（无论有无记分）。"},
{id:1152,cat:"laws",type:"judgment",q:"C1增驾B1（中型客车）驾驶证需持C1满3年以上且最近连续3个记分周期无满分记录。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"C1增驾B1需C1满3年+最近连续3个周期无满分记录+年龄20周岁以上60周岁以下。增驾考试免考科目一和科目四（2026新规），只考科目二和科目三道路驾驶技能。",tip:"口诀：C1升B1=C1满3年+3年无满分+年龄20-60。免文科只考实操。"},
{id:1153,cat:"laws",type:"choice",q:"驾驶人在交通事故中负有责任且不履行赔偿义务的，可能面临什么后果？",opts:["仅道德谴责","纳入失信被执行人名单（老赖名单），限制高消费","驾驶证自动注销","仅承担民事责任"],ans:1,exp:"拒不履行交通事故赔偿义务的=可能被纳入失信名单+限制高消费（不能坐飞机高铁等）。法院判决后仍不履行的，法院可强制执行。",tip:"口诀：事故不赔钱=老赖名单+限高消费（飞机高铁都坐不了）。赔不起也要有诚意。"},
{id:1154,cat:"laws",type:"judgment",q:"2026年起全国所有城市实行了机动车限行政策（如单双号限行、尾号轮换限行等）。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"限行政策由各城市根据本地实际情况自行制定，并非全国统一。目前只有部分大城市（如北京、上海、广州等）实行机动车限行管理。2026年更多城市探索了拥堵收费等新的交通需求管理措施。",tip:"口诀：限行不是全国统一（各城市自己定）。大城市可能有，小城市不一定。"},
{id:1155,cat:"laws",type:"choice",q:"醉酒驾驶营运机动车（如出租车、公交车、货车）被吊销驾驶证的，多长时间内不得重新申领？",opts:["3年","5年","10年","终身"],ans:2,exp:"醉酒驾驶营运车=吊销+10年内不得重新申领+重新申领后不得驾驶营运车辆。若发生重大交通事故构成犯罪的=终身禁驾。营运车醉驾处罚远重于非营运醉驾（吊销5年）。",tip:"口诀：醉驾营运车=吊销+10年禁考。普通醉驾=吊销+5年禁考。肇事犯罪=终身。"},
{id:1156,cat:"laws",type:"judgment",q:"公安机关交通管理部门在处理交通事故时，因收集证据需要可以扣留事故车辆，扣留期间产生的停车费和保管费由车主承担。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"因收集证据扣留车辆产生的费用由行政机关承担，不得向当事人收取。当事人逾期未领取车辆产生的费用由当事人承担。法律明确禁止行政机关向当事人转嫁扣留车辆的费用。",tip:"口诀：事故扣车取证=政府出钱（停车费不用车主付）。超期不取车的费用才自己出。"},
{id:1157,cat:"laws",type:"choice",q:"机动车所有人办理车辆转让登记（过户）时，需在多少日内完成？",opts:["15日","30日","45日","60日"],ans:1,exp:"机动车转让登记需在交付之日起30日内完成。买方超过30日未办理的处警告或200元以下罚款。及时办理过户是保障买卖双方权益的重要手续。",tip:"口诀：买车30天内过户。超30天=罚款。车卖出去了证还在自己名下=担风险。"},
{id:1158,cat:"laws",type:"judgment",q:"机动车驾驶人因服兵役、出国等原因无法在规定时间内办理驾驶证期满换证的，可以申请延期办理，最长期限为3年。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"因服兵役、出国（境）等特殊原因无法换证的，可向车管所申请延期办理，最长延期3年。延期期间驾驶证暂停使用，不得驾驶机动车。延期申请需在有效期满前提出。",tip:"口诀：出国/服兵役可延期换证（最长3年）。但延期期间不能开车！"},
{id:1159,cat:"laws",type:"choice",q:"以下哪类驾驶人不需要每年提交身体条件证明？",opts:["70周岁以上的驾驶人","持有残疾人专用小型自动挡载客汽车（C5）驾驶证的驾驶人","持有大型客车（A1）驾驶证的驾驶人","持有C1驾驶证且年龄40周岁的驾驶人"],ans:3,exp:"40周岁的C1驾驶人无需每年体检。需每年体检的是：70周岁以上驾驶人、C5残疾人驾驶证、AB类驾驶证驾驶人（审验时提交）及其他有特殊要求的。",tip:"口诀：年轻C证不用年年体检。70岁以上/残疾证/AB证才需要每年体检。"},
{id:1160,cat:"laws",type:"choice",q:"车辆在高速公路上发生故障，正确的报警电话号码是？",opts:["110","120","12122","12345"],ans:2,exp:"高速公路交通事故和故障报警电话=12122（全国高速公路报警救援电话）。同时也可拨打110。报警时需告知所在高速名称、公里桩号（路侧每100米一个）、行驶方向。",tip:"口诀：高速报警=12122。说说你在哪条高速、哪个方向、多少公里处。"},
{id:1161,cat:"laws",type:"judgment",q:"机动车临时行驶车号牌（临牌）的有效期一般为15天，最长不超过30天。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"临牌有效期一般为15天（辖区内）或30天（跨辖区），并非最长30天——跨辖区临牌最长30天，辖区内临牌15天。正式号牌制作期间可申领临牌上路。",tip:"口诀：临牌有效期=辖区内15天、跨辖区30天。别把临牌当正式牌用。"},
{id:1162,cat:"laws",type:"choice",q:"驾驶人在道路上发生交通事故后，以下哪项做法是错误的？",opts:["立即停车保护现场","抢救伤员","将伤员移到路边后自行驾车离开","迅速报警"],ans:2,exp:"交通事故后绝不可擅自驾车离开——那会构成逃逸。正确做法：停车→保护现场→抢救伤员→报警。伤员需要专业医疗救治，不是移到路边就了事的。",tip:"口诀：事故四步走——停车→护现场→救人→报警。擅自离开=肇事逃逸。"},
{id:1163,cat:"laws",type:"judgment",q:"驾驶机动车在道路上行驶时，交警可以因驾驶人未随车携带纸质驾驶证而扣留车辆。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"2026年全国推行电子驾驶证——出示交管12123APP中的电子驾驶证即视为随车携带。交警不得仅因未携带纸质驾驶证而扣留车辆。但驾驶证被吊销/扣留状态的除外。",tip:"口诀：电子驾照=纸质驾照（2026年）。手机里有驾照就行，不用带本本。"},
{id:1164,cat:"laws",type:"choice",q:"校车驾驶人申请校车驾驶资格需满足的条件不包括以下哪项？",opts:["取得相应准驾车型驾驶证3年以上","最近连续3个记分周期内无满分记录","无致人死亡或重伤交通事故责任记录","必须具有大学本科以上学历"],ans:3,exp:"校车驾驶人无学历要求。条件包括：相应驾证3年以上+近3周期无满分+无致人死亡/重伤责任记录+无酒后或醉酒驾车记录+无犯罪记录+身心健康。",tip:"口诀：校车司机=驾龄3年+3年无满分+无大事故+无酒驾+健康。不看学历看安全记录。"},
{id:1165,cat:"laws",type:"judgment",q:"机动车驾驶人可以在手机上通过交管12123APP处理所有交通违法行为和缴纳罚款。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"部分严重违法行为（如酒后驾车、使用伪造牌证等需行政拘留或吊销驾照的）不能在APP上处理——必须到交管部门接受调查处理。一般性违法（电子眼抓拍、轻微现场处罚）可通过APP处理。",tip:"口诀：APP能处理一般违法，严重的（拘留/吊销级别）必须去窗口。不是所有都能手机上点。"},
{id:1166,cat:"laws",type:"choice",q:"申请C6（轻型牵引挂车）驾驶证的最低年龄是多少？",opts:["18周岁","20周岁","22周岁","24周岁"],ans:1,exp:"C6（轻型牵引挂车，允许拖挂总质量小于4500kg的房车等）申请最低年龄为20周岁。需已持有C1或C2驾驶证。C1增驾C6免考科目一和科目四（2026新规）。",tip:"口诀：C6（拖挂房车）=20岁+C1/C2证。增驾免文科。"},
{id:1167,cat:"laws",type:"judgment",q:"公安机关交通管理部门可以将驾驶人违法行为信息通过社会信用体系进行披露，纳入个人征信记录。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"严重的交通违法行为（如醉驾、肇事逃逸、买卖分等）会纳入社会信用体系（征信记录）。一般轻微违法行为暂不纳入。征信不良将影响贷款、保险、就业等。",tip:"口诀：严重交通违法=上征信（影响贷款/保险/就业）。轻微的不上。守法开车信用好。"},
{id:1168,cat:"laws",type:"choice",q:"机动车驾驶人申请使用原机动车号牌号码的条件是什么？",opts:["随时可以申请","原车号牌使用满1年，原车转让或注销后2年内购买新车","只能原车主本人使用","无需任何条件"],ans:1,exp:"保留原号牌条件：原车号牌使用满1年+原车转让/注销后2年内购新车（2026年由1年延长至2年）+原车主申请。符合条件的新车或二手车均可使用原号牌。",tip:"口诀：旧号保留=旧牌用满1年+旧车卖后2年内买新车。保留时间延长至2年。"},
{id:1169,cat:"laws",type:"judgment",q:"机动车在城市道路行驶时，遇行人正在通过人行横道，应当停车让行。不让行的将面临记3分的处罚。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"人行横道不礼让行人=记3分+罚款。这是2022年起执行的处罚标准。人行横道是行人的法定优先通行区域，机动车必须减速或停车让行。",tip:"口诀：斑马线不让人=3分。行人在斑马线上有最高优先权。"},
{id:1170,cat:"laws",type:"choice",q:"以下哪项关于车辆保险的说法是正确的？",opts:["交强险可以不买","商业三者险也是强制险","交强险是法定强制保险，必须购买","新车不需要买保险"],ans:2,exp:"交强险（机动车交通事故责任强制保险）=国家法律规定必须购买，不买不能上路、不能年检。商业险（商业三者险、车损险等）为自愿购买。交强险保的是受害人，不是自己。",tip:"口诀：交强险=强制必买（不买不能上路）。商业险=自愿买。交强险是国家要求的底线保障。"},
{id:1171,cat:"laws",type:"judgment",q:"C1驾驶证可以驾驶C6轻型牵引挂车（房车拖挂）而不需要增驾。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"C1不能直接驾驶C6挂车——必须通过增驾考试取得C6资格。2026新规中C1增驾C6免考文科（科一+科四），只需考科目二和科目三道路驾驶。拖挂驾驶需要专门技能。",tip:"口诀：C1开拖挂房车=要增驾C6。不是有C1就能拖。增驾免文科只考实操。"},
{id:1172,cat:"laws",type:"choice",q:"驾驶机动车在道路上发生故障难以移动时，应当在车后多少米处设置警告标志？（非高速公路）",opts:["30米","50-100米","150米","200米"],ans:1,exp:"普通道路故障车=车后50-100米设警告标志。高速公路=150米外。同时开启双闪，夜间加开示廓灯和后位灯。很多追尾事故是因为没有或距离不够的警告标志。",tip:"口诀：普通路警示牌=50-100米。高速=150米。警示牌放近了=没用。"},
{id:1173,cat:"laws",type:"judgment",q:"机动车驾驶人因交通违法行为被处罚后，如果在15日内未缴纳罚款，每日按罚款数额的3%加处罚款，加处罚款总额不得超过罚款本金。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"逾期未缴罚款=每日3%加处罚款，但加处罚款累计不超过罚款本金。例如罚款200元，加处罚款最多200元，总计400元。超过催缴期仍未缴的，申请法院强制执行。",tip:"口诀：罚款逾期=每天加3%（利滚利），但最多加到罚款本金那么多。200块罚款最多变400。"},
{id:1174,cat:"laws",type:"choice",q:"以下哪种情形不属于危险驾驶罪？",opts:["追逐竞驶情节恶劣","醉酒驾车","从事旅客运输严重超员","正常超车"],ans:3,exp:"危险驾驶罪四种情形：追逐竞驶情节恶劣、醉酒驾车、严重超员超速（校车/客车）、违规运输危化品危及公共安全。正常超车不构成危险驾驶罪。",tip:"口诀：危险驾驶罪=竞驶+醉驾+严重超员超速+违规运危化品。正常超车不算。"},
{id:1175,cat:"laws",type:"judgment",q:"机动车驾驶证记载的准驾车型代号与所驾车型必须一致。不一致的（准驾不符），按无证驾驶处理。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"准驾不符≠无证驾驶。准驾不符=有驾驶证但车型不匹配（如C1开摩托车）=记9分。无证驾驶=从未取得驾驶证驾驶机动车=罚款+可拘留。两者性质不同，处罚不同。",tip:"口诀：准驾不符（有证开错车）=9分；无证驾驶（根本没证）=罚款+拘留。有证和没证差别大。"},
{id:1176,cat:"signals",type:"choice",q:"当路口交通信号灯因故障全部熄灭时，应如何通行？",opts:["按自己判断通行","按照无信号灯路口规则——减速慢行，让右方来车先行，转弯让直行","原地等待信号灯恢复","按喇叭示意通行"],ans:1,exp:"信号灯故障（熄灭）=等同于无信号灯控制路口。遵循：减速慢行+让右方来车先行+转弯让直行+相对方向右转让左转。必要时交替闪灯示意。",tip:"口诀：信号灯灭了=当无灯路口处理。减速+让右+转弯让直行。别抢。"},
{id:1177,cat:"signals",type:"judgment",q:"交通信号灯故障时，即使有交警在场指挥，也应该以交警指挥为准。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"交警指挥>交通信号灯>交通标志标线。有交警在路口指挥时，一切以交警手势为准，即便信号灯是绿灯交警让你停也得停。",tip:"口诀：有人听人（交警），没人听灯。交警在场=交警最大。"},
{id:1178,cat:"signals",type:"choice",q:"当路口所有方向的信号灯都在持续闪烁黄灯时，表示什么？",opts:["信号灯故障","路口改为无信号控制，所有方向车辆应减速瞭望、确认安全后通过","禁止所有方向通行","只有主路可以通行"],ans:1,exp:"所有方向黄闪=路口改为无信号控制模式（常见于夜间低流量时段）。所有方向车辆减速瞭望，确认安全后通过。黄闪不是故障，而是一种特定的交通控制方式。",tip:"口诀：四面黄闪=无灯控制模式（晚上常用）。减速+瞭望+安全时通过。"},
{id:1179,cat:"signals",type:"judgment",q:"红色叉形灯（安装在车道上方）亮时，表示该车道禁止车辆通行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"红色叉形灯（车道控制灯）=该车道禁止通行。绿色向下箭头灯=该车道允许通行。常见于高速公路、隧道、大桥的可变车道和潮汐车道上空。",tip:"口诀：红叉=此路不通（车道关闭）。绿箭头向下=此路畅通。上方灯管车道，不是路口。"},
{id:1180,cat:"signals",type:"choice",q:"设有电车道信号灯的路口，电车信号灯与普通机动车信号灯不同时，普通机动车应按哪个信号灯行驶？",opts:["按电车信号灯行驶","按普通机动车信号灯行驶","哪个绿灯走哪个","按最晚亮的信号灯行驶"],ans:1,exp:"电车信号灯仅供有轨电车（轻轨）使用，普通机动车应按自己的信号灯行驶。电车信号灯通常为白色图形（横杠=停、竖杠=直行、斜杠=转向），与普通红绿灯含义不同。",tip:"口诀：电车灯管电车，汽车灯管汽车。各看各的灯，别搞混。"},
{id:1181,cat:"signals",type:"judgment",q:"自行车专用信号灯（带有自行车图案的信号灯）亮绿灯时，自行车可以通行，机动车也可以按此信号灯通行。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"自行车专用信号灯仅针对非机动车。机动车应按自己的信号灯行驶，不得按非机动车信号灯通行。两类信号灯分开控制，各行其道。",tip:"口诀：自行车灯管自行车。你是机动车就看机动车的灯。"},
{id:1182,cat:"signals",type:"choice",q:"铁路道口的信号灯亮红灯并伴有声音警报时，应当如何做？",opts:["加速通过","在停止线外停车等待","低速通过","只要没看到火车就可以通过"],ans:1,exp:"铁路道口红灯亮+警报声=火车即将通过——必须在停止线外停车等待。即使目视范围内暂时看不到火车也必须遵守——火车速度快、制动距离长达数百米甚至上千米。",tip:"口诀：铁路道口红灯+警报=必须停！火车不是你想停就能停的。"},
{id:1183,cat:"signals",type:"judgment",q:"铁路道口无信号灯时，应一停二看三通过。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无人看守的铁路道口=一停（在道口前停车）→二看（左右观察有无火车）→三通过（确认安全后挂低挡匀速通过，道口内不换挡不停车）。",tip:"口诀：无人道口=一停二看三通过。不看不听不过。"},
{id:1184,cat:"signals",type:"choice",q:"公路上方设置有车道信号灯（绿色箭头和红色叉形），绿色向下箭头灯亮时表示什么？",opts:["该车道禁止通行","该车道允许通行","该车道仅供大型车辆通行","前方收费站开放"],ans:1,exp:"绿色向下箭头=该车道开放通行。通常在高速公路收费站、隧道入口、大桥入口等位置设置。功能类似「打开/关闭」车道——红叉=关，绿箭=开。",tip:"口诀：红叉关、绿箭头开。高速公路/隧道上面挂的灯=车道开关。"},
{id:1185,cat:"signals",type:"judgment",q:"可变导向车道（锯齿状标线+LED指示灯）上方指示灯显示直行时，可以在该车道内左转。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"可变导向车道=L形锯齿标线+上方LED指示灯，必须按指示灯显示的当前方向行驶。显示直行就只能直行，显示左转才能左转。在变换时段禁止进入。",tip:"口诀：锯齿车道（可变车道）=抬头看灯。灯说直走就直走，灯说左转再左转。"},
{id:1186,cat:"signals",type:"choice",q:"潮汐车道（可变车道）变换行驶方向的车辆应该如何通行？",opts:["可以在任意时间驶入","在方向变换时段内（指示灯红叉或双黄闪）禁止驶入","可以使用潮汐车道掉头","潮汐车道全天一个方向"],ans:1,exp:"潮汐车道方向变换时段（指示灯显示红叉或双黄闪）=禁止驶入。需等指示灯稳定显示绿色箭头方能按指示方向驶入。驶入错误=逆向行驶。进入前务必看清指示灯状态。",tip:"口诀：潮汐车道变换时段（红叉/双闪）=千万别进去。等灯稳定绿箭头再进。"},
{id:1187,cat:"signals",type:"judgment",q:"消防站门前的红色闪烁信号灯亮时，社会车辆应在停止线外停车，让消防车辆优先通行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"消防站/急救站门前的专用信号灯（红灯闪烁）=社会车辆停车让行。此时有消防车/救护车即将驶出，必须让出通道。不让行=记3分。",tip:"口诀：消防站红灯闪=有消防车要出来。停车让道，别挡住生命通道。"},
{id:1188,cat:"signals",type:"choice",q:"交叉路口内已有机动车排队等候，绿灯亮起时，后车应如何做？",opts:["跟随前车进入路口","若不能一次性通过路口则在停止线外等候，待路口净空后再通行","鸣喇叭催促前方车辆","绕行其他车道"],ans:1,exp:"绿灯≠无条件通行。若前方路口车辆排队，无法一次性通过=在停止线外等候，不得进入路口。进入路口后滞留（堵在路中央）=影响交叉方向交通——属于闯绿灯违法行为。",tip:"口诀：绿灯但要排队=等在外面（路口外等）。别挤进去堵在路中间，谁都不好走。"},
{id:1189,cat:"signals",type:"judgment",q:"黄灯亮时，车辆尚未越过停止线的，应当加速通过路口。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"黄灯亮时未越过停止线=应减速停车。黄灯的意义是「警示、预备停止」而不是「抢在红灯前冲过去」。抢黄灯极易与交叉方向提前启动的车辆发生碰撞。",tip:"口诀：黄灯+没过线=刹车停。黄灯不是叫你加速，是叫你准备停。"},
{id:1190,cat:"signals",type:"choice",q:"有轨电车（轻轨）信号灯的横杠表示什么？",opts:["可以直行","禁止通行（等同红灯）","可以左转","可以右转"],ans:1,exp:"有轨电车信号灯：横杠=停（相当于红灯）；竖杠=直行（相当于绿灯）；向左斜杠=左转；向右斜杠=右转。白色灯光，与普通红绿灯含义对应但图形不同。",tip:"口诀：电车灯=白色图形。横=停，竖=直走，斜=转弯。"},
{id:1191,cat:"signals",type:"judgment",q:"交通信号灯中的绿色箭头灯和绿色圆灯具有相同的法律含义——均表示允许通行。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"绿色圆灯=所有方向（直行、左转、右转）均可通行（除非有其他限制）。绿色箭头灯=仅箭头指示方向可以通行，其他方向禁止。箭头灯是定向放行，圆灯是多向放行。",tip:"口诀：绿圆灯=全方向可以走。绿箭头=只能按箭头方向走。圆灯大方，箭头灯专一。"},
{id:1192,cat:"signals",type:"choice",q:"在没有非机动车信号灯的路口，非机动车应当按照什么信号灯通行？",opts:["机动车信号灯","行人信号灯","不需要信号灯","按照最方便的信号灯"],ans:0,exp:"无非机动车专用信号灯时，非机动车按机动车信号灯通行。有非机动车专用信号灯的按专用信号灯通行。电动自行车参照非机动车管理。",tip:"口诀：没自行车灯=看汽车灯。有自行车专用灯=看专用灯。"},
{id:1193,cat:"signals",type:"judgment",q:"盲人过街音响提示装置（盲人钟）发出急促的嘀嘀声时，表示行人信号灯为绿灯，盲人可以通行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"盲人过街音响提示=持续缓慢的嗒嗒声=红灯等待；急促的嘀嘀声=绿灯通行。配合行人信号灯使用，帮助视障人士安全过街。",tip:"口诀：盲人钟=慢嗒等（红灯），快嘀走（绿灯）。声音提示视障者安全过街。"},
{id:1194,cat:"signals",type:"choice",q:"道路上的黄色闪烁灯（黄闪）通常设置在什么位置？",opts:["高速公路服务区","学校、医院、人行横道前方等需要警示减速的路段","收费站","隧道内"],ans:1,exp:"黄闪灯（黄色持续闪烁）=警示减速慢行。常见于学校/医院前方、人行横道预告、危险路段等位置。提示驾驶人注意潜在危险，减速通过。不是信号灯故障或路口黄灯。",tip:"口诀：黄闪灯（一闪一闪）=小心！前面有学校/人行道/危险路段。减速注意。"},
{id:1195,cat:"signals",type:"judgment",q:"交通警察发出左转弯手势信号时，允许车辆左转弯，同时允许掉头。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"交警左转弯手势=允许左转弯，但不等同于允许掉头。掉头需要额外判断路段是否允许——有禁止掉头标志或标线的路段即使在交警指挥下也不得掉头。",tip:"口诀：交警让左转≠就能掉头。掉头还要看有没有禁掉头标志。"},
{id:1196,cat:"signals",type:"choice",q:"车道上方设有黄色「X」形信号灯闪烁时表示什么？",opts:["该车道可以通行","该车道即将关闭，车辆应尽快驶离","该车道仅供超车","该车道为公交专用"],ans:1,exp:"黄色X闪烁=该车道即将关闭（如前方施工/事故封道），车辆应尽快安全驶离。比红色X（已关闭/禁止驶入）提前一个预警阶段。常见于高速公路和隧道的车道控制信号。",tip:"口诀：黄X闪=车道马上关了，赶紧变道走。红X=已经关了。"},
{id:1197,cat:"signals",type:"judgment",q:"交通警察指挥手势中，左臂向左平伸、掌心向前，右臂向右平伸、掌心向前，表示直行信号，准许左右两方直行车辆通行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"交警双臂平伸=直行信号。面向交警的左方和右方车辆可以直行。其他方向车辆禁止通行。各方右转弯车辆在不妨碍被放行车辆时也可通行。",tip:"口诀：双臂平伸=直行。交警面朝谁两边，谁就走。"},
{id:1198,cat:"signals",type:"choice",q:"交通警察左臂向前上方直伸、掌心向前，其他手臂收回（或自然下垂），此手势表示什么？",opts:["左转弯","停止信号","靠边停车","减速慢行"],ans:1,exp:"交警单臂（左臂）向前上方直伸、掌心向前=停止信号。这是交警手势中最重要的信号之一——看到该手势必须停车。注意与靠边停车手势区分（右手前伸+左臂摆动）。",tip:"口诀：交警手举过头顶=停止（所有方向都停）。手掌像一堵墙挡在你面前。"},
{id:1199,cat:"signals",type:"judgment",q:"在没有左转专用信号灯的路口，直行绿灯亮时，左转车辆可以越过停止线进入路口等待，在对向直行车辆通过后完成左转。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无左转专用灯时=直行绿灯+无左转红灯=左转车可进入路口等待，在对向直行车通过后+确保行人安全后完成左转。但有「绿灯左转禁止」辅助标志的除外。",tip:"口诀：没左转专用灯=直行绿灯时可以进路口等。让完对向直行车和行人再左转。"},
{id:1200,cat:"signals",type:"choice",q:"交叉路口设有人行横道信号灯的，行人通过时应该按照哪个信号灯？",opts:["机动车信号灯","人行横道信号灯","不需要看信号灯","任何绿灯都可以过"],ans:1,exp:"有人行横道信号灯（红绿小人）的按人行横道信号灯指示。无人行横道信号灯的行人按机动车信号灯（绿灯过、红灯停）。行人与机动车信号分离设置的路口，行人只看自己的灯。",tip:"口诀：人行道有专用灯（红绿小人）=看小人灯。没有小人灯=看汽车灯。"},
{id:1201,cat:"signals",type:"judgment",q:"高速公路隧道入口处的车道信号灯显示红色叉形时，表示该车道因隧道内事故或施工已封闭，车辆不得驶入。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"隧道入口红叉=该车道关闭（隧道内可能有事故/施工/火灾等），禁止驶入。隧道是高速公路上最危险的封闭空间之一，必须严格遵守隧道信号灯指示。",tip:"口诀：隧道口红叉=别进！里面有事故/火灾/施工。换条车道走。"},
{id:1202,cat:"signals",type:"choice",q:"道路上的「菱形◇」交通标线（白色菱形块）表示什么？",opts:["减速让行线","人行横道预告标线","停车让行线","车道分界线"],ans:1,exp:"菱形◇标线=人行横道预告标线，提示前方30-50米处有人行横道（斑马线）。看到菱形标线应开始减速、观察、准备停车让行。通常设置两个菱形（第一、第二预告）。",tip:"口诀：地上画◇=前面有斑马线（30-50米）。看到菱形就准备减速让行人。"},
{id:1203,cat:"signals",type:"judgment",q:"高速公路上的绿色和白色交替闪烁信号灯（设在隧道入口或跨线桥）表示路面湿滑/结冰警告。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"绿色和白色交替闪烁=雾天引导灯或轮廓指示灯（不是路面湿滑警告）。路面湿滑警告通常通过可变情报板（LED显示屏）以文字和图标显示。不同颜色闪烁灯功能不同。",tip:"口诀：绿白交替闪=雾灯/轮廓灯（引导你跟着走）。路面湿滑=看LED情报板。"},
{id:1204,cat:"signals",type:"choice",q:"收费站的ETC车道上方显示绿色「ETC」和向下箭头时，什么车辆可以使用该车道？",opts:["所有车辆","仅安装ETC设备且正常工作的车辆","没有ETC的车辆也可以","仅大型车辆"],ans:1,exp:"ETC车道=仅安装ETC设备且账户正常的车辆使用。没有ETC的车辆误入应立即变道（在安全前提下），否则无法通行造成拥堵。部分收费站设有人工/ETC混合车道。",tip:"口诀：ETC车道=要有ETC设备才能走。没装就别进，进了过不去。"},
{id:1205,cat:"signals",type:"judgment",q:"交通警察左臂向前平伸、掌心向前，右臂向左前方平伸、掌心向左水平摆动，表示左转弯信号。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"交警左转弯手势=右臂向左前方平伸+左臂配合。具体：左臂可能在不同位置，右臂向左前方平伸、手掌引导左转方向。还需结合身体朝向和辅助手势判断。",tip:"口诀：交警左转弯手势=一手引导，一手配合。看到交警用手划方向就按划的方向走。"},
{id:1206,cat:"signals",type:"choice",q:"高速公路最左侧车道上方显示白色文字「小型车」和速度值的车道指示标志，表示什么？",opts:["所有车辆均可驶入","该车道为小型车专用车道，且速度应在标示范围内","该车道仅供大型车辆使用","该车道已关闭"],ans:1,exp:"车道指示标志=标明车道允许的车型和速度范围。左侧车道通常标注「小型车」和速度上限（如120km/h）及下限（如110km/h）。大型车辆禁止驶入小型车专用车道（超车时除外）。",tip:"口诀：最左道=小车专用+限速范围。大车别长期占着最左快车道。"},
{id:1207,cat:"signals",type:"judgment",q:"黄色网格线（网状线）区域内，车辆在任何情况下都可以临时停车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"黄色网格线=禁止以任何理由停车！这是为确保路口、消防通道、重要单位出入口等不因排队车辆而堵塞设置。只能在确认可一次性通过时才能进入。",tip:"口诀：黄网格线=禁停区（任何时候任何理由都不能在里面停）。过了网格线还没空位就在线外等。"},
{id:1208,cat:"signals",type:"choice",q:"设有公交专用道的道路上，公交专用道信号灯（蓝色背景+白色公交车图案的灯）亮绿灯时，表示什么？",opts:["社会车辆可以驶入","公交车可以通行，社会车辆在非专用时段可以通行","所有车辆禁止通行","公交车也不能通行"],ans:1,exp:"公交专用灯=公交车通行信号。社会车辆能否驶入公交专用道取决于时段——有标注专用时段的，非专用时段社会车辆可使用；全天专用车道的，社会车辆永远不可驶入（紧急避险除外）。",tip:"口诀：公交专用灯=管公交车的。社会车能不能进=看时段标志。"},
{id:1209,cat:"signals",type:"judgment",q:"交叉路口有人行横道预告菱形标线，行人正在通过时左转车辆可以先行通过。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"行人正在通过人行横道=机动车必须停车让行。左转、右转车辆都必须礼让正在通过的行人。不礼让行人记3分。行人优先权在交叉路口同样受法律保护。",tip:"口诀：斑马线上有人=机动车全停。转弯车也不能跟行人抢。"},
{id:1210,cat:"signals",type:"choice",q:"城市道路上交通信号灯的红灯、黄灯、绿灯的排列顺序（竖向）是什么？",opts:["上红中黄下绿","上绿中黄下红","上黄中红下绿","上红中绿下黄"],ans:0,exp:"信号灯竖向排列=上红、中黄、下绿（从上到下）。横向排列=左红、中黄、右绿。这是国家标准统一规定，便于色盲人士通过位置判断信号。",tip:"口诀：竖灯=上红中黄下绿。横灯=左红中黄右绿。红黄绿顺序全世界统一。"},
{id:1211,cat:"signals",type:"judgment",q:"黄色虚线（路面标线）分隔对向车流时，允许车辆临时跨越超车或左转弯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"中心黄色虚线=允许临时跨越（超车、左转、掉头），但须在确认对向无来车且安全的前提下。黄色实线=禁止跨越。黄色虚实线=虚线一侧可跨、实线一侧禁跨。",tip:"口诀：黄虚线=可以跨（超车/转弯/掉头）。黄实线=不能跨。虚实线=虚侧可跨。"},
{id:1212,cat:"signals",type:"choice",q:"交通警察发出减速慢行手势信号时，其特征是什么？",opts:["双臂平伸","左臂向前上方直伸","右臂向前上方直伸，掌心向下，做上下摆动","左臂向左水平摆动"],ans:2,exp:"交警减速慢行手势=右臂向前上方直伸+掌心向下（或倾斜）+上下摆动。示意车辆减慢速度。注意与停止信号（左臂上举不动）区分——一个是持续的、一个是静止的。",tip:"口诀：交警一手下摆=减速慢行。像在往下拍空气让你慢下来。"},
{id:1213,cat:"signals",type:"judgment",q:"高速公路同方向有4条车道的，左侧第一条车道为小型车专用道，限速120-110km/h。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"同向4车道高速=最左道小型车110-120km/h（专用）、第二道客货车90-120km/h、第三道客货车80-100km/h、最右道60-100km/h（含应急车道旁）。具体以路段标牌为准。",tip:"口诀：4车道=左快右慢依次降。最左小车专用110-120，最右60-100。"},
{id:1214,cat:"signals",type:"choice",q:"道路上的「倒三角+让字」标线（减速让行线）与什么交通标志配合使用？",opts:["停车让行标志","减速让行标志","禁止驶入标志","限速标志"],ans:1,exp:"路口白色双虚线（倒三角形状）=减速让行标线，配合路侧「让」字标志（红倒三角）使用。车辆进入路口前应减速或停车瞭望，让干路车辆先行，确认安全后通过。",tip:"口诀：路口白虚线倒三角=让。跟红倒三角「让」牌一对。减速让行不是停车让行。"},
{id:1215,cat:"signals",type:"judgment",q:"设置有人行横道信号灯的路口，当人行横道信号灯为红灯但机动车信号灯为绿灯时，行人可以随机动车一起通过。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"有人行横道信号灯时，行人只看人行横道灯——红灯=停，绿灯=行。即使机动车灯是绿灯，人行道灯红灯时行人也不能通过。行人和机动车各有各的信号灯。",tip:"口诀：行人看小人灯（不看汽车灯）。小人红灯=不能走，管你汽车什么灯。"},
{id:1216,cat:"signals",type:"choice",q:"T型路口（丁字路口）右侧无道路的路口，红灯亮时右侧无道路的车辆能否直行？",opts:["可以直行","不可以直行（应停车等待）","只有右转可以","减速后可以直行"],ans:1,exp:"T型路口右侧无道路时，面向右侧无路方向的车辆在红灯时不得直行（虽然右侧没有交叉道路，但信号灯统一控制所有方向）。所有方向红灯=停车等待。部分地区设有「红灯亮时禁止直行」标志。",tip:"口诀：丁字路口右侧没路=红灯也得停。红灯对所有方向有效，不分有没有路。"},
{id:1217,cat:"signals",type:"judgment",q:"人行横道两端设有「人行横道警示柱」（红白相间柱体）的主要作用是提醒驾驶人注意前方人行横道。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"人行横道警示柱（红白相间弹性柱）=设置在人行横道两端和中间隔离带，警示驾驶人注意减速让行，同时保护等候过街的行人。夜间有反光效果。",tip:"口诀：斑马线头尾红白柱=提醒司机注意行人。晚上反光也能看见。"},
{id:1218,cat:"signals",type:"choice",q:"交通信号灯中「公交优先信号」的特征是什么？",opts:["公交车辆无需看信号灯","为公交车提供优先绿灯信号（延长绿灯或提前亮绿灯），减少公交车在路口的延误","公交车在任何信号时都可以通过","公交车有自己的专用信号灯系统"],ans:1,exp:"公交优先信号=通过检测公交车接近路口，动态调整信号灯配时（延长绿灯时间或提前亮绿灯），减少公交车在路口的等候时间。公交车上装有发射器与路口信号控制器通信。",tip:"口诀：公交优先信号=感应到公交车来了自动多给绿灯。让公交车少等红灯。"},
{id:1219,cat:"signals",type:"judgment",q:"道路中央的「隔离护栏」或「隔离墩」与交通标线具有同等法律效力，均禁止跨越。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"物理隔离设施（护栏、隔离墩、绿化带等）与中心黄色双实线功能相同——禁止跨越。物理隔离比标线更强制——无法跨越。设置隔离设施的位置都是严禁车辆变道或掉头的路段。",tip:"口诀：护栏/隔离墩=实体的黄实线（禁止跨越）。看得见摸得着的禁跨。"},
{id:1220,cat:"signals",type:"choice",q:"高速公路上方的「可变情报板」（LED信息屏）显示的内容具有什么法律地位？",opts:["仅供参考","与交通标志具有同等法律效力，驾驶人必须遵守","没有法律效力","只是广告信息"],ans:1,exp:"可变情报板显示的交通管制信息（如限速调整、车道封闭、前方事故提醒等）=与固定交通标志同等效力。驾驶人必须按情报板实时信息调整驾驶行为。2026年交通法明确电子可变标志的法律地位。",tip:"口诀：LED情报板=电子交通标志（必须遵守）。高速上看到限速变了一定要减速。"},
{id:1221,cat:"signals",type:"judgment",q:"隧道内的紧急疏散标志（绿色背景+白色人形跑向出口图案）指示的是紧急逃生通道方向。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"绿色逃生标志=紧急出口/疏散通道方向。隧道内每隔一定距离（通常250-500米）设有逃生通道（人行横洞或车行横洞+安全门），供火灾等紧急情况时人员疏散。",tip:"口诀：隧道绿底+小跑人=逃生方向。火灾时跟着人跑的方向跑。"},
{id:1222,cat:"signals",type:"choice",q:"车辆行经学校区域，看到「学校」警告标志和地面黄色「慢」字标记时，限速应当不超过多少？",opts:["20km/h","30km/h","40km/h","50km/h"],ans:1,exp:"学校区域限速一般不超过30km/h（以实际标志为准）。黄色「慢」字标记=提醒驾驶人注意前方学校，减速慢行，随时准备停车让行学童。",tip:"口诀：学校区=30码+黄色慢字。看到慢字脚放刹车，孩子们随时可能跑出来。"},
{id:1223,cat:"signals",type:"judgment",q:"驾驶机动车在夜间通过无交通信号灯控制的交叉路口时，应交替使用远近光灯示意。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无信号灯路口=交替闪远近光灯+减速+注意观察。灯光是夜晚的语言——闪灯提醒其他方向来车和行人注意你的存在。有信号灯的路口按信号灯走即可，不需要额外闪灯。",tip:"口诀：无灯路口=闪灯（远近交替）+减速。晚上用灯光打招呼。"},
{id:1224,cat:"signals",type:"choice",q:"下列哪项关于道路交通标线的说法是正确的？",opts:["所有白色标线都可以跨越","白色虚线可跨越，白色实线不可跨越","黄色标线都可以跨越","标线颜色没有意义"],ans:1,exp:"白虚线=同向车道分界，可跨越变道；白实线=同向车道分界，禁止跨越；黄虚线=对向车流分界，可跨越超车；黄实线=对向车流分界，禁止跨越。颜色代表车流方向，虚实代表能否跨越。",tip:"口诀：白色=同向分道，黄色=对向分道。虚线=可跨，实线=禁跨。四要素对应。"},
{id:1225,cat:"signals",type:"judgment",q:"道路上的导向箭头标线（白色箭头画在路面上）表示前方路口各车道的行驶方向，进入导向车道后不得变更车道。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"路面导向箭头+导向车道实线=进入后锁定方向，不得变道。驾驶人应在进入导向车道前就根据目的地选好车道。进入后才发现走错了也只能按箭头方向走，到前方再调头或绕行。",tip:"口诀：路面白箭头=告诉你这道往哪走。进去了就锁死方向，走错了到前面再改。"},
{id:1226,cat:"safe",type:"choice",q:"防御性驾驶的核心原则是什么？",opts:["快速驾驶减少在路上时间","预判潜在危险并提前采取预防措施","紧盯前车不放","只要自己不违规就安全"],ans:1,exp:"防御性驾驶=预见危险+提前防范。核心包括：保持安全距离、经常扫视周围（前方远中近+左右+后视镜）、预判他人可能的错误行为、保持逃生空间（周围有退路）。",tip:"口诀：防御性驾驶=想别人会犯错，提前给自己留后路。不撞别人+不被别人撞。"},
{id:1227,cat:"safe",type:"judgment",q:"驾驶人在行车中应每5-8秒扫视一次后视镜，建立对周围交通环境的整体感知。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"5-8秒扫一次后视镜=防御性驾驶的基本功。这意味着不只是盯着前方——前后左右都要周期性观察，建立「360度态势感知」。突然刹车前必须先看后视镜。",tip:"口诀：5-8秒扫一次后视镜。不只盯前面，前后左右心里有数。"},
{id:1228,cat:"safe",type:"choice",q:"夜间在没有路灯、照明不良的道路上行驶，车速超过30km/h时应使用什么灯光？",opts:["近光灯","远光灯","示廓灯","危险报警闪光灯"],ans:1,exp:"无照明+车速>30km/h=可以使用远光灯，但会车、跟车、进入照明良好路段时应切换为近光灯。车速低于30km/h或有路灯=用近光灯。远光灯照射距离约100-150米，近光约30-50米。",tip:"口诀：无灯+超30码=远光；有灯或有车（会车/跟车）=近光。30码是灯光分界线。"},
{id:1229,cat:"safe",type:"judgment",q:"驾驶人在夜间会车时，应当在距对向来车100米以外改用近光灯。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"夜间会车应在距对向来车150米（不是100米）以外改用近光灯。150米=一个半足球场的长度，这个距离足以确保双方安全切换灯光。100米太近，对方可能已经受到远光眩目。",tip:"口诀：会车改近光=150米（不是100米！）。150米=高速放警示牌的距离，记住这个数字。"},
{id:1230,cat:"safe",type:"choice",q:"驾驶机动车在城市道路上行驶时，前方有大型公交车进站停靠，正确的做法是？",opts:["加速从左侧超过","减速慢行，注意公交车前可能有下车的乘客突然横穿马路","鸣喇叭催促公交车","紧贴公交车左侧通过"],ans:1,exp:"公交车停靠=高风险场景。下车乘客可能从公交车前方走出横穿马路（完全被公交车遮挡视线）。正确做法：大幅减速+观察公交车前下方（能看到行人的脚）+保持横向距离+准备随时停车。",tip:"口诀：公交车停站=慢+看车头前面（防鬼探头）。公交车是大盲区，车前随时可能窜出人。"},
{id:1231,cat:"safe",type:"judgment",q:"驾驶机动车在遇到有老年人和儿童的道路上行驶时，应适当减速并拉大横向间距，因为他们可能突然改变行走方向。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"老年人=行动缓慢但可能突然转向（听力减退+反应慢）；儿童=行为不可预测（随时可能跑动）。遇到这两类行人应格外小心——减速+拉大横向距离+准备随时刹车+不要鸣喇叭惊吓。",tip:"口诀：老人+小孩=慢+远+备刹车。不鸣笛吓他们，小心他们突然变向。"},
{id:1232,cat:"safe",type:"choice",q:"在道路上行驶中，发现前方有摩托车或电动自行车在车流中穿行时，正确的做法是？",opts:["与其抢道","保持安全距离，不要跟车过近，给其留出安全空间","加速超越","鸣喇叭驱赶"],ans:1,exp:"摩托车/电动自行车=保护性差的交通参与者。应保持安全距离+不紧逼+给其留出安全空间。骑行者可能因路面坑洞、侧风等原因突然摆动，跟车过近极易碾压。",tip:"口诀：别紧逼摩托车/电动车。他们摔倒你碾压=100%你的全责。给他们多点空间。"},
{id:1233,cat:"safe",type:"judgment",q:"大型货车转弯时存在「内轮差」（前后轮轨迹不同），内侧的自行车和行人容易被卷入后轮。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"内轮差=大型车转弯时前轮和后轮的轨迹不同（后轮切内圈）。大货车右转时右侧的自行车/行人极易被后轮卷入碾压。遇到大车转弯应远离其内侧至少3米以上。",tip:"口诀：大车转弯=死亡内轮差。大车右转你别在它右边——离远点（至少3米）。"},
{id:1234,cat:"safe",type:"choice",q:"驾驶机动车在道路上遇到执行紧急任务的警车、消防车、救护车、工程救险车时，应当怎么做？",opts:["加速行驶不让道","立即靠右停车让行或减速让出通道","与其并行","不予理睬"],ans:1,exp:"遇特种车辆执行紧急任务=立即让行。可借用公交专用道、驶过停止线等方式让行，因此产生的交通违法可申请撤销。不主动让行=记3分。",tip:"口诀：特种车鸣笛闪灯=赶紧让。因此闯红灯/压线可撤销。不让=3分。"},
{id:1235,cat:"safe",type:"judgment",q:"在道路上驾驶机动车时，如果遇到有人强行加塞（别车），应该坚决不让，加速堵住对方。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"遇到加塞和挑衅驾驶=让一步海阔天空。与对方较劲容易引发路怒冲突甚至交通事故——即使对方全责，处理事故浪费的时间和精力也不值得。安全到家比争一口气重要。",tip:"口诀：别人加塞=让一让。不斗气、不别车。安全到家才是赢家。"},
{id:1236,cat:"safe",type:"choice",q:"夜间驾驶在照明良好的城市道路上，最安全的灯光使用是什么？",opts:["远光灯","近光灯","示廓灯（小灯）","不开灯"],ans:1,exp:"有路灯的照明良好路段=近光灯。很多驾驶人错误地以为「路灯够亮了不用开灯」——但车灯不只是照亮前方，更重要的是让其他交通参与者看到你。示廓灯亮度不足，不能满足行车安全要求。",tip:"口诀：城市有路灯=近光灯（必须开）。开灯不只为自己看，更让别人看到你。"},
{id:1237,cat:"safe",type:"judgment",q:"驾驶机动车在交叉路口准备右转弯时，如果右侧有自行车或电动自行车直行，右转机动车应减速让行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"右转弯机动车应让行右侧直行的非机动车。这是「转弯让直行」原则的体现——直行的非机动车在绿灯时拥有优先通行权。很多右转事故就是因为机动车抢行导致的。",tip:"口诀：右转让右侧直行非机动车。转弯让直行，不管对方几轮。"},
{id:1238,cat:"safe",type:"choice",q:"在高速公路上，前方有校车停在应急车道上下学生，后方车辆应该如何做？",opts:["正常行驶","减速慢行，注意校车周围人员动向","鸣喇叭提醒","停车等待"],ans:1,exp:"高速公路上校车不应在应急车道上下学生（应进服务区）。如果遇到此类情况=减速通过+高度警惕+准备制动。校车周围可能有学生和工作人员走动。",tip:"口诀：高速上见校车停=减速+警惕。学生可能出现在任何位置。"},
{id:1239,cat:"safe",type:"judgment",q:"道路上的施工区通常有明显的橙色标志和锥筒引导，驾驶人应按引导标志减速慢行，不得在施工区超车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"施工区=橙色标志/锥筒/临时标线引导+限速降低+禁止超车。施工区车道变窄、路面状况可能不佳、有施工人员作业——任何违规操作都可能导致人员伤亡事故。",tip:"口诀：施工区=橙色标志+减速+不超车。施工人员是用生命在修路，请保护他们。"},
{id:1240,cat:"safe",type:"choice",q:"驾驶机动车在乡村道路上行驶，遇到路边有散养的牲畜（牛、羊等）时，正确的做法是什么？",opts:["鸣喇叭驱赶","减速慢行或停车等待，不可鸣喇叭惊吓牲畜","加速通过","紧贴牲畜通过"],ans:1,exp:"牲畜行为不可预测——鸣笛或突然加速会使牲畜受惊乱窜，造成更危险的情况。应减速慢行+保持距离+不可鸣笛闪光灯刺激+必要时停车等待牲畜通过。",tip:"口诀：路上有牛羊=不鸣笛+不闪灯+慢慢走（或停）。牲畜受惊比你更慌。"},
{id:1241,cat:"safe",type:"judgment",q:"高速公路行车时，应经常通过后视镜观察后方来车情况，如果发现后方大型货车跟车过近，应加速拉开距离或变道避让。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"被大货车紧逼=危险（一旦前车急刹，大货车根本停不住）。正确应对：轻加速拉开距离、打转向灯变道（让大货车超过去）、或从最近出口驶离。不要跟大货车较劲——重量差几十倍。",tip:"口诀：大货车跟你太近=让。加速跑或变道让它走前面。大货车惯性大，危险。"},
{id:1242,cat:"safe",type:"choice",q:"安全环保驾驶中「匀速行驶」的优点是什么？",opts:["更容易疲劳","燃油经济性最好、排放最低、安全性最高","可以更快到达目的地","没有任何优点"],ans:1,exp:"匀速行驶=节能（减少加减速燃油消耗）+环保（降低排放）+安全（减少速度变化造成的追尾风险）。频繁加减速会增加15%-30%的燃油消耗。",tip:"口诀：匀速=省油+环保+安全。一脚油门一脚刹车=费油费刹车费人品。"},
{id:1243,cat:"safe",type:"judgment",q:"驾驶机动车在路口等红灯时，如果红灯时间较长（超过30秒），手动挡车辆可以挂空挡拉手刹，自动挡车辆保持D挡踩刹车即可。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"长时间红灯（>30秒）=建议挂N挡（自动挡）或空挡（手动挡）+拉手刹。自动挡长时间D挡踩刹车=增加变速箱油温+油耗+脚疲劳。手动挡长时间踩离合=加速离合器磨损。",tip:"口诀：长红灯（>30秒）=挂N挡+拉手刹。别一直D挡踩刹车，脚累车也累。"},
{id:1244,cat:"safe",type:"choice",q:"驾驶机动车在雨天遇到路面有较深积水时，以下哪项做法最安全？",opts:["加速冲过去","挂低速挡匀速缓慢通过，中途不换挡不停车","绕到对向车道避开积水","快速倒车离开"],ans:1,exp:"深积水=挂低挡+匀速一次性缓慢通过+中途不停车不换挡（防排气管进水）。高速冲水=水溅入进气口毁发动机。不知水深时最好绕行或等水位降低。",tip:"口诀：积水=低速慢过（不停不换挡）。不知道多深就别试。"},
{id:1245,cat:"safe",type:"judgment",q:"驾驶人在行车中感觉到困倦时，最有效的解决方法是打开车窗吹风或调大音乐音量以保持清醒。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"开窗和调大音量=只能短暂提神（几分钟），治标不治本。唯一有效的方法=安全停车（服务区、休息站）→小睡15-20分钟（咖啡因+小睡组合效果更好）。疲劳驾驶的危害等同酒驾。",tip:"口诀：困了=停车睡15分钟。开窗/音乐=骗自己，睡着就几秒钟的事。"},
{id:1246,cat:"safe",type:"choice",q:"在学校路段，遇有学生放学过马路时，以下哪种做法是正确的？",opts:["按喇叭提醒学生让路","停车等待，让学生全部通过后再行驶","缓慢行驶，从学生中间穿过","加速在学生通过前冲过去"],ans:1,exp:"学生过马路=完全停车等待（不是减速慢行）。学生可能因嬉戏打闹突然折返——只有完全停止才能保证绝对安全。停车后保持耐心，不鸣笛催促。",tip:"口诀：学生过马路=停死（车完全不动）。孩子不可预测，停着最安全。"},
{id:1247,cat:"safe",type:"judgment",q:"高速公路行驶中，前方发生交通事故导致车道堵塞，后方车辆应开启危险报警闪光灯（双闪）提醒后方来车，并在确保安全的前提下减速停驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速前方事故堵车=立即开双闪提醒后车（防止后车高速追尾）+平稳减速（不急刹，给后车反应时间）+与前车保持足够距离。高速堵车最危险的就是被后车追尾。",tip:"口诀：高速前面堵了=开双闪+减速+远离前车（防被后车撞）。后车追上来前给自己留逃生空间。"},
{id:1248,cat:"safe",type:"choice",q:"驾驶机动车在设有停车让行标志（红色八角形「停」字）的交叉路口，应如何操作？",opts:["减速慢行后通过","在停止线前完全停车，观察确认安全后再通过","按喇叭后通过","不需要停，减速即可"],ans:1,exp:"停牌=必须完全停止（车轮不转）！不是减速——必须在停止线前（或人行横道前/进入路口前）完全停车，左右观察确认无来车或行人后重新起步通过。不完全停车=违法。",tip:"口诀：红色八角「停」=车轮必须停死！不是减速是停。"},
{id:1249,cat:"safe",type:"judgment",q:"在道路上行驶时，与前车保持2秒钟以上的时间间隔是国际通用的安全跟车距离衡量方法。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2秒规则=观察前车通过一个固定参照物（如树、路灯杆）后，自己至少2秒后才到达同一参照物。雨天4秒，冰雪天6-8秒。2秒距离在不同车速下自动调节（车速越快、绝对距离越大）。",tip:"口诀：跟车=2秒规则（前车过某点后，你2秒后才到）。雨4秒冰8秒。"},
{id:1250,cat:"safe",type:"choice",q:"车辆在通过无人看守的铁路道口时，驾驶人应该在什么位置停车观察？",opts:["在铁轨上停车观察","在道口停止线前或距最近铁轨5米以外停车观察","不需要停车","在道口对面停车观察"],ans:1,exp:"无人看守铁路道口=在停止线前（或距最近铁轨≥5米处）停车→左右观察→听有无火车鸣笛→确认安全后挂低速挡平稳通过。不得在铁轨上停车、换挡——万一熄火后果不堪设想。",tip:"口诀：铁路道口=停线外（5米远）→看→听→挂低速挡过。绝不在铁轨上停车。"},
{id:1251,cat:"safe",type:"judgment",q:"驾驶人在日常驾驶中发现车辆有异常抖动、异响或跑偏时，应尽快到专业维修点检查，不应带病上路。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"异常抖动/异响/跑偏=车辆可能存在安全隐患（轮胎/悬挂/制动/转向系统故障）。应及时检查维修，不得带病行驶。小毛病不修变大毛病，更可能引发严重交通事故。",tip:"口诀：车不对劲=快去修。抖动/异响=车的求救信号，别不理。"},
{id:1252,cat:"safe",type:"choice",q:"驾驶机动车在停车场内行驶时，最高速度不应超过多少？",opts:["5km/h","10km/h","20km/h","30km/h"],ans:0,exp:"停车场（室内外）=限速5km/h。停车场内行人多、儿童可能突然出现、视线盲区多、空间狭小——5km/h的速度即使发生碰撞伤害也相对轻微。实际驾驶中以不超过步行速度为宜。",tip:"口诀：停车场=5码（步行速度）。油门基本不踩，脚放刹车上。"},
{id:1253,cat:"safe",type:"judgment",q:"机动车驾驶人在饮酒后至少需要等待8小时才能安全驾驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"酒精代谢速度因人而异（平均每小时10-15mg/100ml），8小时不一定能代谢完毕。宿醉驾驶（隔夜酒驾）同样违法且危险。正确做法：饮酒后至少12小时不驾车，大量饮酒后24小时。",tip:"口诀：酒后至少12小时别开车（隔夜酒也是酒驾）。不确定就找代驾。"},
{id:1254,cat:"safe",type:"choice",q:"驾驶机动车在道路上遇到大货车时，以下哪项做法是正确的？",opts:["长时间与大货车并排行驶","超越大货车时快速平稳通过，避免在大货车盲区久留","在大货车前方缓慢行驶","从右侧紧急停车带超越大货车"],ans:1,exp:"大货车的致命盲区很大（前后左右都有）。做法：不并排、不紧跟、不在其前方减速。超车=确认安全后快速平稳超越，减少在大货车盲区的时间。让大货车超你=减速让道，不打灯示意。",tip:"口诀：远离大货车——不并行、不跟近、不让在它盲区久留。超大货=快准稳。"},
{id:1255,cat:"safe",type:"judgment",q:"驾驶自动挡汽车下长坡时，应挂N挡（空挡）滑行以节省燃油。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"空挡滑行=极端危险+不省油（电喷发动机在带挡滑行时停止喷油，空挡反而继续喷油维持怠速）。下长坡应挂低速挡（L挡/S挡/手动模式低速挡）利用发动机制动，减轻刹车负担防热衰减。",tip:"口诀：下坡别挂N挡（空挡滑行=找死）。挂低速挡用发动机拖住车速。省油是假的。"},
{id:1256,cat:"safe",type:"choice",q:"「开门杀」事故中，驾驶人下车开门时撞到经过的自行车或电动车，如何预防？",opts:["快速开门","采用「荷式开门法」——用远离车门的手开门，身体自然转动观察侧后方","只看后视镜","按喇叭后开门"],ans:1,exp:"荷式开门法（Dutch Reach）=用右手开左边门（或左手开右边门），迫使身体自然转动+头部转向侧后方，便于看到后方来车和行人。配合后视镜观察，双重确认。",tip:"口诀：荷式开门=反手开门（右手开左门）。身体一转，后面自然就看到了。"},
{id:1257,cat:"safe",type:"judgment",q:"驾驶机动车在道路上行驶，如果遇到蛇形行驶或明显异常的前方车辆（可能是酒驾或毒驾），应保持安全距离、报警处理，不要试图拦截。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"疑似酒驾/毒驾车辆=保持距离+稳定观察+报警（告知位置、车型、车牌、行驶方向）+不要贴身跟随或试图拦截——对方行为不可预测，拦截可能引发正面冲突或严重事故。",tip:"口诀：看到蛇形车=远离+报警。别逞英雄去拦，对方是失控状态。"},
{id:1258,cat:"safe",type:"choice",q:"驾驶人在高速公路上行驶，突然发现前方发生连环追尾事故，最合理的应急处置是什么？",opts:["急打方向绕到应急车道","紧握方向盘，用力踩死刹车","紧握方向盘，点刹减速，同时开启双闪，利用ABS（如有）平稳制动并观察后视镜","放弃刹车，利用手刹紧急制动"],ans:2,exp:"高速前方事故=握紧方向+点刹渐进减速（不急刹防后车追尾）+开启双闪提醒后车+观察后视镜看后方来车+必要时驶入应急车道或路肩避让。有ABS的车辆可平稳踩死刹车，方向盘保持可控。",tip:"口诀：高速前面撞了=双闪+点刹渐进减速+看后车。先护自己不被后车撞，再避前面。"},
{id:1259,cat:"safe",type:"judgment",q:"驾驶机动车在道路上掉头时，应选择宽阔、视线良好、没有禁止掉头标志的路段，确保安全后进行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"掉头=选择允许掉头+视线良好+足够宽度的路段+确认前后无来车+打左转向灯+用最低速完成。禁止在铁路道口/人行横道/隧道/窄桥/弯道/陡坡等危险路段掉头。",tip:"口诀：掉头=安全路段+前后无车+打左灯+慢。禁掉头的地方别试。"},
{id:1260,cat:"safe",type:"choice",q:"驾驶机动车在有儿童玩耍的住宅小区道路上行驶时，最高速度不宜超过多少？",opts:["5km/h","10km/h","20km/h","30km/h"],ans:0,exp:"小区道路=限速5km/h（步行速度）。小区内儿童玩耍、老人散步、宠物出没频繁，低矮的儿童可能突然从停放的车辆之间跑出。5km/h=随时可以立即停车的速度。",tip:"口诀：小区里=5码（人走路的速度）。小区不是公路，每栋楼后面都可能窜出小孩。"},
{id:1261,cat:"safe",type:"judgment",q:"驾驶机动车在路口等待左转时，应将车轮保持正直方向，待确认安全可以左转时再打方向。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"等待左转时保持车轮正直=重要的安全习惯。如果提前左打方向，一旦被后车追尾，车辆会被推入对向车道——与对向来车发生更严重的二次碰撞。正直方向=即使被追尾也是被推向前方而非侧方。",tip:"口诀：等左转=方向正（别提前打）。后车追尾=被推直行不至于撞对向来车。"},
{id:1262,cat:"safe",type:"choice",q:"驾驶人收到「车辆安全召回」通知后，应该怎么做？",opts:["可以不予理会","在规定时间内将车辆送至指定维修点免费维修","自行维修","卖掉车辆"],ans:1,exp:"汽车召回=制造商免费维修（更换缺陷零部件）。收到召回通知后应在规定期限内配合。拒不配合召回不得上路行驶。召回是保障安全的法定制度，由市场监管部门监督执行。",tip:"口诀：召回=免费修！不是要你掏钱。按期去修就行。"},
{id:1263,cat:"safe",type:"judgment",q:"驾驶机动车进入环岛（环形路口）前应减速，让已在环岛内的车辆先行，驶出环岛时开启右转向灯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"环岛通行=进让出（进岛让岛内的车）+出打灯（驶离环岛前开右转灯）。环岛内行驶不需打灯。进环岛前应减速观察岛内车辆动态。",tip:"口诀：进环岛让岛内→出环岛打右灯。岛内直走不需打灯。"},
{id:1264,cat:"safe",type:"choice",q:"驾驶机动车在雨天夜间行驶时，路面上的车道标线会因雨水反光而看不清，这时应如何判断车道？",opts:["凭感觉开","看道路右侧的边缘线或路沿石来判断车身位置","看对面来车","加速通过"],ans:1,exp:"雨天夜间标线反光难辨=看右侧边缘线或路沿石。这是被远光眩目时的同款应对技巧——利用右侧边缘确定车辆在车道内的位置。同时降低车速，保持更大的跟车距离。",tip:"口诀：雨夜标线看不清=看右边白线/路沿。右边是判断车身位置的锚点。"},
{id:1265,cat:"safe",type:"judgment",q:"驾驶机动车在道路上行驶时，如果车内发生争吵或有其他干扰，驾驶人应靠边停车处理完毕后再继续行驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"车内情绪激动或冲突=严重影响注意力。驾驶人应在安全位置靠边停车，处理好情绪后再继续驾驶。带着负面情绪开车=危险程度成倍增加。",tip:"口诀：车里吵架=靠边停+冷静后再走。带着气开车=带事故隐患开车。"},
{id:1266,cat:"safe",type:"choice",q:"高速公路上，如果前方有一队摩托车骑行，正确的超车方式是什么？",opts:["从车队中间穿插","选择宽阔路段，保持足够横向距离（至少1.5米），逐一平稳超越","加速鸣喇叭示意他们让路","紧贴摩托车超车"],ans:1,exp:"超摩托车队=保持足够横向距离（至少1.5米）+平稳超车+不惊吓。摩托车受侧风影响大，你贴身超车会造成气流冲击导致骑行者失控。不要从车队中间穿插——极易引发碰撞。",tip:"口诀：超摩托车=给够横向空间（1.5米以上）+不惊吓。气流也能撞翻摩托车。"},
{id:1267,cat:"safe",type:"judgment",q:"驾驶机动车在高速公路上，如果遇到动物突然横穿，首先应当急打方向避让。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速遇动物=握紧方向+稳定减速（不急刹）+不猛打方向！急打方向避让动物比自己撞护栏或被后车追尾更危险。在无法安全避让时，减速后正面碰撞比侧翻和失控更安全。安全辅助系统（AEB）可能自动制动。",tip:"口诀：高速上有动物窜出=减速但不猛打方向。宁撞动物不翻车。"},
{id:1268,cat:"safe",type:"choice",q:"驾驶人在服务区停车休息后准备离开，正确的出行前检查顺序是什么？",opts:["直接开走","绕车一周检查轮胎、灯光、车周有无障碍物和儿童后再上车","只检查油量","检查导航就可以"],ans:1,exp:"出发前=绕车一周检查！检查轮胎气压和磨损、灯光是否正常、车周有无障碍物/儿童/动物、牌照是否清洁可见。专业驾驶人的习惯——每次停车后重新出发前都要绕车一周。",tip:"口诀：上车前绕一圈=看轮胎+车周围+牌照。这个习惯能救命。"},
{id:1269,cat:"safe",type:"judgment",q:"驾驶机动车在道路上行驶时，应尽量避免使用手机导航，即使在等红灯时也不应操作手机。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"等红灯=车辆仍在「驾驶中」——使用手机同样属于妨碍安全驾驶行为。即使挂了P挡或拉了手刹，只要在道路上处于驾驶状态，操作手机都可能被处罚。需要操作导航应靠边停车后进行。",tip:"口诀：等红灯也不能碰手机！驾驶中=全程（含等红灯）。需要改导航=停车再改。"},
{id:1270,cat:"safe",type:"choice",q:"驾驶机动车在冬季低温环境下，以下哪项关于车辆起步的说法是正确的？",opts:["启动后立即高速行驶以快速升温","启动后怠速运转30秒-1分钟，然后低速行驶一段距离，待水温正常后再正常行驶","长时间原地怠速热车","不需要热车"],ans:1,exp:"现代电喷发动机不需长时间热车——启动后怠速30秒-1分钟，以中低速（2000转以下）行驶至水温表指针开始移动后即可正常行驶。长时间原地怠速不仅费油且增加积碳。",tip:"口诀：冬天热车=启动后等30秒→低速走→水温上来再加速。不原地等太久。"},
{id:1271,cat:"safe",type:"judgment",q:"驾驶机动车遇到有人在路边示意搭车（竖大拇指）时，可以在应急车道停车搭载。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路上严禁停车搭载路人——即使对方是求助者。正确做法：帮助拨打12122报警，由专业救援人员处理。高速公路行人本身就是禁止的，停车搭载一并将自己置于危险中。",tip:"口诀：高速上别停车载人（帮打电话就行）。应急车道不是搭车站。"},
{id:1272,cat:"safe",type:"choice",q:"驾驶机动车在道路上行驶，正确的坐姿和方向盘握法是什么？",opts:["单手放在方向盘12点位置","双手分别放在方向盘9点和3点位置（或8点和4点），背部紧贴座椅","身体前倾靠近方向盘","单手放在车窗上"],ans:1,exp:"标准握姿=双手9点和3点（或8点和4点）+背部贴紧座椅+手臂微弯曲（约120度）+腿部微曲膝。这种姿势在碰撞时气囊展开有足够空间，方向盘助力最有效，紧急操作反应最快。",tip:"口诀：握方向盘=9点+3点（双手对称）。不是12点也不是单手耍酷。"},
{id:1273,cat:"safe",type:"judgment",q:"在高速公路行驶中，频繁变更车道能更快到达目的地。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"频繁变道≠更快。研究表明，拥堵路况中频繁变道最多节省约4%的时间（可忽略不计），但事故风险增加600%以上。匀速在一个车道行驶=安全+省油+省心。",tip:"口诀：变来变去快不了（顶多省4%时间），事故风险涨6倍。安心走一条道。"},
{id:1274,cat:"safe",type:"choice",q:"驾驶机动车下长坡时，如果刹车踏板感觉变软、制动效果明显下降（热衰减），紧急应对措施是什么？",opts:["继续踩刹车","抢挂低速挡利用发动机制动+寻找紧急避险车道","拉起手刹","关闭发动机"],ans:1,exp:"刹车热衰减=抢挂低挡（自动挡切手动模式/低速挡）+发动机制动降速+寻找紧急避险车道（上坡沙石路=救命坡）。不要反复踩刹车——越踩越热越没刹车。必要时利用山体或护栏摩擦停车。",tip:"口诀：下坡没刹车了=抢低挡+找避险车道。千万不能熄火（熄火=没方向+没刹车）。"},
{id:1275,cat:"safe",type:"judgment",q:"「让速不让道」是指遇到侧方车辆突然变道侵入自己车道时，应减速让行而不是急打方向避让。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"让速不让道=遇到入侵自己车道=减速但不打方向避让。急打方向可能导致自己失控撞护栏或撞到隔壁车道的车（自己全责）。保持在自己的车道内减速——即使被撞也不是你的责任。",tip:"口诀：别车来了减速度但别换道。让速不让道——方向不动踩刹车。换道撞了是你的错。"},
{id:1276,cat:"operation",type:"choice",q:"自动挡汽车的P挡（Parking）应在什么情况下使用？",opts:["临时停车等红灯","长时间停车（熄火后）使用，变速箱通过锁止机构锁住输出轴","行驶中滑行","短时间停车不熄火"],ans:1,exp:"P挡=驻车挡（熄火停车时用）。P挡通过机械锁止机构锁住变速箱输出轴，防止车辆移动。注意：必须完全停稳后才能挂入P挡，否则会损坏锁止机构。等红灯用N挡或D挡+刹车即可。",tip:"口诀：P挡=停车熄火时用。必须车完全停稳再挂P。红灯别挂P（被追尾撞坏变速箱）。"},
{id:1277,cat:"operation",type:"judgment",q:"自动挡汽车在行驶中可以从D挡直接挂入R挡（倒挡）。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"D挡→R挡=必须先完全停车！行驶中误挂R挡会严重损坏变速箱（AT/AT内部齿轮崩裂）。现代车辆虽有电子保护（行驶中挂R挡不会执行），但绝不可尝试。",tip:"口诀：D挡变R挡=必须停车。行驶中挂R挡=变速箱自杀。"},
{id:1278,cat:"operation",type:"choice",q:"自动挡汽车的N挡（Neutral空挡）的主要作用是什么？",opts:["长时间停车","短时间停车不熄火（如等红灯）或车辆故障时被牵引拖车时使用","上坡起步","高速行驶中滑行"],ans:1,exp:"N挡=空挡（切断发动机与车轮的动力连接）。用于短时停车+拖车牵引（但拖车速度不得超过50km/h、距离不超过50km）。严禁N挡滑行——失去发动机制动，转向助力可能减弱，极度危险。",tip:"口诀：N挡=短暂切断动力（等红灯/拖车用）。别N挡滑行！"},
{id:1279,cat:"operation",type:"judgment",q:"自动挡汽车在等红灯时应当挂P挡以保证绝对安全。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"短时间等红灯=N挡+手刹（或D挡+踩刹车），不是P挡。P挡时变速箱锁止——万一被后车追尾，冲击力会直接损坏变速箱锁止机构和壳体。长红灯可挂N挡拉手刹。",tip:"口诀：等红灯别挂P（追尾毁变速箱）。短灯D+刹车，长灯N+手刹。"},
{id:1280,cat:"operation",type:"choice",q:"自动挡汽车下陡坡时，使用D挡长时间踩刹车可能造成刹车热衰减。正确的档位选择是什么？",opts:["N挡（空挡）","D挡+间歇踩刹车","L挡（或S挡/手动模式低速挡），利用发动机制动","R挡倒车下坡"],ans:2,exp:"下长坡=挂L挡（或S挡/手动模式选低挡位）+发动机制动。发动机转速升高拖住车速，大幅减少刹车使用频率，防止热衰减。没有低速挡的可用手动模式锁定2挡或3挡。",tip:"口诀：自动挡下长坡=挂L/S/手动低挡（让发动机帮忙刹车）。D挡一路踩刹车=刹车冒烟。"},
{id:1281,cat:"operation",type:"judgment",q:"S挡（Sport运动模式）通过提高换挡转速来获得更快的动力响应，但燃油经济性会降低。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"S挡=延迟升挡时机+发动机转速更高=动力响应更快+油耗增加15%-30%。适合超车、爬陡坡、山路驾驶。日常巡航用D挡更经济。S挡只是改变换挡逻辑，不改变发动机本身动力。",tip:"口诀：S挡=运动模式=更有劲+更费油。超车爬坡用S，平常D挡省油。"},
{id:1282,cat:"operation",type:"choice",q:"手动挡汽车下长坡时，使用刹车控制车速可能导致刹车热衰减。正确的操作方法是什么？",opts:["挂空挡滑行","挂低速挡（2挡或3挡），利用发动机制动辅助控制车速","频繁踩刹车","熄火滑行"],ans:1,exp:"手动挡下长坡=挂低速挡+发动机制动。发动机在高转速下不喷油（电喷发动机减速断油功能）——既安全又省油。下坡车速用低挡控制，刹车只用于必要时的辅助减速。",tip:"口诀：手动挡下坡=挂低速挡（2/3挡）靠发动机拖住。不是空挡滑行也不是一直踩刹车。"},
{id:1283,cat:"operation",type:"judgment",q:"CVT（无级变速器）车型在急加速时，发动机转速会维持在一个较高且恒定的转速，而车速持续增加。这是正常的CVT工作特性。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"CVT加速=发动机转速爬升到一个高效点后保持恒定转速（如4000转），车速通过传动比连续变化持续增加。与AT/DCT「转速上去→换挡掉转速→再上去」的台阶感完全不同。这是CVT的正常特性。",tip:"口诀：CVT加速=转速稳住，车速往上窜。不换挡的变速箱，加速感像滑滑梯。"},
{id:1284,cat:"operation",type:"choice",q:"双离合变速箱（DCT/DSG）在低速蠕行时可能出现轻微顿挫，这是什么原因？",opts:["变速箱故障","双离合器在1挡和2挡之间频繁切换判断犹豫（正常的机械特性）","油品问题","需要更换变速箱"],ans:1,exp:"DCT低速顿挫=双离合器在走走停停时频繁在1挡和2挡之间预位切换，偶尔判断延迟导致轻微顿挫——属于正常机械特性，不算故障。严重顿挫或异响才需检查。",tip:"口诀：双离合低速顿=正常（低速走走停停它不知道该1还是2挡）。不严重不担心。"},
{id:1285,cat:"operation",type:"judgment",q:"自动挡汽车在坡道上停车时，应按照「踩刹车→挂N挡→拉手刹→松脚刹（确认手刹能停住车）→挂P挡→熄火」的顺序操作，以保护变速箱锁止机构。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"坡道停车正确顺序=踩刹车→挂N挡→拉紧手刹→松开脚刹确认手刹可独立停住→再挂P挡→熄火。这样重力由手刹承担而非变速箱P挡锁止机构。直接挂P挡熄火后车辆可能溜动冲击变速箱。",tip:"口诀：坡道停自动挡=先N+手刹停稳→再挂P。让手刹受力，P挡备用。"},
{id:1286,cat:"operation",type:"choice",q:"在坡道上停车时，除拉手刹、挂挡外，还应将前轮转向什么方向？",opts:["正对前方","上坡停车前轮向左打（朝向路中央），下坡停车前轮向右打（朝向路沿）","任意方向","朝向路中央"],ans:1,exp:"坡道停车防溜=手刹+挂挡（手动挂1挡/倒挡，自动挂P）+方向打向路边。上坡前轮向左打（万一溜车，车尾撞路沿停住）；下坡前轮向右打（万一溜车，车头撞路沿停住）。",tip:"口诀：上坡左打轮，下坡右打轮。方向打往路边——溜车撞路沿（不是冲下坡）。"},
{id:1287,cat:"operation",type:"judgment",q:"手动挡汽车起步时，应先松开手刹，然后慢慢抬起离合器踏板，同时轻踩油门，三者协调配合完成平稳起步。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"手动挡起步=踩离合+挂1挡→慢抬离合至半联动（感觉车抖动或车头微翘）→稳住离合高度→松手刹→轻踩油门+继续抬离合=平稳起步。离合抬太快=熄火。",tip:"口诀：手动起步=慢抬离合+轻加油+松手刹。「三联动」协调好，车不抖不熄。"},
{id:1288,cat:"operation",type:"choice",q:"手动挡车辆在需要快速超车时，如果需要最大加速度，应该怎样操作？",opts:["在5挡深踩油门","降一个或两个挡位（如5挡降3挡）提高发动机转速后再加速","挂空挡后再挂回原挡位","缓慢加速"],ans:1,exp:"手动挡急加速超车=降挡提高发动机转速（进入最大扭矩区间）+深踩油门。高挡位低速时发动机扭矩不足，加速缓慢。降挡使发动机转速升至3000-5000转，获得最大扭矩输出。",tip:"口诀：手动挡超车=降挡（5降3或4降3）+深踩油门。高挡位没劲，降挡才有爆发力。"},
{id:1289,cat:"operation",type:"judgment",q:"双离合变速箱（DCT）可以像传统AT自动变速箱一样进行长时间D挡踩刹车等候而不受影响。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"DCT长时间D挡踩刹车=离合器半联动摩擦发热→加速离合器片磨损。等红灯超过10秒建议挂N挡。这与AT变速箱（液力变矩器可长时间D挡）不同——DCT没有液力变矩器缓冲。",tip:"口诀：双离合=红灯长挂N挡（别一直D挡踩刹车）。它没有液力变矩器保护，会磨损离合。"},
{id:1290,cat:"operation",type:"choice",q:"车辆在冰面起步时，手动挡应如何操作？",opts:["1挡大油门起步","使用2挡起步（减少扭矩输出降低打滑风险），极轻踩油门","快速松开离合器","正常1挡起步"],ans:1,exp:"冰面手动挡起步=用2挡（甚至3挡）起步+极轻油门+极慢抬离合。2挡起步减小了传递到车轮的扭矩，降低打滑概率。自动挡使用雪地模式（如有）或轻踩油门。",tip:"口诀：冰面起步=2挡（手动）或雪地模式（自动）+轻踩油门。大油门=车轮空转更滑。"},
{id:1291,cat:"operation",type:"judgment",q:"装备有Auto Hold（自动驻车）功能的车辆在等红灯时，踩停后可以松开刹车踏板，车辆会自动保持制动，起步时轻踩油门自动解除。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"Auto Hold（自动驻车）=踩停后自动拉起电子手刹保持制动→可松开脚刹→绿灯时轻踩油门自动解除制动+起步。不需要手动操作手刹，也不需要一直踩刹车。与电子手刹配合工作。",tip:"口诀：Auto Hold=踩停自动刹住→点油门自动松开。等红灯可以松开脚休息。"},
{id:1292,cat:"operation",type:"choice",q:"电子手刹（EPB）与机械手刹（传统手刹杆）相比的主要优势是什么？",opts:["没有优势","按钮操作、节省车内空间、可与Auto Hold联动、紧急时可作为辅助制动（持续拉起不放=四轮制动）","制动效果更好","更便于漂移"],ans:1,exp:"EPB=按钮代替手柄+节省空间+Auto Hold联动+紧急制动（持续拉起EPB按钮不放=ESP系统以最大制动力四轮制动，比机械手刹更安全稳定）。缺点：没电时无法释放手刹。",tip:"口诀：电子手刹=按钮操作+自动驻车+紧急时持续拉起可四轮刹车。比机械手刹聪明。"},
{id:1293,cat:"operation",type:"judgment",q:"装备有陡坡缓降控制系统（HDC）的车辆在下陡坡时，系统会自动控制车速在设定范围内（通常5-30km/h），驾驶人只需控制方向无需踩刹车和油门。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"HDC（Hill Descent Control）=自动控制下坡车速在设定低速范围+驾驶人只需控制方向盘。系统通过ABS泵对每个车轮单独制动维持恒定低速。SUV和越野车常见配置。",tip:"口诀：陡坡缓降（HDC）=下坡你只管方向，车速系统帮你管。越野利器。"},
{id:1294,cat:"operation",type:"choice",q:"汽车车顶行李架装载物品时，从车顶算起装载高度不得超过多少？",opts:["0.5米","1米","1.5米","2米"],ans:0,exp:"车顶行李架装载高度从车顶起不得超过0.5米（50cm）。总高度（地面到装载物顶端）不得超过4米（普通车辆）。超高超宽=记1分+罚款。装载物必须牢固捆绑。",tip:"口诀：车顶载物=不超过车顶上面半米高。总高度不超过4米。"},
{id:1295,cat:"operation",type:"judgment",q:"车辆装载货物时可以超出车身宽度，只要不超过后视镜宽度即可。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"载货宽度不得超过车身宽度（不能超出车身轮廓）。超出车身宽度的属超宽装载=记1分+罚款。超大型不可解体物品超宽需办理超限运输许可并悬挂标志。",tip:"口诀：货物不能比车身宽（不能伸出车身两侧）。超宽=1分。"},
{id:1296,cat:"operation",type:"choice",q:"车辆使用非全尺寸备胎（小备胎）行驶时，最高速度不应超过多少？",opts:["40km/h","60km/h","80km/h","100km/h"],ans:2,exp:"非全尺寸备胎（俗称小备胎/窄备胎）=限速80km/h（通常标注在备胎上）+尽快更换全尺寸轮胎+不宜长途行驶。小备胎抓地力和稳定性较差，高速行驶有安全隐患。",tip:"口诀：小备胎=80码封顶+赶紧去修车店换回正常胎。小备胎不是长期用的。"},
{id:1297,cat:"operation",type:"judgment",q:"防滑链应安装在车辆的驱动轮上（前驱车装前轮，后驱车装后轮，四驱车四个轮都装）。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"防滑链=装在驱动轮上最有效。前驱车前轮，后驱车后轮。四驱车最理想四个轮都装。安装后限速40-50km/h，进入干燥路面需及时拆除（损坏路面+链条损坏+噪音震动大）。",tip:"口诀：防滑链装驱动轮+限速40-50码。没冰没雪就拆掉。"},
{id:1298,cat:"operation",type:"choice",q:"涡轮增压发动机在长时间高速行驶后，停车熄火前应如何操作？",opts:["立即熄火","怠速运转1-2分钟，让涡轮冷却和润滑后再熄火","挂空挡踩油门","直接拔钥匙"],ans:1,exp:"涡轮增压器转速可达10-20万转/分钟，工作温度极高（800-1000℃）。高速行驶后立即熄火=机油停止循环→涡轮轴承高温结焦积碳→缩短寿命。怠速1-2分钟使涡轮冷却+机油带走余热。",tip:"口诀：涡轮车高速后=怠速1-2分钟再熄火。让涡轮冷却下来，否则烧轴承。"},
{id:1299,cat:"operation",type:"judgment",q:"自动启停系统（Start-Stop）在车辆停止时自动熄火以节省燃油，松开刹车或踩油门时自动重启发动机。在严重拥堵走走停停时建议关闭该系统。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"频繁启停=电瓶和启动机磨损加大+每次重启的震动影响舒适性。严重拥堵走走停停（每次停机不到5秒又启动）=建议关闭启停系统。正常等红灯=启停有助于省油5%-10%。",tip:"口诀：走走停停堵车时=关掉启停。正常等红灯=开着省油。几秒一启停反而费电瓶。"},
{id:1300,cat:"operation",type:"choice",q:"后驱车在冰雪路面起步时相比前驱车更容易出现什么情况？",opts:["转向不足","甩尾（车尾侧滑）","前轮打滑","熄火"],ans:1,exp:"后驱车（RWD）=冰雪起步车尾容易甩向一侧。原因：后轮驱动+车头重尾轻（大部分重量在前）+后轮抓地力不足→车尾外摆。应极轻踩油门+方向盘迅速修正。前驱车更容易出现前轮打滑（转向不足）。",tip:"口诀：后驱冰雪=屁股甩（油门稍大就甩尾）。前驱冰雪=车头推（打方向转不过来）。"},
{id:1301,cat:"operation",type:"judgment",q:"四驱车辆（4WD/AWD）在冰雪路面上的制动距离比两驱车短。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"四驱=提高加速抓地力（不容易打滑起步），但不缩短制动距离！制动距离取决于轮胎与路面的摩擦力+车重+制动系统效能——与驱动形式无关。四驱车冰雪路面制动距离与两驱车相同。",tip:"口诀：四驱=好起步≠刹车距离短。冰雪路上刹车大家都一样（看轮胎不看你几个轮驱动）。"},
{id:1302,cat:"operation",type:"choice",q:"差速锁（Differential Lock）在什么情况下应该使用？",opts:["日常公路驾驶","当一个车轮悬空或极度打滑失去抓地力时，锁定差速器使两侧车轮同速旋转以脱困","高速公路行驶","任何路况都开启"],ans:1,exp:"差速锁=越野脱困工具。当一个车轮悬空打滑时，普通差速器会把动力全部传到打滑的车轮（空转），另一个有抓地力的车轮得不到动力。锁止差速器强制两侧车轮同速旋转，恢复驱动力。公路行驶必须解除锁止。",tip:"口诀：差速锁=一个轮悬空时用（锁住两个轮一起转）。脱困后就关，公路不能锁。"},
{id:1303,cat:"operation",type:"judgment",q:"全时四驱（AWD全轮驱动）车辆在任何路面条件下都可以比两驱车更快地行驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"AWD=提高牵引力和稳定性，但不是速度加成器。在干燥路面正常行驶时AWD与两驱无明显速度差异。在某些路况（如湿滑）AWD确实更容易加速，但过度自信开太快反而更危险。AWD不等于安全+速度双重加成。",tip:"口诀：四驱≠能开更快。它帮你起步稳，但不帮你刹车。别有了四驱就狂。"},
{id:1304,cat:"operation",type:"choice",q:"自动挡汽车长时间停放在陡坡上，仅挂P挡不拉手刹有什么风险？",opts:["没有任何风险","P挡锁止机构承受全部重力，长期可能导致锁止机构过度磨损或卡住，难以从P挡移出","变速箱油会漏出","发动机会损坏"],ans:1,exp:"陡坡P挡不拉手刹=整车重力压在变速箱P挡锁止机构上（一个小金属爪）。长期会造成锁止机构变形/过度磨损/卡死→下次从P挡移出时出现「砰」的一声并难以移动。手刹应先受力。",tip:"口诀：坡上P挡不拉手刹=摧残变速箱。先拉手刹让手刹受力，P挡后备。"},
{id:1305,cat:"operation",type:"judgment",q:"手动挡车辆换挡时应眼睛看转速表和档位指示，以确保挂入正确档位。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"换挡应凭手感+肌肉记忆，眼睛保持看路！低头看挡杆或仪表=视线离开道路=极度危险。经过练习后换挡应盲操。转速声音和车速感觉告诉你何时换挡，不需要看表。",tip:"口诀：换挡=凭手感不看挡。低头看挡=追尾。"},
{id:1306,cat:"operation",type:"choice",q:"手动挡在高速行驶时如果需要紧急制动，正确的操作是什么？",opts:["先踩离合再踩刹车","同时踩下离合和刹车（或先刹车后离合）","只踩刹车不踩离合","挂空挡后踩刹车"],ans:1,exp:"紧急制动=离合+刹车一起踩（或先刹车后立即踩离合）。原因：①防止发动机熄火（熄火=失去转向助力+刹车助力）；②ABS和ESP需要发动机运转维持工作。只踩刹车不跟离合=接近停车时发动机会剧烈抖动甚至熄火。",tip:"口诀：手动急刹车=双脚齐下（刹车+离合一起踩）。防熄火保全安全系统。"},
{id:1307,cat:"operation",type:"judgment",q:"自动挡汽车在行驶中遇到长下坡，挂N挡（空挡）滑行可以有效节省燃油。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"电喷发动机带挡滑行=不喷油（减速断油模式），空挡滑行=维持怠速喷油。带挡滑行更省油！且带挡有发动机制动保证安全。空挡滑行不仅不省油而且极度危险。",tip:"口诀：带挡滑行=不喷油（真省油）；空挡滑行=喷油+危险（伪省油）。别被老司机误导。"},
{id:1308,cat:"operation",type:"choice",q:"电子助力转向系统（EPS）与液压助力转向系统相比，以下哪项说法正确？",opts:["没有区别","EPS在发动机关闭时转向助力也消失；EPS在电气系统通电时就能提供助力","EPS比液压助力差","EPS只用在赛车上"],ans:1,exp:"EPS（电动助力）=电动马达辅助转向，通电即可工作（即使发动机关闭）。液压助力=发动机带动液压泵，发动机关闭=助力消失（方向盘变沉重）。EPS还具有可变助力（低速轻、高速重）的优势。",tip:"口诀：电动助力（EPS）=通电就有助力。液压助力=发动机不转=没助力（沉）。"},
{id:1309,cat:"operation",type:"judgment",q:"无钥匙启动（一键启动）的车辆，在行驶中长按启动按钮可以强制关闭发动机。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"行驶中紧急情况下，长按一键启动按钮（约3秒）或连续按3次=强制熄火。这是紧急安全功能——用于油门卡住等紧急情况。但熄火后转向和刹车助力会消失，操作需格外谨慎。",tip:"口诀：一键启动紧急熄火=长按3秒或连按3次。但熄火后没助力，仅限紧急情况用。"},
{id:1310,cat:"operation",type:"choice",q:"以下关于拖挂房车（轻型牵引挂车）行驶的说法，哪项正确？",opts:["可以任意速度行驶","牵引车和挂车之间应连接安全链（保险链），挂车应有独立刹车系统，行驶中注意横向摆动","与普通轿车驾驶无区别","挂车不需要任何特殊装置"],ans:1,exp:"拖挂行驶=安全链（防脱钩）+挂车刹车系统（制动惯性刹车或电子刹车）+注意横向摆动（蛇形失控）+转弯半径加大+倒车方向相反。挂车总质量不超过牵引车的允许拖挂质量。",tip:"口诀：拖挂房车=安全链+挂车刹车+小心蛇形摆动。倒车方向反的！"},
{id:1311,cat:"operation",type:"judgment",q:"胎压监测系统（TPMS）报警灯亮起时，表示至少有一个轮胎气压严重不足，应尽快检查轮胎气压。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"TPMS灯亮=至少一个轮胎胎压低于标准值25%以上（或高于标准值）。应立即找安全地点停车检查——目视检查轮胎+用胎压表测量+充气或更换备胎。高速行驶中爆胎极其危险。",tip:"口诀：胎压灯亮=赶紧停车查轮胎。不是误报就是真漏气，认真对待。"},
{id:1312,cat:"operation",type:"choice",q:"汽车在高速公路行驶时正确的胎压应该是什么状态？",opts:["比标准胎压低以增加舒适性","按照车辆制造商推荐的冷胎标准胎压（通常标注在车门框或油箱盖内侧）","比标准胎压高以省油","无所谓"],ans:1,exp:"胎压=按厂家标准冷胎胎压（车辆停驶3小时后或行驶不超过2km的冷态下测量）。标准胎压标注在驾驶座车门框、油箱盖或车主手册。高速行驶胎压过低比过高更容易爆胎。",tip:"口诀：胎压=按厂家标准来（车门框上有标）。冷胎时打气。别自己乱调。"},
{id:1313,cat:"operation",type:"judgment",q:"使用定速巡航（CCS）在高速公路行驶时，驾驶人可以完全不用关注前方路况。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"定速巡航=只控制油门维持恒定速度，不控制方向、不控制刹车、不识别障碍物。驾驶人仍需全程握方向盘+观察路况+随时准备制动。使用定速巡航容易注意力下降，应保持警觉。",tip:"口诀：定速巡航=只帮你踩油门，方向+刹车+观察还是你来。千万别当自动驾驶。"},
{id:1314,cat:"operation",type:"choice",q:"手动挡车辆在湿滑路面起步时，为了降低打滑风险，下面哪种方法最有效？",opts:["1挡加大油门","用2挡起步，轻抬离合，小油门","不踩油门只靠离合器","快速弹离合"],ans:1,exp:"湿滑路面=2挡起步（发动机扭矩输出减少）+极轻油门+极慢抬离合。低扭矩减少打滑概率。前驱车若打滑可尝试轻微左右转动方向盘寻找抓地力。自动挡有雪地模式的应开启。",tip:"口诀：湿滑起步=2挡+轻油门+慢离合。大油门1挡=打滑空转原地不动。"},
{id:1315,cat:"operation",type:"judgment",q:"自动挡汽车在行驶中如果需要更高的发动机制动效果（如下坡），可以从D挡切换到手动模式并降挡。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"手自一体变速箱（带手动模式）=行驶中可随时切换到手动模式并降挡提高发动机制动效果。降挡后发动机转速升高=制动效果更强。注意降挡不宜过快（逐级降），避免发动机超转速。",tip:"口诀：自动挡下坡=切手动→降挡→发动机制动。转速升高正常，别慌。"},
{id:1316,cat:"operation",type:"choice",q:"车辆在长时间不使用（超过一个月）时，以下哪项保养措施是正确的？",opts:["不需要做任何处理","断开电瓶负极防止亏电；胎压适当调高防轮胎变形；满油存储防油箱生锈（燃油车）；保持50%以上电量存储（电动车）","每天启动一次","放在室外通风处即可"],ans:1,exp:"长时间停驶=断开电瓶负极（或定期充电）+胎压适当调高（防轮胎扁平变形）+燃油车满油（防油箱内部冷凝生锈）+电动车保持50%-70%电量+使用车罩防晒防尘。",tip:"口诀：一个月不开=断电瓶+胎压略高+满油/半电+盖车衣。别扔那不管。"},
{id:1317,cat:"operation",type:"judgment",q:"汽车加油时，为安全起见应关闭发动机，不得吸烟、不得使用手机、不得在油箱口附近产生火花。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"加油=必须熄火+禁止吸烟+禁止使用手机（防静电火花）+不要回到车内（产生静电后再接触油枪可能引发火灾）。使用手机引发加油站火灾虽然是极小概率事件，但安全规定仍禁止。",tip:"口诀：加油=熄火+不抽烟+不打手机。别上车坐着又下来摸油枪（静电危险）。"},
{id:1318,cat:"accident",type:"choice",q:"在无信号灯控制的交叉路口发生两车碰撞事故，以下哪种情况A车承担全部责任？",opts:["两车同时进入路口","A车未让行右方道路来车（B车从右侧驶来）发生碰撞","两车都是直行","B车追尾A车"],ans:1,exp:"无信号路口=让右原则。A车未让行右侧来车B车导致碰撞=A车全责。相对方向=转弯让直行、右转让左转。追尾=后车全责。同时进入路口应各自承担同等责任或按过错比例分担。",tip:"口诀：无灯路口=让右边的车。你的右边有车=你要让。撞了=没让的全责。"},
{id:1319,cat:"accident",type:"judgment",q:"发生交通事故后，事故双方对事故事实和成因无争议的，可以自行协商处理损害赔偿事宜，无需报警。但造成人员伤亡的必须报警。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无人伤+事实无争议=自行协商或走快处快赔。有人伤（任何程度）=必须报警+保护现场+抢救伤员。自行协商后应签订书面协议或在快处快赔中心办理。",tip:"口诀：人没事+没争议=自己协商。有人受伤=必须报警。区分清楚。"},
{id:1320,cat:"accident",type:"choice",q:"发生交通事故后，一方驾驶人逃逸的，事故责任如何认定？",opts:["逃逸方无责任","逃逸方承担全部责任。但有证据证明对方也有过错的，可以减轻逃逸方责任","双方各50%","责任由警方随机认定"],ans:1,exp:"逃逸=推定全责（法律对逃逸的严厉态度）。但如果对方也有明显过错（如闯红灯），逃逸方可减轻责任但不能免责。逃逸本身额外承担行政处罚（记12分+罚款+可能拘留或刑事处罚）。",tip:"口诀：逃逸=全责推定（先认全责再说）。对方也有错可以减但不能免。逃逸=错上加错。"},
{id:1321,cat:"accident",type:"judgment",q:"发生交通事故后当事人逃逸的，逃逸的当事人承担全部责任。但是有证据证明对方当事人也有过错的，可以减轻责任。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"逃逸推定全责是法律的严厉立场。但如有证据证明对方也有过错（如对方闯红灯在先），可相应减轻逃逸方责任。逃逸本身仍会被记12分并面临其他处罚。",tip:"口诀：逃逸先认全责，对方有错可减轻。逃逸记12分没商量。"},
{id:1322,cat:"accident",type:"choice",q:"交通事故损害赔偿争议的解决途径不包括以下哪项？",opts:["请求公安机关交通管理部门调解","向人民法院提起民事诉讼","向仲裁机构申请仲裁（如双方达成仲裁协议）","单方面向保险公司申请全额赔付并强制对方接受"],ans:3,exp:"交通事故赔偿争议解决途径：①双方协商→②交警调解（非强制）→③民事诉讼→④仲裁（需双方同意）。保险公司赔付基于责任认定，不能强制对方接受自己单方面提出的赔偿方案。",tip:"口诀：事故赔偿=先协商→再调解→最后法院。保险按责任赔，不强求对方。"},
{id:1323,cat:"accident",type:"choice",q:"机动车与行人或非机动车驾驶人之间发生交通事故，赔偿责任如何划分？",opts:["行人全责","机动车一方永远全责","机动车一方承担赔偿责任。但如有证据证明行人/非机动车方有过错的，可减轻机动车方责任。即使机动车方无过错，也需承担不超过10%的赔偿责任","双方各50%"],ans:2,exp:"机动车vs行人/非机动车=机动车承担主要赔偿责任（基于优者危险负担原则）。行人有过错=减轻机动车责任。机动车完全无过错（如行人闯红灯+翻越护栏）=机动车仍承担≤10%的无过错赔偿责任（交强险兜底）。这是保护弱势交通参与者的立法精神。",tip:"口诀：车撞人=车先赔。人有错减一点，车没错也赔≤10%（交强险兜底）。法律倾向保护弱者。"},
{id:1324,cat:"accident",type:"judgment",q:"道路交通事故社会救助基金可以垫付受害人的抢救费用和丧葬费用。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"救助基金=三种情形可垫付：①肇事车辆未参保交强险→②肇事逃逸无法找到→③抢救费用超过交强险责任限额。救助基金管理机构垫付后有权向事故责任人追偿。",tip:"口诀：救助基金=三情形垫付——没保险/逃逸找不着/超限额。救命钱先垫，回头再找责任人要。"},
{id:1325,cat:"accident",type:"choice",q:"驾驶人血液中酒精含量达到多少属于「饮酒后驾驶」？",opts:["≥10mg/100ml","≥20mg/100ml","≥80mg/100ml","≥100mg/100ml"],ans:1,exp:"饮酒驾车=20mg/100ml≤BAC<80mg/100ml。醉酒驾车=BAC≥80mg/100ml。饮酒驾车=暂扣驾照6个月+罚款1000-2000元+记12分。醉酒驾车=吊销驾照+追究刑事责任（危险驾驶罪）+5年内不得重新取得驾照。",tip:"口诀：20-80=饮酒（扣证6月+记12分）；≥80=醉酒（吊销+坐牢+5年不能考）。开车不喝酒，喝酒不开车。"},
{id:1326,cat:"accident",type:"judgment",q:"交通事故造成人员死亡的，肇事驾驶人自动承担刑事责任。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"交通事故致人死亡≠自动构成犯罪。只有当驾驶人违反了交通运输管理法规（如酒驾、超速、闯红灯等）并因此导致死亡时，才构成交通肇事罪。如果驾驶人完全合规驾驶、事故由不可抗力或死者故意行为（如自杀）造成，则不构成犯罪。",tip:"口诀：撞死人≠一定坐牢。你违规+致人死亡=交通肇事罪。你合规+意外=不构成犯罪。"},
{id:1327,cat:"accident",type:"choice",q:"以下关于交通事故现场保护的说法，哪项是正确的？",opts:["可以移动车辆","应当立即标记停车位置、伤亡人员位置，保护现场痕迹和遗留物品，不得擅自移动车辆和物品（因抢救伤员需移动的应标明位置）","现场保护不重要","只需拍照即可"],ans:1,exp:"现场保护=标记车辆位置+伤员倒卧位置+散落物位置→保护刹车痕迹和碰撞痕迹→避免破坏现场（防止过往车辆碾压证据）。因抢救伤员必须移动车辆/人员的，应在现场用粉笔/石子等标明原位置。",tip:"口诀：保护现场=标记位置+保护痕迹+不随便动。救人移动必须留标记。"},
{id:1328,cat:"accident",type:"judgment",q:"一方当事人故意造成交通事故的，他方不承担赔偿责任。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"故意造成事故（如碰瓷、自杀式冲撞）=对方无责。故意行为造成的损失不属于交强险赔偿范围，保险公司不赔，由故意行为人自行承担全部损失。",tip:"口诀：故意找死=对方不赔。碰瓷的别想讹人——故意行为保险公司也不赔。"},
{id:1329,cat:"laws",type:"choice",q:"初次申领机动车驾驶证的，可以申请的准驾车型不包括以下哪项？",opts:["小型汽车（C1）","小型自动挡汽车（C2）","大型客车（A1）","普通三轮摩托车（D）"],ans:2,exp:"初次申领=不能直接申请A1（大型客车）、A2（牵引车）、B1（中型客车）。这些车型需通过增驾取得——如C1满一定年限后增驾B1再增驾A1（逐级增驾）。初次可申请：C1、C2、C3、C4、C5（残疾人专用）、D、E、F等。",tip:"口诀：初学者不能拿A1A2B1。大客/半挂/中客=要逐级增驾。从小车开始升级。"},
{id:1330,cat:"laws",type:"judgment",q:"驾驶人年龄在70周岁以上的，应当每年进行一次身体检查，并提交身体条件证明。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"70岁以上驾驶人=每年体检+每年提交身体条件证明（通过交管12123或车管所窗口）。未按时提交的，驾驶证可能被公告停止使用。此外，年龄达70岁自动降级C1/C2（无法继续持有A/B类驾照）。",tip:"口诀：70岁=每年体检+每年交证明。不交证明=驾照停用。到了70自动降级小车。"},
{id:1331,cat:"laws",type:"choice",q:"机动车驾驶证有效期分为多少年？",opts:["3年、6年、10年","6年、10年、长期","5年、10年、15年","3年、5年、长期"],ans:1,exp:"驾驶证有效期=初次6年→换证时记分周期内无满分记录换发10年→再换证时仍无满分记录换发长期。有满分记录=仍换发6年有效期。简约而科学的激励机制——安全驾驶奖励更长有效期。",tip:"口诀：6年→10年→长期。满分记录=打回6年重来。开得好=永久有效。"},
{id:1332,cat:"laws",type:"judgment",q:"机动车驾驶人可以委托代理人代理换证、补证等业务。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"换证/补证可委托代理人办理，需提交：①代理人身份证明→②驾驶人亲笔签名的委托书→③驾驶人身份证明→④体检证明（换证需要）。部分业务已可通过交管12123APP在线办理，无需代理人。",tip:"口诀：换证补证能找人代办（带委托书+证件）。现在更方便=APP在线办。足不出户搞定驾照。"},
{id:1333,cat:"laws",type:"choice",q:"以下哪种情况驾驶证会被吊销？",opts:["一个周期记满12分","醉驾","未按规定系安全带","超速20%以下"],ans:1,exp:"记满12分=扣留驾照+参加学习考试（不是吊销，考过就恢复）。醉驾=吊销驾照+刑事责任+5年禁考（营运车10年禁考+终身禁驾营运车）。吊销是永久性的，只能重新申请（且需等待禁考期满）。",tip:"口诀：12分=扣留（暂时的，考过就还）；醉驾=吊销（永久的，等几年再考）。扣留≠吊销。"},
{id:1334,cat:"laws",type:"judgment",q:"机动车在抵押期间，抵押人（车主）仍可正常使用车辆，但未经抵押权人（银行等）同意不得办理转移登记。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"抵押期间=车主正常使用（车辆不转移占有）。但办理转移登记（过户给他人）=需抵押权人同意（先解除抵押或银行出具同意函）。银行贷款买的车=绿本（登记证书）押在银行，还清贷款后办理解除抵押才能拿到绿本。",tip:"口诀：贷款车=你开着但户不好过。想过户先还清贷款解抵押。"},
{id:1335,cat:"safe",type:"choice",q:"关于「防御性驾驶」的核心理念，以下哪项表述最准确？",opts:["只管自己的驾驶行为","主动预判潜在危险、保持安全余量、提前采取措施避免事故，不依赖他人遵守规则","开快车避免危险","完全信任其他驾驶人"],ans:1,exp:"防御性驾驶=不假设他人会遵守规则。核心理念：①预判风险（看到前方皮球滚出→预判后面可能有小孩冲出来）→②保持安全余量（车距、速度、视野）→③提前应对（看见前车刹车灯亮就松油门，不等看到完全停止再反应）。",tip:"口诀：防御性驾驶=把路上所有人都当新手。预判+留余量+提前动。别等看到危险再反应。"},
{id:1336,cat:"safe",type:"judgment",q:"驾驶人在服用感冒药（含抗组胺成分）后，如果感觉没有困意就可以开车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"含抗组胺成分的感冒药（如扑尔敏、苯海拉明）=嗜睡+反应变慢。即使主观感觉没有困意，药物对反应速度和判断力的削弱是客观存在的。服用明确标注服用后不宜驾驶车辆的药物=不应开车。许多「药驾」事故的当事人都是觉得我没困。",tip:"口诀：吃了感冒药=别开车（不管困不困）。药驾反应=慢+迟钝，你自己感觉不到。看药物说明书上的驾驶警告。"},
{id:1337,cat:"safe",type:"choice",q:"夜间在无照明的道路上行驶，车速为60km/h时，近光灯的有效照射距离约为多少？以此速度行驶是否存在危险？",opts:["约150米，安全","约30-50米，而60km/h的制动距离约为30-40米——意味着当你看到障碍物时刚好刹停在它面前，几乎无安全余量，非常危险","约100米，很安全","约200米，没有任何风险"],ans:1,exp:"近光灯有效照射距离=约30-50米（不同车型有差异）。60km/h=每秒约17米+反应时间1-1.5秒（约17-25米）+制动距离约20-30米=总停车距离约37-55米。近光灯照射距离≈停车距离——意味着黑暗中看到障碍物时，刚好勉强刹停，几乎没有安全余量。夜间应降低车速（建议不超过40-50km/h）。",tip:"口诀：近光灯只能照30-50米远，60码停车也差不多30-40米——看见就刚好刹住，一丝富余都没有。夜里开慢点。"},
{id:1338,cat:"safe",type:"judgment",q:"在道路上遇到大型客车停靠上下乘客时，后方来车应减速慢行并注意避让下车乘客。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"大客车上下客=乘客可能突然从车前方横穿马路（视线被大车遮挡）。后方来车应减速慢行+观察大车前方是否有行人探出+随时准备刹车。同理——公交车站附近是行人事故高发区。",tip:"口诀：大客车停靠=有人可能从车前冒出来。减速+盯住车头两侧+随时刹车。鬼探头高发地。"},
{id:1339,cat:"operation",type:"choice",q:"驾驶自动挡汽车在坡道上停车时，正确的操作顺序是什么？",opts:["直接挂P挡熄火","踩刹车→挂N挡→拉手刹→松刹车让手刹吃住力→再挂P挡→熄火","先熄火再拉手刹","挂D挡拉手刹"],ans:1,exp:"坡道停车正确顺序=踩刹车→N挡→拉手刹→松刹车（确认手刹吃住力、车不溜动）→再挂P挡→熄火。如果是先挂P挡再拉手刹，P挡的驻车棘爪会承受车辆重量，再次启动时P挡很难从驻车齿中脱出，会听到嘭的一声响——对变速箱有损伤。",tip:"口诀：坡道停车=先手刹紧→松脚刹确认不溜→再挂P挡。别让P挡牙承受车重。"},
{id:1340,cat:"operation",type:"judgment",q:"ABS（防抱死制动系统）在紧急制动时能显著缩短制动距离，因此在湿滑路面上应更加放心地高速行驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"ABS的作用=防止制动时车轮抱死（保持转向能力），不是为了缩短制动距离。在松软路面（碎石、雪地）上ABS甚至会增加制动距离。ABS是安全辅助≠可以更冒险地开车。湿滑路面无论有无ABS都应大幅降速。",tip:"口诀：ABS=防抱死≠缩短刹车距离。它的最大本事=急刹时还能打方向。别因为有ABS就开得更快。"},
{id:1341,cat:"operation",type:"choice",q:"仪表盘上发动机故障灯（黄色发动机图标，Check Engine）常亮时，以下哪种做法正确？",opts:["不管它继续开","立即熄火等待","应尽快到维修站检查，如果故障灯闪烁（非长亮）则表明存在严重失火可能损坏催化转化器，应立刻靠边停车","自行断电重置"],ans:2,exp:"发动机故障灯=长亮通常可以继续行驶但应尽快检修（可能是排放系统问题等）。如果闪烁=严重故障（通常为发动机失火，未燃汽油进入排气管会烧毁催化转化器），应立即安全停车、熄火、叫拖车。不能忽视——它真的在告诉你发动机出问题了。",tip:"口诀：发动机黄灯长亮=尽快修；黄灯闪烁=立即停车叫拖车！闪烁=催化器要烧了。"},
{id:1342,cat:"operation",type:"judgment",q:"自动挡车辆在行驶中可以挂入P挡（驻车挡）来辅助减速。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"行驶中挂P挡=变速箱严重损坏（P挡的驻车棘爪会撞击旋转的齿轮→棘爪断裂→变速箱内部碎片四散→变速箱报废+车辆瞬间锁死可能失控）。P挡只能在完全静止时使用。行驶中需要发动机制动=用L挡或S挡降挡。",tip:"口诀：P挡=静止专用。行驶中挂P=变速箱爆炸。减速用L挡或轻踩刹车，别碰P。"},
{id:1343,cat:"operation",type:"choice",q:"车辆涉水后，制动性能会暂时下降，正确的做法是什么？",opts:["不用管它","在确保安全的前提下，低速行驶并轻踩刹车数次，利用摩擦热量烘干制动器中的水分","加速行驶让风吹干","用力拉手刹"],ans:1,exp:"涉水后制动器进水=制动力矩下降（水膜使刹车片与制动盘之间摩擦系数降低）。正确做法=低速行驶+轻踩刹车数次（间歇轻刹），摩擦产生的热量将水分蒸发，恢复制动效能。涉水后恢复制动力的这段路程中应保持与大车的距离。",tip:"口诀：涉水后=低速+轻刹数次→热量烘干刹车盘。像甩干机一样把水甩出来。"},
{id:1344,cat:"laws",type:"choice",q:"以下哪项不属于交通肇事罪的构成要件？",opts:["违反交通运输管理法规","发生重大事故致人重伤/死亡或重大财产损失","驾驶人主观上具有伤害他人的故意","行为与结果之间存在因果关系"],ans:2,exp:"交通肇事罪=过失犯罪（不是故意犯罪）。构成要件：①违规→②重大事故（1死或3重伤以上或无力赔偿超30万元）→③行为与结果有因果关系→④主观上是过失（疏忽大意或过于自信）。如果是故意伤害他人或以危险方法危害公共安全=其他更重的罪名。",tip:"口诀：交通肇事=过失不是故意。违规+出大事+因果关系=交通肇事罪。故意的=危害公共安全罪（更重）。"},
{id:1345,cat:"safe",type:"choice",q:"如果发现前方车辆的货物有掉落风险（如篷布松开、货物倾斜），正确的做法是？",opts:["紧跟其后","加速超车","减速保持安全距离，同时用闪灯或鸣喇叭提醒前方车辆","不管它"],ans:2,exp:"前车货物可能掉落=立即减速拉大安全距离（货物可能在下一秒就掉下来）+闪灯/鸣喇叭提醒前车+在安全条件下变道避开该车后方区域。隧道和高速公路上货物散落造成的二次事故非常常见。",tip:"口诀：前车货要掉=远离+提醒。别紧跟——货掉下来第一个砸你。"},
{id:1346,cat:"supplementary",type:"judgment",q:"驾考科目一考试时间为45分钟，共100道题，90分及格。每题1分，答错不扣分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"科一=100题（判断+单选）+45分钟+90分（对90道）及格。每题1分。包括道路交通安全法律法规、交通信号、安全行车知识、机动车驾驶操作知识等。成绩当场显示。",tip:"口诀：科一=100题/45分钟/90分过。每题1分，错11道以上=挂。"},
{id:1347,cat:"supplementary",type:"choice",q:"在长途驾驶前，除了检查车辆状况外，以下哪项准备是最重要的？",opts:["带足够零食","规划路线（包括休息点和加油站/充电站）、保证充足睡眠、检查备胎和应急工具","只需加满油","带上娱乐设备"],ans:1,exp:"长途驾驶=睡眠充足（疲劳驾驶极其危险）+路线规划（包括休息点间隔不超过2小时/200公里）+检查车辆（轮胎+灯光+油液+备胎+应急工具三角牌灭火器等）。2026年新规加重了疲劳驾驶处罚——连续驾驶超4小时不停车休息=记9分（营运车）。",tip:"口诀：长途前三件事=睡好+查车+规划休息点。每2小时/200公里至少休息一次。"},
{id:1348,cat:"highway",type:"choice",q:"高速公路交通流量管理的核心目标是什么？",opts:["最大化车流量","保障交通安全、有序、高效","限制车辆通行数量","只服务长途车辆"],ans:1,exp:"高速公路交通流量管理的核心目标是保障安全、有序、高效通行。通过匝道控制（匝道信号灯）、可变限速、车道管理（开放/关闭车道）、信息发布等手段实现。",tip:"口诀：流量管理=安全+有序+高效。不是一味多放车，而是让车流顺畅。"},
{id:1349,cat:"highway",type:"choice",q:"高速公路可变限速标志（VSL, Variable Speed Limit）通常根据什么动态调整限速值？",opts:["驾驶人的喜好","实时交通流量、天气状况、事故发生情况等综合因素","固定时间表","交警个人判断"],ans:1,exp:"可变限速系统根据实时检测的交通流密度、能见度、路面湿滑程度、前方事故等综合信息自动或人工调整限速，并通过电子显示屏发布当前限速值，驾驶人必须遵守。",tip:"口诀：可变限速像天气预报——实时根据路况、天气、事故变。显示屏上多少就开多少。"},
{id:1350,cat:"highway",type:"judgment",q:"高速公路上的可变限速标志显示的限速值低于常规限速时，驾驶人可以不予理会，按习惯速度行驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"可变限速标志显示的限速值具有法律约束力，驾驶人必须遵守。不遵守可变限速=超速行驶，依据实际超速比例处罚。可变限速通常因恶劣天气、事故、施工等安全原因临时实施。",tip:"口诀：电子屏上显示的限速=法律效力。变低了就减速，别当建议。"},
{id:1351,cat:"highway",type:"choice",q:"在高速公路上发生轻微事故且车辆可以移动时，正确的处理流程是？",opts:["留在现场等待交警，不动车","双方理论清楚责任再挪车","开启双闪→拍照取证→将车移至应急车道或最近出口/服务区→再协商或报警","直接驶离现场"],ans:2,exp:"高速公路轻微事故（人未伤亡、车可移动）=「车靠边、人撤离、即报警」九字诀。拍照固定证据后立即将车移至不妨碍交通处，严禁在行车道上争论逗留。",tip:"口诀：高速事故九字诀——车靠边，人撤离，即报警。先移车再商量，别在行车道当靶子。"},
{id:1352,cat:"highway",type:"judgment",q:"高速公路发生事故后，驾驶人设置好警告标志就可以在行车道内等待救援。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"设置警告标志后，所有人员必须撤离到护栏外侧的安全区域。车道是极其危险的，后方来车可能来不及避让。二次事故是高速公路上最致命的威胁。",tip:"口诀：放完警示牌≠安全，人要撤到护栏外面去。车被撞了还可以修，人没了就真没了。"},
{id:1353,cat:"highway",type:"choice",q:"高速公路施工区（养护作业区）通常由哪几个区段组成？",opts:["只有一个施工区","警告区→过渡区→缓冲区→施工作业区→终止区","入口区和出口区","作业区和行车区"],ans:1,exp:"高速施工区标准划分为5段：警告区（提前警示）、过渡区（引导车辆变道）、缓冲区（防护施工区）、施工作业区（实际施工位置）、终止区（恢复正常通行）。每个区段有特定标志和要求。",tip:"口诀：施工区五段——警告→过渡→缓冲→作业→终止。见到施工标志逐段降速。"},
{id:1354,cat:"highway",type:"judgment",q:"经过高速公路施工区域时，由于车道变窄，可以加速抢行通过以减少拥堵时间。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"经过施工区应减速慢行、依次交替通行（「拉链式」通行，两车道汇入一处时各车道轮流交替）、严禁抢行。施工区限速通常降低至60-80km/h，超速将被重罚。施工区是事故高发区。",tip:"口诀：施工区减速慢行+交替通行（像拉拉链一样，左右各一辆交替通过）。抢行=危险+违章。"},
{id:1355,cat:"highway",type:"choice",q:"高速公路施工区常见的临时隔离设施不包括以下哪项？",opts:["水马（注水塑料护栏）","交通锥（锥形路标）","临时混凝土护栏","永久性波形护栏"],ans:3,exp:"永久性波形护栏是常规安装的固定护栏，不属于「临时」隔离设施。临时设施包括水马（注水增加重量，碰撞时可吸收冲击力）、交通锥（导流隔离）、临时防撞桶、移动式护栏等。",tip:"口诀：永久护栏≠临时设施。施工区用的都是可移动的——水马、锥桶、临时的。"},
{id:1356,cat:"highway",type:"judgment",q:"高速公路施工区夜间必须设置明显的施工警告灯（黄闪灯或旋转警示灯）。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路施工区夜间须设置施工警告灯。黄闪灯警告驾驶人前方有施工，旋转/频闪警示灯用于施工车辆和关键位置提醒。夜间施工安全标志还应具有反光效果。",tip:"口诀：施工区夜间必亮灯——黄闪灯提醒+反光标线引导。晚上施工=灯火通明。"},
{id:1357,cat:"highway",type:"choice",q:"高速公路「匝道信号控制」（Ramp Metering，匝道入口红绿灯）的作用是什么？",opts:["限制所有车辆进入高速","通过控制匝道车辆进入节奏，调节主线车流密度，防止拥堵和事故","给收费站计时","装饰作用"],ans:1,exp:"匝道信号灯（通常设在入口匝道）每次放行1-2辆车，间隔数秒，以控制汇入主线的车辆节奏，避免大量车辆同时涌入导致主线拥堵或追尾。绿红交替的圆灯信号，驾驶人必须遵守。",tip:"口诀：匝道口的红绿灯=控制上高速的节奏。一次过一两辆，不让扎堆涌进主线。"},
{id:1358,cat:"highway",type:"judgment",q:"匝道信号灯为红灯时，车辆可以无视信号直接驶入高速公路主线。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"匝道信号灯具有法定效力，红灯必须停车等待，绿灯方可通行。闯匝道红灯等同于闯红灯，记6分。",tip:"口诀：匝道口红灯=必须停车等。闯匝道红灯=6分，和路口闯红灯一样。"},
{id:1359,cat:"highway",type:"choice",q:"高速公路上的「紧急避险车道」（紧急停车带/避险车道）主要供什么情况使用？",opts:["正常超车","刹车失灵的车辆紧急避险","临时休息","掉头"],ans:1,exp:"紧急避险车道（多设于长下坡路段，有沙砾或碎石减速床）专供制动失效（刹车失灵）的车辆冲入减速停稳，避免失控冲下悬崖或撞向其他车辆。正常车辆严禁占用或驶入。",tip:"口诀：避险车道=刹车失灵专用道。路面是松软沙石（增大阻力减速），不是休息区。"},
{id:1360,cat:"highway",type:"judgment",q:"普通车辆可以在紧急避险车道内停车休息或者掉头重新进入高速。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"紧急避险车道是生命通道，仅供制动失效车辆紧急使用。正常车辆占用将导致真正需要的车辆无处避险，后果不堪设想。不得停车、不得掉头。",tip:"口诀：避险车道≠停车区/掉头区。你占了它，真正刹车失灵的就没命了。"},
{id:1361,cat:"highway",type:"choice",q:"高速公路上的「侧风（横风）警示标志」（风筒/风向袋标志）通常在什么位置设置？",opts:["隧道入口","桥梁、山谷、沿海等高架暴露路段","服务区","收费站"],ans:1,exp:"侧风警示标志设置在经常出现强横风的桥梁、高架路段、山口垭口、沿海公路等。同时可能设置风向袋（风筒）——红色/橙色锥形布袋飘动方向和程度直观显示风速和风向。侧风路段应握紧方向盘、降低车速。",tip:"口诀：大风路段看标志+风筒（红橙色布袋子）。风筒飘得越平，风速越大，该减速了。"},
{id:1362,cat:"highway",type:"judgment",q:"看到高速公路上风向袋（风筒）水平飘动时，大型客车和厢式货车尤其需注意侧风横推风险。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"大型客车、厢式货车、半挂车等侧面受风面积大，强侧风可能导致车辆横向偏移甚至侧翻。风筒呈水平状态表示风速≥10m/s（约36km/h），此时大车尤应大幅减速。",tip:"口诀：风筒水平飘=大风！大车（客车/货车/挂车）侧面像帆，最怕横风。"},
{id:1363,cat:"highway",type:"choice",q:"在高速公路上连续驾驶2小时后，为防止疲劳驾驶，最佳的做法是什么？",opts:["喝功能饮料继续开","打开车窗吹风","驶入服务区休息至少15-20分钟，做伸展活动","加速尽早到达目的地"],ans:2,exp:"防疲劳最有效的方法=停车休息+活动身体。功能饮料和开窗吹风只能短暂缓解困意信号，不能消除疲劳（中枢神经系统疲劳不受这些因素根本影响）。法律规定连续驾驶4小时必须停车休息≥20分钟，实际安全建议每2小时休息一次。",tip:"口诀：防困最管用的只有休息。喝红牛/开窗=治标不治本。2小时一歇，4小时必停20分钟。"},
{id:1364,cat:"highway",type:"judgment",q:"在高速公路上驾驶时，如果感到困倦但距离服务区还有一段距离，可以在路肩上临时停车闭眼休息几分钟。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"在路肩（应急车道）停车休息属于违法停车（非紧急情况占用应急车道记9分）。困倦时应驶入最近服务区，如实在坚持不到服务区，应在最近出口驶离高速，在安全地点停车休息。",tip:"口诀：困了不能停应急道睡觉（9分）。坚持到服务区，不行就下高速找地方休。"},
{id:1365,cat:"highway",type:"choice",q:"关于高速公路上车队（多辆车结伴行驶）的安全行驶，以下哪项说法正确？",opts:["应紧跟前车保持最短距离以免掉队","各车之间应保持安全距离，使用对讲机或导航位置共享保持联系，严禁为了不掉队而缩短安全距离","应并排占据所有车道","应频繁变道保持车队连接"],ans:1,exp:"结伴行驶（自驾游车队等）每车仍需保持法定安全距离（>100km/h时≥100米），不可为「不掉队」而跟车过近。使用通讯设备协调——约定在下一服务区或出口汇合，而非在行车道上同步。",tip:"口诀：结伴出行≠不守车距。每车保持100米安全距，掉队了就服务区汇合。"},
{id:1366,cat:"highway",type:"judgment",q:"在高速公路上结伴行驶时，为保持一致，可以在行车道内停车等候掉队车辆。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路上任何情况下（除车辆故障等紧急情况外）不得在行车道内停车。车队掉队应通过手机/对讲机约定在下一服务区或出口汇合。停车等候极度危险且违法。",tip:"口诀：掉队了服务区见，别在车道内停车等。高速停车=害人害己。"},
{id:1367,cat:"highway",type:"choice",q:"驾驶牵引房车/拖挂式旅居车（拖挂房车）在高速公路上行驶，以下哪项说法正确？",opts:["可以任意变道超车","最高限速100km/h，应保持安全距离，避免频繁变道","与普通小汽车限速完全相同","可以在最左侧快车道长时间行驶"],ans:1,exp:"小型载客汽车牵引旅居挂车/总质量700kg以上挂车=最高限速100km/h（比普通小车的120km/h低）。挂车会增加车辆总长和转弯半径，变道更危险，应尽量减少变道。牵引挂车的组合属于「小型载客汽车列车」。",tip:"口诀：拖房车上高速=限速100码（不是120），少变道。后面拖着东西，车更长更不好控制。"},
{id:1368,cat:"highway",type:"judgment",q:"C6驾驶证（轻型牵引挂车驾驶证）允许持有人在高速公路上牵引总质量不超过4500kg的旅居挂车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"C6驾驶证（2022年新增准驾车型）允许驾驶总质量小于4500kg的轻型牵引挂车（汽车列车），适用于牵引房车/拖挂式旅居车。C6需通过增驾考试获得（C1/C2持有1年以上可增驾C6）。",tip:"口诀：拖房车要C6证——总质量<4.5吨的挂车。C1增驾C6，免考科一科四。"},
{id:1369,cat:"highway",type:"choice",q:"摩托车在高速公路上的限速和通行规定是什么？",opts:["与汽车完全一样","最高限速80km/h，不得载人，须在最右侧车道行驶，需佩戴安全头盔","最高限速120km/h","可以在任意车道行驶"],ans:1,exp:"摩托车在高速公路上：最高限速80km/h、最低60km/h、须在最右侧车道行驶（不得进入最左侧快车道）、不得载人（两轮摩托车）、驾驶人及乘坐人均须佩戴头盔。注意：部分省份/路段可能禁止摩托车上特定高速，需关注入口禁令标志。",tip:"口诀：高速摩托=限80码+最右道+不载人+戴头盔。摩托在高速上是最慢的，别挡快车道。"},
{id:1370,cat:"highway",type:"judgment",q:"两轮摩托车在高速公路上行驶时可以搭载一名乘客，但两人都必须佩戴安全头盔。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"根据《道路交通安全法实施条例》，两轮摩托车在高速公路上不得载人。摩托车高速稳定性较差，载人进一步增加风险。被查处将面临罚款和记分。",tip:"口诀：摩托上高速=单人单车，不许带人。两个人都戴头盔也不行。"},
{id:1371,cat:"highway",type:"choice",q:"在高速公路上行驶时遇到地震（如桥梁晃动、路面开裂等迹象），应如何应对？",opts:["加速驶离","立即急刹车停在原地","减速靠近路侧停车，远离桥梁、隧道、高架等结构物，地震停止后尽快驶离高速","在原车道匀速行驶"],ans:2,exp:"地震时高速公路可能的结构风险：桥梁位移、隧道坍塌、高架断裂。正确做法：减速靠边停车（勿停在桥梁/隧道/高架上）、避开高空标志牌和路灯、地震停止后根据官方指引驶离（可能需从最近出口或服务区离开）。",tip:"口诀：地震高速=靠边停→远离桥隧高架→震后按指引撤离。别停桥上，别钻隧道。"},
{id:1372,cat:"highway",type:"judgment",q:"高速公路上遇到前方洪水淹没路面时，如果水深还未没过排气管，可以低速涉水通过。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路积水有两大危险：深度不明（路面可能已被洪水掏空或冲毁）；水流冲击力（15cm深的流水即可冲走小型车）。遇到积水应停车判断——切勿盲目涉水，应立即报警并向安全地带转移。",tip:"口诀：高速积水不涉水——看不清深度+水流冲力。报警并转移到安全地带。"},
{id:1373,cat:"highway",type:"choice",q:"高速公路夜间施工区（养护施工）与日间施工的主要区别是什么？",opts:["没有区别","夜间须增设施工警告灯、反光锥桶、LED导向标志，施工人员须穿着反光背心，光照充足的施工照明","夜间不能施工","夜间施工不需要任何额外警示"],ans:1,exp:"夜间施工需加强视觉警示：施工警告灯（黄闪）、高反光度锥桶和导向标志（LED箭头）、施工区域提供充足照明（不影响驾驶人眩光）、施工人员必须穿高反光背心。限速通常进一步降低。",tip:"口诀：夜间施工=灯光秀——闪灯+反光+LED箭头+照明。晚上看不见，全靠警示。"},
{id:1374,cat:"highway",type:"judgment",q:"高速公路夜间施工区限速与日间相同。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"夜间施工区限速通常低于日间（例如日间80km/h，夜间60km/h），因为夜间能见度更低、驾驶人反应时间更长。具体以施工区限速标志为准。",tip:"口诀：夜间施工限速更严——比白天更低。视距差了，速度降更多。"},
{id:1375,cat:"highway",type:"choice",q:"智慧高速公路的「动态车道管理」（Dynamic Lane Management）是指什么？",opts:["车道随时可以随意变换方向","根据实时交通流量动态开放/关闭车道（如硬路肩临时开放为行车道、潮汐车道方向变更、车道上方红×/绿箭指示）","把所有车道都变成ETC车道","无人驾驶专用车道"],ans:1,exp:"动态车道管理通过车道上方可变标志（红×=该车道关闭，绿箭=该车道开放通行）和可变信息板，根据拥堵、事故、施工等情况实时调整各车道通行状态。硬路肩在特定条件下可临时开放行驶（需有指示标志）。",tip:"口诀：红叉=此道关（不能走），绿箭=此道通。车道上方的灯会变，跟着走。"},
{id:1376,cat:"highway",type:"judgment",q:"高速公路上方有红叉（×）标志的车道，如果前方没有车阻挡，驾驶人可以驶入通行。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"车道上方红×=该车道已关闭（禁止通行），无论前方有无车辆均不得驶入。可能因前方事故、施工、障碍物等原因关闭。驶入关闭车道属于严重违章。",tip:"口诀：红叉=禁止入内！不是\"没车就进去\"。像红灯一样，管你前面有没有车。"},
{id:1377,cat:"highway",type:"choice",q:"在高速公路服务区（休息区）最长的连续停留时间一般限制为多久？",opts:["没有限制","通常不超过24小时（具体视各路段规定），超时可能被收取超时费","最多2小时","最多48小时"],ans:1,exp:"高速公路服务区主要功能是短暂休息，多数路段规定停留不超过24小时（部分路段更短）。超时停留可能被收取超时费用（基于ETC出入口时间计算的超时费），旨在防止利用服务区逃费或长时间占用公共资源。",tip:"口诀：服务区别过夜——一般不超过24小时。长时间不走可能被收超时费。"},
{id:1378,cat:"highway",type:"judgment",q:"在高速公路服务区可以长期停放车辆（如连续停放数日），没有任何限制。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"服务区非停车场，不得长期占用停车位。长期停放不仅可能被收取超时费，还可能被清拖。长时间不使用车辆应停放在普通停车场。",tip:"口诀：服务区不是免费停车库。停几天=可能被清拖。"},
{id:1379,cat:"highway",type:"choice",q:"运输危险化学品（易燃易爆、有毒有害等）的车辆在高速公路上行驶时，以下哪项要求正确？",opts:["与普通车辆一样随意行驶","须经公安机关批准，按指定时间、路线、速度行驶，悬挂警示标志，配备押运人员","可以进入隧道行驶","不需要额外限制"],ans:1,exp:"危险品运输车须取得「剧毒/危化品公路运输通行证」→按审批的时间（通常避开白天高峰和节假日）、路线（避开人口密集区、特长隧道、饮用水源地保护区等敏感路段）、速度行驶→悬挂「危险品」警示标志→需配备取得从业资格的押运员。",tip:"口诀：危化品车上高速=先审批→限时间限路线限速度→挂标志+配押运员。规矩多了去了。"},
{id:1380,cat:"highway",type:"judgment",q:"运输危险化学品的车辆在高速公路上可以不受时间限制，随时通行。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"危化品运输车通常有通行时段限制：不得在法定节假日、重大活动期间通行；部分省份规定0:00-6:00禁行；部分隧道/桥梁全天禁行危化品车。具体以通行证标注和路段标志为准。",tip:"口诀：危化品车有时段禁行——节假日禁、半夜禁、部分隧道桥禁。不是想走就能走。"},
{id:1381,cat:"highway",type:"choice",q:"运输不可解体超限物品（如巨型风力发电机叶片、预制桥梁梁段等）的车辆进入高速公路需满足什么条件？",opts:["不需要特殊许可","依法办理超限运输许可，按指定时间/路线/速度行驶，配备必要的警示和护送措施","仅限夜间行驶","可以在任何时间任何路段行驶"],ans:1,exp:"超限运输车辆须取得《超限运输车辆通行证》→按审批的时间、路线、速度行驶→车辆悬挂明显超限标志→根据货物宽度/长度可能需要配备前导车和押运车护送。超高、超宽、超长均需审批。",tip:"口诀：拉大件上高速=先办超限证→按指定路线走→前后可能有护送车。大件不是想拉就拉。"},
{id:1382,cat:"highway",type:"judgment",q:"高速公路因恶劣天气、重大事故、地质灾害等原因需要全线或部分路段封闭时，由公安机关交通管理部门（高速交警）决定并实施。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路封闭由公安机关交通管理部门（高速交警）根据实际情况决定并实施。运营管理单位配合设置封闭标志和绕行引导。驾驶人应服从指挥，从指定出口驶离或进入服务区等待。",tip:"口诀：高速封路=交警决定。听指挥，按指引绕行或等待。不要试图硬闯。"},
{id:1383,cat:"highway",type:"choice",q:"高速公路封闭期间，驾驶人违法闯入封闭路段的，将面临什么后果？",opts:["没有处罚","罚款200-2000元，并可能被记分和拘留","仅口头警告","不需要承担法律责任"],ans:1,exp:"违反封路禁令标志、不听劝阻、强行进入封闭路段=违反禁令标志+不服从交警指挥+危害公共安全。记分+罚款，造成事故的承担全部法律责任。",tip:"口诀：封路了就绕行，别硬闯。闯封路段=罚款+记分，出了事全责。"},
{id:1384,cat:"highway",type:"judgment",q:"高速公路中央隔离带（中央分隔带）的「紧急开口/应急掉头口」（黄色活动护栏连接处）可供普通车辆在需要时掉头使用。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"中央隔离带活动护栏开口（紧急掉头口/应急救援通道）仅供警车、消防、救护、工程救险等特种车辆在紧急情况下使用，以及事故处置时临时疏导交通。普通车辆严禁使用（穿越中央分隔带掉头=一次记12分）。",tip:"口诀：高速中间的活动护栏开口=特种车辆专用（紧急救援用）。你开过去掉头=12分全扣。"},
{id:1385,cat:"highway",type:"choice",q:"在高速公路上遇到因事故导致的前方严重拥堵，后方有特种车辆（救护车/消防车）鸣笛需要通行时，正确的做法是？",opts:["保持不动","向两侧（左车向左、右车向右）让出中间通道（形成「应急通道/生命走廊」）","加速驶离","倒车让行"],ans:1,exp:"应学习德国的「Rettungsgasse/生命通道」做法——拥堵时左车道车辆向左靠，右车道车辆向右靠，在两车道之间形成一条应急通道供救援车辆通行。这不只是文明，是法律义务。不让行特种车辆=记3分。",tip:"口诀：堵车时听到警笛→左车靠左，右车靠右，中间给救援车让路。生命通道=两车之间开辟通道。"},
{id:1386,cat:"highway",type:"judgment",q:"在高速公路上遇拥堵排队时，驾驶人可以将车辆驶入应急车道以更快通过拥堵路段。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"应急车道任何时候都不应用于日常通行——即使拥堵时也禁止占用。拥堵时应急车道是救援车辆唯一能到达事故现场的通道，占用应急车道=堵塞生命通道。任何原因占用应急车道记9分。",tip:"口诀：堵车时应急道更不能占——那是救援车唯一的救命路。你堵几分钟，可能有人救不回来。"},
{id:1387,cat:"highway",type:"choice",q:"在高速公路上遇到前车货物掉落、车辆零件脱落等抛洒物时，以下做法正确的是？",opts:["急打方向躲避","紧急制动停车","握紧方向盘，减速避让（不猛打方向），通过后如条件允许拨打12122报告","无视碾压过去"],ans:2,exp:"高速遇到路面抛洒物→紧握方向盘（最重要！急打方向可能翻车/撞护栏）→松油门减速→在确保安全前提下小幅度避让→通过后拨打12122（高速公路报警救援电话）报告位置和抛洒物情况，以便清理。",tip:"口诀：路面异物三字诀——握稳、慢减、小避。别猛打方向（会翻）！过后打12122报告。"},
{id:1388,cat:"highway",type:"judgment",q:"在高速公路上看到前方有其他车辆掉落的货物，应当立即停车下去清理或捡拾。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路严禁行人进入，驾驶人不得在高速公路上步行、停车捡拾物品。拨打12122由专业清障人员处理。随意停车+下车=极度危险。",tip:"口诀：高速上东西掉了别下车捡。命比货物贵。打12122让专业的人来。"},
{id:1389,cat:"highway",type:"choice",q:"「高速公路的加速车道和减速车道长度通常在什么范围？」——以下说法正确的是？",opts:["加速车道约50米，减速车道约30米","加速车道约150-400米（按设计速度不同），减速车道约100-200米","加速和减速车道长度相同","没有明确标准"],ans:1,exp:"加速车道（汇入主线前的提速区）长度按高速公路设计速度（80-120km/h）不同而不同——通常150-400米，给车辆足够的距离提速至60km/h以上并安全汇入。减速车道长度较短（约100-200米）——但仍需足够的距离从主线速度减速至匝道限速。",tip:"口诀：加速道比减速道长（提速需要更远距离）。加速道150-400米，减速道100-200米。"},
{id:1390,cat:"weather",type:"choice",q:"在极端恶劣天气（如特大暴雨、强台风、暴雪）下，驾驶人最重要的决策是什么？",opts:["开启远光灯继续行驶","降低速度，评估风险，必要时主动选择安全地点停车等待天气好转","紧跟大车行驶","加速尽早离开恶劣天气区域"],ans:1,exp:"极端天气下最重要的安全决策=评估是否应该继续行驶。当能见度极低、路面严重积水/结冰、风力达到危险级别（如台风预警期间）时，主动停车等待比冒险行驶明智得多。「晚到总比不到好」。",tip:"口诀：极端天气第一问——该不该继续开？敢停车等才是最勇敢的决定。晚到好过不到。"},
{id:1391,cat:"weather",type:"judgment",q:"遇到台风预警（10级以上大风），在高速公路上行驶的小型汽车不受影响，可以正常行驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"10级以上大风足以吹翻行驶中的小型汽车（尤其是高重心车辆如SUV/MPV），侧风是重大威胁。台风期间高速公路通常会关闭或限行。即使未关闭，也应主动驶离高速。",tip:"口诀：台风天开小车=随时被掀翻。高速公路可能关闭，主动撤离。"},
{id:1392,cat:"weather",type:"choice",q:"同时遇到夜间+大雨+高速公路的三重不利条件时，以下哪项综合做法最正确？",opts:["保持120km/h使用远光灯","开启近光灯和雾灯，车速降至60km/h以下，拉大跟车距离至150米以上，必要时驶入服务区","打双闪全速行驶","关闭所有灯光减少炫光"],ans:1,exp:"夜间+雨=能见度极差+路面湿滑+对向灯光炫光加剧。综合应对：近光灯+前雾灯+后雾灯→车速大大降低（≤60km/h甚至更低）→拉大跟车距离→尽量不超车不变道→如条件太差，驶入最近服务区等待。",tip:"口诀：夜+雨+高速=三重debuff——开灯（近光+雾灯）、降速（≤60）、拉距（≥150米）、不行就服务区。"},
{id:1393,cat:"weather",type:"judgment",q:"在高速公路夜间+大雾的双重影响下，可开启远光灯提高能见度。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"雾天开远光灯=灯光被雾气中的水滴反射→形成「白墙效应」→反而什么都看不见。雾天应使用近光灯+前雾灯+后雾灯。夜间雾天更需要近光（光线穿透雾气更好）。",tip:"口诀：雾天+远光灯=自瞎。远光打到雾上反射回来，白茫茫一片。雾天用近光+雾灯。"},
{id:1394,cat:"weather",type:"choice",q:"关于「黑冰」（Black Ice，路面极薄冰层，肉眼几乎看不见）的识别和应对，以下哪项说法正确？",opts:["黑冰很容易看到","黑冰常出现在桥梁、隧道口、背阴路段、清晨低气温时，路面看起来湿润但在车灯光照下无明显水花飞溅。应大幅减速，避免刹车和转向","黑冰不影响行车安全","压过黑冰时应加速通过"],ans:1,exp:"黑冰最危险之处=难以察觉（路面看起来只是潮湿）。常出现在：桥梁（上下冷风吹、桥面先结冰）、隧道口（进出温差）、背阴路段（日照不到）、清晨气温最低时。识别特征：前方车辆轮胎没有水花溅起（但路面看起来湿的=实际是冰）。应对：不提速、不急刹、不急转，让车滑行通过。",tip:"口诀：黑冰=看不见的杀手。桥面/隧道口/背阴处/凌晨=高危区。路面湿但没水花=冰！松油门滑过去。"},
{id:1395,cat:"weather",type:"judgment",q:"桥面比普通路面更容易结冰，因此冬季通过桥梁时应提前减速。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"桥面上下都不接触地面（不像普通路面有大地保温），冷空气从上下双向冷却桥面→桥面温度比普通路面低2-4°C→桥面先结冰并在普通路面还干燥时已经结冰。桥梁入口常有「桥面易结冰」警告标志。",tip:"口诀：桥面先结冰！因为上下冷风吹，不像路面有大地保温。过桥前降速。"},
{id:1396,cat:"weather",type:"choice",q:"车辆发生「水滑效应」（Hydroplaning，轮胎完全浮在水膜上失去抓地力）的最低车速阈值约为多少？",opts:["30km/h","50km/h","约80-90km/h（取决于轮胎花纹深度和积水深度）","120km/h以上"],ans:2,exp:"水滑效应发生的速度取决于：轮胎花纹深度（花纹越浅越危险，磨损至1.6mm极为危险）、积水深度（>2mm以上积水）、车速（车速越高越容易水滑）。一般在80-90km/h以上开始有风险，磨损轮胎更低速即可发生。发生时方向盘突然变轻、车辆漂移→松油门+握稳方向盘+不刹车。",tip:"口诀：水滑≈80码以上+积水面+光头胎。感觉方向突然变轻=水滑了→松油门不动刹车不动方向。"},
{id:1397,cat:"weather",type:"judgment",q:"车辆发生水滑时，应立即猛打方向盘调整方向和紧急制动以恢复控制。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"水滑时轮胎与路面失去接触，猛打方向和刹车都无效甚至加剧失控。正确做法：松油门（让车速自然下降）→握稳方向盘保持直线→等轮胎重新接触路面恢复抓地力→再缓慢调整。刹车应在轮胎恢复路面接触后再轻踩。",tip:"口诀：水滑=松油门+不动方向+不刹车。等轮胎重新碰到路面再说。"},
{id:1398,cat:"weather",type:"choice",q:"冬季驾车经过高海拔山口路段时，以下准备和做法哪项不正确？",opts:["提前了解气象和路况信息","携带防滑链并知道如何安装","不需要任何特殊准备","备足燃油和应急物资（水、食物、保暖衣物）"],ans:2,exp:"冬季高海拔山口=冰雪路面+低温（可能低于-20°C）+能见度变化快+救援困难。必须的准备：防滑链（并会装）、满油（电）、保暖衣物和应急食物、充电宝、提前了解气象和路况。没有准备=危险。",tip:"口诀：冬过高山=装备齐全再出发。防滑链、满油满电、保暖物资、查天气，缺一不可。"},
{id:1399,cat:"weather",type:"judgment",q:"在积雪覆盖的山路上，可以沿着前车的轮胎印行驶，不用担心路面边缘。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"前车的轮胎印不一定在路面中间——前车可能已经偏离到了边缘或危险区域。应以道路边缘参照物（护栏、标线、路缘石）为准判断位置，而非单纯跟随轮胎印。",tip:"口诀：雪地别盲目跟车辙印——前车说不定也走偏了。看护栏和路缘石判断路在哪。"},
{id:1400,cat:"weather",type:"choice",q:"在台风/强热带风暴期间驾驶，以下哪项做法是最危险的？",opts:["减速慢行","通过跨海大桥/跨江大桥等暴露结构时加速冲过去","注意横风和路面坠物","远离大型广告牌和行道树"],ans:1,exp:"台风时通过跨海/跨江大桥=极高风险（开阔水面无遮挡，风速更大，桥梁本身的振动也可能加剧）。应避免通过桥梁等暴露结构，寻找安全地带停车。如必须通过，应大幅减速（不是加速），做好强侧风准备。",tip:"口诀：台风天过桥=最危险。能不过就不过，必须过就龟速。"},
{id:1401,cat:"weather",type:"judgment",q:"台风过后，道路上可能仍有积水、倒树、坠落的电线等危险，应继续谨慎驾驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"台风过后道路未清理完毕：积水深度不明（可能掩盖坑洞）、断树断枝占道、电线杆倾倒（可能带电）。此时驾驶仍应减速慢行，提高警惕。",tip:"口诀：台风走≠路安全。积水藏坑、断树挡道、电线可能带电。灾后开车=比平时加倍小心。"},
{id:1402,cat:"weather",type:"choice",q:"在沙尘暴（扬沙/沙尘暴，能见度急剧下降至数百米甚至数十米）天气下在高速公路上行驶，正确的做法是？",opts:["开启远光灯","开启近光灯+前后雾灯+双闪，大幅降速，尽快从最近出口驶离或进入服务区","保持高速行驶尽快离开","关闭所有车窗即可"],ans:1,exp:"沙尘暴=能见度急降+细沙进入发动机进气系统（损害发动机）+影响人类呼吸。应对：开近光+前后雾灯+双闪（提高自身可见性）→降速至与能见度匹配→尽快驶离高速。沙尘暴期间高速通常限速甚至关闭。",tip:"口诀：沙尘暴=能见度归零+沙子伤发动机。开所有灯（远光除外）→大降速→尽快下高速。"},
{id:1403,cat:"weather",type:"judgment",q:"沙尘暴天气驾驶时可以开启空调外循环以保持空气流通。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"沙尘暴时应将空调切换至内循环（关闭外循环），防止沙尘通过空调系统进入车内。同时关闭所有车窗。外循环会将沙尘带入车内，呼吸系统和电子设备均受损。",tip:"口诀：沙尘暴=空调切内循环。外循环=把沙子吸进车里。"},
{id:1404,cat:"weather",type:"choice",q:"驾车途中突遇冰雹（Hail），以下做法正确的是？",opts:["加速通过","立即靠边停车，尽量选择有遮蔽处（桥下、加油站顶棚下，注意不要影响交通），人员留在车内避免被冰雹击中","下车寻找遮蔽物","打开车窗观察"],ans:1,exp:"冰雹=可能导致挡风玻璃破碎、车身损伤和人员受伤。应对：找到遮蔽处停车（立交桥下、加油站顶棚内等，但需不影响交通），人员留在车内（车身提供防护），关闭车窗。如无遮蔽处，靠边停车开启双闪。冰雹通常持续数分钟。",tip:"口诀：冰雹来了找遮蔽——桥下/加油站棚下停车。人千万别下车，冰雹砸头能出人命。"},
{id:1405,cat:"weather",type:"choice",q:"高温天气（气温超过40°C）长途行驶时，关于轮胎胎压的正确做法是？",opts:["保持厂家建议的标准胎压，避免超载，定时休息让轮胎冷却","适当降低胎压防止高温爆胎","提高胎压减少摩擦发热","轮胎洒水降温"],ans:0,exp:"降低胎压=增加轮胎与路面的摩擦→反而增加轮胎发热→更容易爆胎。正常做法：保持厂家建议的标准胎压（检查备胎）、避免超载、定时休息让轮胎冷却、使用氮气填充可减少高温膨胀。长途高温行驶胎压应正常。",tip:"口诀：高温降胎压=反效果（增加摩擦发热）。保持标准胎压+定时休息降温+别超载。"},
{id:1406,cat:"weather",type:"choice",q:"高温天气长时间行驶，以下哪项做法是正确的？",opts:["连续驾驶4小时以上不停车","每隔2小时左右停车休息，检查轮胎和发动机温度，补充水分","长时间怠速开空调休息","轮胎洒水降温"],ans:1,exp:"高温长途驾驶注意事项：定时休息（人补水+车散热）、检查轮胎有无鼓包/异常发热、检查冷却液温度和机油、不要在车内放置打火机/喷雾罐等。发动机长时间运转+高温环境=过热风险。",tip:"口诀：高温长途二小时歇一次。人喝水，车散热。打火机别放车里。"},
{id:1407,cat:"weather",type:"judgment",q:"驾车途中突遇山洪暴发（Flash Flood），看到前方路面有流动的水，如果水看起来不深，可以缓慢通过。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"山洪的水深和流速无法目测判断——15cm深的流水即可冲走小型车，30cm足以冲走大多数车辆（包括SUV）。洪水还可能已冲毁路面下方路基（路面表面看起来完好但底下已空）。遇到山洪=调头或停在高处，绝不能涉水。",tip:"口诀：山洪=看不见的深度和路基坑。15cm流水能冲走小车。见水就调头，别赌。"},
{id:1408,cat:"weather",type:"choice",q:"在多雨季节经过山区道路（有山体滑坡/泥石流风险的区域）时，以下哪项做法最正确？",opts:["快速通过风险区域","出行前查询地质灾害预警信息（国土资源部门和气象部门联合发布），避免在暴雨期间和暴雨刚过后通过风险路段","与前车保持近距离","在风险路段停车拍照"],ans:1,exp:"山体滑坡/泥石流常在持续暴雨后发生，有地质灾害预警机制。出行前应查询预警（红色/橙色预警=极高/高风险，应避免进入）。行驶中注意观察山坡有无异常（小石子滚落、水流突然变浑浊=泥石流前兆）——一旦有异常立即撤离。",tip:"口诀：雨季过山=先查地质灾害预警。红橙预警别进山。路上看到石子滚落+水变浑=泥石流前兆，快撤。"},
{id:1409,cat:"weather",type:"judgment",q:"经过可能发生山体滑坡的路段时，可以鸣喇叭以振动土层观察是否有松动。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"在可能的滑坡路段鸣喇叭=声音振动可能触发松动的土石滑落=人为引发灾难。应安静、快速、远离山体一侧通过。",tip:"口诀：滑坡路段别按喇叭——震动可能把石头震下来。安静快速通过。"},
{id:1410,cat:"weather",type:"choice",q:"关于高速公路雾天行车，以下哪种类型的雾最需要警惕（因为来势最突然、浓度变化最剧烈）？",opts:["城市雾","「团雾」（辐射雾/局地雾，突然出现的浓雾团块，能见度从几百米骤降至几十米甚至几米）","海雾","雾霾"],ans:1,exp:"团雾（Patchy Fog/突发浓雾）是高速公路上最致命的天气现象之一——在大范围天气良好的情况下突然出现的局部浓雾块。进入团雾时能见度从正常骤然降至极低，驾驶人完全没有心理准备→急刹车→连环追尾。团雾多出现在秋冬季节的夜间/清晨、水网地带、山谷低洼处。",tip:"口诀：高速第一杀手雾=团雾（突然一堵雾墙）。能见度骤降、毫无防备。看到「易发团雾路段」标牌要提高警惕。"},
{id:1411,cat:"weather",type:"judgment",q:"遇到团雾时，因为能见度极低，应立即紧急制动将车停下来。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"突然急刹=后车追尾（后车同样进入团雾看不到你已停车）。正确做法：松油门缓慢降速→同时开启前后雾灯+近光灯+双闪→保持车道内行驶不随意变道→寻找安全机会驶离高速。非万不得已不得在行车道停车。",tip:"口诀：进团雾别急刹（后车会追尾）——缓降速+开全灯+不变道+找机会下高速。"},
{id:1412,cat:"weather",type:"choice",q:"「温度逆增」（Temperature Inversion，近地面空气比上层更冷）与道路结冰的关系是什么？",opts:["温度逆增时路面反而不易结冰","温度逆增使近地面温度更低，路面结冰风险增大，尤其在桥面和低洼路段","温度逆增与结冰无关","温度逆增只在高海拔地区出现"],ans:1,exp:"温度逆增=暖空气在上、冷空气在下→近地面温度特别低→路面即使气温预报温度不低也可能结冰。这种地面和空气温度的差异是冬季道路结冰的重要成因。低洼路段（冷空气下沉聚集）尤其易结冰。",tip:"口诀：逆温=地面比空气更冷（冷空气沉在底下）。气象说2°C，地面可能已经结冰。"},
{id:1413,cat:"weather",type:"choice",q:"驾车通过有路面易结冰警示标志的路段时，后方有车辆催促，正确的做法是？",opts:["维持安全低速，不因后车催促而提高速度，可打右灯示意让后车在安全条件下超车","加速通过以满足后方车辆","紧急制动让后车先行","靠边停车让后车通过"],ans:0,exp:"结冰路段=最高优先级是自身安全，不是后方驾驶人的不耐烦。不因后车催促而提高速度，可打右转向灯示意让后车在安全条件下超车。在冰面急加速/急刹车/急转向=失控。",tip:"口诀：结冰路上被催也别快。你滑翻了他不会赔你。打右灯让他超，自己的节奏自己掌握。"},
{id:1414,cat:"weather",type:"choice",q:"驾车经过森林火灾（山火/Wildfire）附近的道路时，以下做法最危险的是？",opts:["关闭车窗和空调外循环","开启远光灯穿透烟雾","降低车速观察前方路况和烟雾方向","根据情况判断是否需要调头离开"],ans:1,exp:"烟雾+远光灯=反射炫光+完全失去视野（类似雾天开远光）。火灾烟雾影响能见度和呼吸，应关闭车窗+空调内循环、近光灯+雾灯、减速、评估火势方向——如山火向道路蔓延应立即调头远离。",tip:"口诀：烟雾中开远光=自盲。用近光+雾灯。烟大就关窗+内循环+快离开。"},
{id:1415,cat:"weather",type:"judgment",q:"寒潮天气（急剧降温+大风+可能降雪）清晨启动车辆后，应立即以高速行驶以快速使发动机达到工作温度。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"寒冷天气启动后应怠速运转30秒-1分钟让机油循环→然后低速行驶（≤40km/h）一段时间使发动机和变速箱逐步升温→水温正常后再正常驾驶。冷车立即高速行驶=发动机和变速箱润滑不足=加剧磨损。",tip:"口诀：寒潮冷启动=先怠速30秒→低速走一段→水温上来再正常开。冷车别猛踩。"},
{id:1416,cat:"weather",type:"choice",q:"在雪地长时间驾驶后，「雪盲症」（Snow Blindness，紫外线经雪地反射灼伤眼角膜）的症状和预防措施是什么？",opts:["雪盲症只影响视力不影响驾驶","症状为眼痛、畏光、流泪、异物感，预防措施为佩戴防紫外线的墨镜/护目镜。出现症状后应立即停止驾驶，闭眼休息，冷敷","雪盲症可以继续驾驶","雪盲症只在夜间发生"],ans:1,exp:"雪地对紫外线的反射率高达80-85%（远高于普通地面的10%），暴露数小时即可导致角膜上皮损伤（雪盲）。预防=佩戴UV400防护的墨镜或雪地护目镜。出现眼痛/畏光/流泪=立即停车→不要再开（视力受损无法安全驾驶）→闭眼休息+冷敷→通常24-48小时自愈。",tip:"口诀：雪地开车戴墨镜——不是耍帅，是防雪盲。眼睛一疼赶紧停，别硬撑。"},
{id:1417,cat:"weather",type:"choice",q:"大雪天在高速公路上行驶时，应如何使用灯光？",opts:["使用近光灯和前后雾灯（远光灯会因雪花反射导致严重眩光）","开启远光灯照亮更远距离","只使用示廓灯节省电力","关闭所有灯光减少反射"],ans:0,exp:"下雪时（与雾类似），远光灯照到雪花产生强烈反射和眩光，反而严重降低能见度。雪天应用近光灯+前雾灯+后雾灯。",tip:"口诀：雪天远光=照雪花反射回来闪瞎自己。用近光+雾灯。"},
{id:1418,cat:"weather",type:"choice",q:"关于高速公路桥梁在冬季比普通路面先结冰的现象，以下原因分析正确的是？",opts:["桥梁路面材料更容易结冰","桥面上下均受冷空气影响（不像普通路面有大地保温），温度降得更快更低","桥面有特殊涂层","只是偶然现象，没有科学依据"],ans:1,exp:"桥梁先结冰的原因：路面在地面上→大地在白天吸收热量、夜间缓慢释放（地温较稳定）；桥面悬空→上下都是冷空气→夜间降温快且幅度大→桥面温度可低于普通路面2-4°C→当普通路面还干燥时，桥面可能已有冰层。",tip:"口诀：桥悬空=双层冷风夹击。路面有大地\"暖宝宝\"（保温），桥面没有。"},
{id:1419,cat:"weather",type:"choice",q:"经过桥面结冰警告标志后，桥面看起来是干燥的，应如何应对？",opts:["按警告标志提示提前减速（桥面可能有无形的黑冰），不可因看起来干燥而高速通过","按正常速度行驶","加速通过","停车检查冰面"],ans:0,exp:"桥面结冰警告标志的设置说明该路段存在桥面先于路面结冰的风险——即使进桥时看起来干燥，桥面也可能有不可见的黑冰（透明薄冰层）。应按标志提示提前减速。",tip:"口诀：有结冰警告标志=即使看着干也是有风险的。减速就行了，别赌。"},
{id:1420,cat:"weather",type:"choice",q:"雨天夜间在有路灯照明的城市道路上行驶时，应使用什么灯光？",opts:["远光灯","近光灯","雾灯","示廓灯"],ans:1,exp:"夜间有路灯照明的道路=近光灯（有路灯说明照明条件尚可，不需远光；远光会对其他道路使用者造成眩光）。雨天夜间+有路灯=近光灯（有雨雾时可加开前雾灯）。",tip:"口诀：有灯照=近光够。路灯+远光=晃别人。雨天再加前雾灯。"},
{id:1421,cat:"weather",type:"judgment",q:"大风天气在高速公路上行驶时，在桥梁、隧道口等风力骤然增强的位置（风口效应），应加速行驶快速通过以减少受风时间。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"风口位置+加速=更快车速时受侧风打击后果更严重（侧风对车辆的影响力与车速平方成正比）。风口位置应减速，做好方向盘被横推的准备。",tip:"口诀：风口效应=风速骤增。越快的车速+越大的侧风=越容易翻。风口应该减速，不是加速。"},
{id:1422,cat:"weather",type:"choice",q:"遇到「风吹雪」（Blowing Snow，大风将积雪吹起形成类似沙尘暴的白蒙效应）天气时，正确的做法是？",opts:["开启远光灯","开启近光灯和前后雾灯，降低车速，保持车道，尽快驶离高速","加速冲出雪区","关闭所有灯光"],ans:1,exp:"风吹雪=类似沙尘暴+雾的叠加效应，能见度急剧下降+路面被风吹雪覆盖（可能掩盖冰面）。应对：开近光+前后雾灯+双闪→降速→保持当前车道不变道→尽快驶离。",tip:"口诀：风吹雪=雪地版的沙尘暴。白茫茫一片+路面突然有雪。降速+开灯+不变道。"},
{id:1423,cat:"weather",type:"judgment",q:"进入冬季后，高速公路会在可能结冰的路段喷洒融雪剂（盐/氯盐类），融雪剂不会对车辆底盘和轮胎产生任何影响。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"融雪剂（主要是氯化钠、氯化钙等氯盐）对车辆金属底盘有腐蚀作用（加速锈蚀）——尤其对老车和底盘防护差的车辆。冬季经过撒盐路段后，应尽快清洗底盘去除盐分。同时融雪剂也会加速轮胎橡胶老化。",tip:"口诀：融雪剂=盐。盐会腐蚀底盘。冬天走过撒盐路后尽快洗车洗底盘。"},
{id:1424,cat:"weather",type:"choice",q:"以下哪项不是冬季长途行驶的必备应急物品？",opts:["防滑链","保暖毯和应急食物","汽车应急启动电源（搭电宝）","遮阳挡"],ans:3,exp:"冬季应急物品重点：防滑链（冰雪路段）、保暖毯和应急食物（被困时防失温）、搭电宝（低温电池易亏电）、手电筒、充电宝、铲雪工具等。遮阳挡是夏季用品，冬季不必要。",tip:"口诀：冬季长途=防滑链+保暖物资+搭电宝+铲雪工具。遮阳挡=夏天用的，冬天不用。"},
{id:1425,cat:"weather",type:"judgment",q:"如果在冬季的夜晚被困在高速公路或偏远道路上（堵车或车辆故障），应持续运转发动机并开启暖风以保持车内温度。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"冬季夜间被困+持续发动引擎=废气积聚风险（排气管被积雪堵住时一氧化碳回流入驾乘舱）→一氧化碳中毒。正确做法：间歇性启动引擎供暖（每次10-15分钟，每小时一次），启动前检查排气管是否有积雪堵塞，并开窗留缝隙通风。",tip:"口诀：冬天困住别一直发动——排气管被雪堵=一氧化碳中毒。间歇启动+检查排气管+开窗留缝。"},
{id:1426,cat:"weather",type:"choice",q:"在高速公路上遇到浓雾+低温（0°C以下）的组合天气，路面上形成了雾凇/霜冻层，此时最正确的选择是？",opts:["保持100km/h行驶","车速不超过20km/h，开启所有灯光（除远光），尽快从最近出口驶离高速","正常速度行驶但开启远光灯","超越大车让其带路"],ans:1,exp:"雾+0°C以下=能见度极差+路面极滑（雾+霜=路面附着力极低）。此时应执行能见度<50米的标准：限速20km/h+开全灯+尽快驶离高速。继续在高速行驶风险极高。",tip:"口诀：雾+冰=双重危险。20码+全灯+下高速。这天还在高速上开=玩命。"},
{id:1427,cat:"weather",type:"judgment",q:"路面湿滑时（雨后、洒水后），加速或制动应比干燥路面更轻柔，避免急加速导致驱动轮空转打滑和急制动导致抱死侧滑。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"湿滑路面轮胎附着力显著降低，急加速→驱动轮空转打滑→车头摆动；急制动→车轮抱死→方向失控侧滑。应所有操作（加速、制动、转向）比干燥路面更轻柔平缓。",tip:"口诀：湿滑路面=手脚放轻。油门轻踩，刹车轻点，方向轻打。温柔就对了。"},
{id:1428,cat:"weather",type:"choice",q:"驾车从隧道驶出时遇到大雨（隧道内干燥→隧道外大雨），需要特别注意什么？",opts:["不需要注意","出隧道瞬间视野因雨水急剧变化（挡风玻璃突然被雨淋湿+隧道外亮度变化），应提前减速、开启雨刮器","加速通过","立即紧急制动"],ans:1,exp:"隧道内干燥→出隧道瞬间挡风玻璃被大量雨水覆盖=视野瞬间归零+光差（黑洞/白洞效应）。正确做法：进隧道前留意天气预报和前方路况→如知道出隧道后有大雨，出隧道前就开启雨刮器并减速→做好视野瞬间丧失的准备。",tip:"口诀：隧道口+大雨=双重暴击——眼睛还没适应光，挡风玻璃就被雨糊了。出隧道前提前开雨刮和减速。"},
{id:1429,cat:"weather",type:"judgment",q:"雨天在弯道行驶时，车辆可能出现「转向不足」（推头/前轮向外滑）或「转向过度」（甩尾/后轮向外滑），这两种情况的应对方法相同——都是紧急刹车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"转向不足（推头）=松油门+轻微回方向+等前轮恢复抓地力；转向过度（甩尾）=松油门+向甩尾方向反打方向+不要刹车。两种情况的应对方法不同，但共同点是都不能急刹车（急刹加剧失控）。",tip:"口诀：推头（前轮外滑）=松油回方向；甩尾（后轮外滑）=松油反打方向。两种都别刹车！"},
{id:1430,cat:"emergency",type:"choice",q:"在高速公路上遇到刹车完全失灵（制动踏板踩到底毫无制动力）的紧急情况，处理措施的先后顺序是什么？",opts:["立即拉手刹","松油门→开启双闪→尝试逐级降挡（利用发动机制动）→寻找并驶入紧急避险车道（如有）→万不得已时利用护栏摩擦减速","猛打方向盘","立即熄火"],ans:1,exp:"刹车失灵处置顺序：①松油门停止加速→②开双闪警告后车→③逐级降挡（自动挡切至手动模式/L挡/低速挡）利用发动机制动减速→④寻找紧急避险车道（沙石减速床）冲入→⑤最后手段：用车身侧面轻擦护栏/山体减速（不可正面撞击）。错误做法：立即拉手刹（可能翻车）、立即熄火（失去转向助力）。",tip:"口诀：刹车失灵五步走——松油门→双闪→降挡（发动机拖慢）→冲避险车道→擦护栏（最后手段）。别拉手刹、别熄火。"},
{id:1431,cat:"emergency",type:"choice",q:"刹车失灵时能否将发动机熄火来使车辆停下来？",opts:["不能——熄火会失去转向助力和刹车真空助力，导致车辆更难控制","可以，这是最有效的减速方法","可以，但需要在低速时操作","可以，现代车辆熄火后刹车和转向仍能工作"],ans:0,exp:"熄火=失去转向助力（方向盘变重无法转向）+失去刹车真空助力（剩余刹车力更弱）=车辆完全失控。现代车辆的转向和刹车都依赖发动机运转提供的辅助动力。",tip:"口诀：刹车失灵不能熄火——熄火=方向打不动+刹车更弱。保持发动机运转至少有方向助力。"},
{id:1432,cat:"emergency",type:"choice",q:"在长下坡路段（连续下坡数公里）行驶时，为了预防刹车过热失效，正确的做法是？",opts:["一直轻踩刹车控制速度","使用低速挡（L挡/S挡/手动模式低挡位）利用发动机制动控制速度，配合间歇性刹车","空挡滑行","频繁急刹车测试刹车性能"],ans:1,exp:"长下坡=刹车过热失效的最大风险场景。发动机制动（Engine Braking）=挂低挡位让发动机高转速产生阻力拖慢车辆，是长下坡的核心安全技术。刹车应间歇使用（轻踩→松开散热→再轻踩），而非持续踩着不放。空挡滑行=失去发动机制动=极度危险。",tip:"口诀：下长坡=用发动机\"别\"住车（挂低挡），刹车当辅助用（轻踩松散热，别一直踩）。"},
{id:1433,cat:"emergency",type:"choice",q:"在长下坡时感觉刹车变软（制动踏板行程变长、制动力减弱），正确的做法是？",opts:["立即降挡利用发动机制动+寻找避险车道+开启双闪（刹车已经过热衰退，继续踩可能刹车完全失效）","继续用力踩刹车","加速通过下坡路段","空挡滑行"],ans:0,exp:"刹车变软=刹车油沸腾产生气泡（气阻/Brake Fade）=刹车即将完全失效的前兆。此时继续踩刹车无效——应立即降挡利用发动机制动+寻找避险车道+开启双闪。",tip:"口诀：长下坡刹车变软=刹车要没了！赶紧降挡用发动机制动+找避险车道。别继续踩了，没用的。"},
{id:1434,cat:"emergency",type:"choice",q:"车辆在高速公路上突然爆胎（前轮爆胎），正确的做法是？",opts:["紧急制动","紧握方向盘保持直线行驶，松油门逐渐减速，不踩刹车，待车速降低后轻踩刹车靠边停车","猛打方向盘修正方向","加速稳住方向"],ans:1,exp:"前轮爆胎最危险（爆胎车辆会向爆胎侧急偏）。关键反应：①双手紧握方向盘（尽全力抵抗跑偏）→②不要踩刹车！（刹车加速跑偏）→③松油门让车自然减速→④待车速降至30km/h以下后轻踩刹车靠边停车→⑤开双闪、150米放警示牌。全过程中最忌讳急刹和打方向。",tip:"口诀：爆胎三大忌——不刹车、不打方向、不松方向盘。握死方向盘+松油门让车自己慢下来。"},
{id:1435,cat:"emergency",type:"judgment",q:"后轮爆胎比前轮爆胎危险性小，但仍然需要紧握方向盘、松油门减速，不可急刹车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"后轮爆胎车辆有甩尾趋势，但比前轮爆胎（直接失去方向控制）危险性稍小。但处理原则相同：紧握方向盘+松油门+不刹车+等速度下来再靠边。",tip:"口诀：后轮爆胎=可能甩尾。处理原则一样：握方向+松油+不刹。前轮爆更危险，但后轮也不能大意。"},
{id:1436,cat:"emergency",type:"choice",q:"在高速公路弯道上发生爆胎，处理方式与直线爆胎有何不同？",opts:["完全相同","弯道爆胎危险性更高——除了握紧方向盘+松油门+不刹车外，还需注意离心力导致的车辆外滑趋势，尽可能不要增加转向角度","弯道爆胎可以紧急刹车","弯道爆胎应加速通过"],ans:1,exp:"弯道爆胎=爆胎失控+离心力外滑叠加。处理：握稳方向盘+松油门+不要额外增加转向角度（让车尽量沿着原有弯道轨迹滑行减速）+绝对不可急刹车。在弯道中爆胎急刹车=轮胎失去横向抓地力+刹车力=车辆沿切线冲出弯道。",tip:"口诀：弯道爆胎=双重危险（爆胎+甩出弯）。握方向+别多打方向+松油。让车自己沿弯滑着慢下来。"},
{id:1437,cat:"emergency",type:"judgment",q:"车辆在高速行驶中引擎盖突然弹起遮挡视线，应立即紧急制动停车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"引擎盖弹起遮挡视线→本能想踩刹车，但急刹可能导致后车追尾（后车不知道你为什么突然刹车）。正确做法：保持冷静→从引擎盖与挡风玻璃的缝隙或侧窗观察前方→松油门逐步减速→开双闪→打右转向灯变道至应急车道→停车处理。",tip:"口诀：引擎盖弹起遮了眼——别急刹（后车追尾）。从缝隙/侧窗看路，慢慢靠边停。"},
{id:1438,cat:"emergency",type:"choice",q:"车辆在高速行驶中油门踏板被卡住（无法回位），以下正确的处理方式是？",opts:["用脚去勾踏板","立即挂入空挡（N挡），同时刹车减速，靠边停车后熄火","猛踩刹车同时油门保持","关闭发动机"],ans:1,exp:"油门卡住（卡死）处置：①立即挂入空挡（N挡）→发动机失去负载转速会飙高（有限速器保护不会损坏）→②平稳刹车减速→③靠边停车→④熄火。不要先熄火（失去转向和刹车助力），也不要同时踩油门和刹车（刹车可能被油门抵消）。",tip:"口诀：油门卡住=先挂N挡（切断动力）→再刹车靠边→再熄火。别先熄火（方向会变重）。"},
{id:1439,cat:"emergency",type:"judgment",q:"油门卡住时可以同时用力踩刹车和油门以抵消动力。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"同时踩刹车和油门可能导致刹车系统过热失效（刹车和发动机对抗=刹车巨量发热），而且制动距离大增。应先切断动力（N挡/空挡）再刹车。",tip:"口诀：别让刹车和油门打架——先N挡断动力，再刹车。刹车斗不过发动机的。"},
{id:1440,cat:"emergency",type:"choice",q:"如果车辆即将发生不可避免的正面碰撞，且速度较高（>50km/h），驾驶人应如何保护自己？",opts:["松手趴下","双手紧握方向盘，背部紧贴座椅靠背，头部紧贴头枕，双脚踏实地板，身体后靠，利用安全带预紧和SRS气囊系统保护","解开安全带","闭上眼睛"],ans:1,exp:"预知即将正面碰撞：身体紧贴座椅（缩小身体与气囊之间的间距，避免气囊弹出时身体前移造成的二次伤害）→双手紧握方向盘（手臂承受冲击，同时保持方向稳定）→头部紧靠头枕（防鞭打损伤）→双脚踏实地板（稳定身体）。安全带的预紧装置会在碰撞瞬间拉紧，将身体固定在最佳受保护位置。",tip:"口诀：预知碰撞=身体后贴紧（给气囊留空间）+握方向盘+头靠头枕+脚踩实。不要往前趴。"},
{id:1441,cat:"emergency",type:"judgment",q:"车辆发生正面碰撞时，SRS安全气囊在碰撞后立即展开并保持充气状态为后续二次碰撞提供持续保护。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"气囊在碰撞瞬间（约30-50毫秒）展开后立即开始泄气（排气孔设计），不能保持充气状态——它的作用是缓冲碰撞瞬间的冲击力（一次性），而非提供持续的垫子。",tip:"口诀：气囊=瞬间缓冲（砰地炸开，立刻泄气）。不是一直鼓着的，别想着它能撑住二次碰撞。"},
{id:1442,cat:"emergency",type:"choice",q:"车辆在高速公路行驶中突然发生电器系统故障导致方向盘电子助力（EPS）失效，方向盘突然变重，正确的应对是？",opts:["紧急制动","双手用力操控方向盘保持方向，开启双闪，松油门减速后靠边停车","不管它继续开","尝试重新点火"],ans:1,exp:"EPS失效=方向盘需要非常大的力量才能转动（不是完全锁死，低速时尤为沉重）。应对：双手用力控制方向（方向盘还可以转动，只是需要更大的力量）→开双闪→松油门减速→寻找安全位置靠边停车→检修。不要急刹车（后车追尾风险）。",tip:"口诀：方向盘突然变重=电子助力没了。双手使劲+双闪+松油靠边。方向盘没锁死，只是变沉了。"},
{id:1443,cat:"emergency",type:"judgment",q:"方向盘完全锁死（无法转动）时，应该立即使劲扭动方向盘以解锁。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"方向盘完全锁死=转向柱机械故障（极其罕见但可能发生）。使劲扭动可能进一步损坏转向机构，应紧急制动停车。但要注意：停车熄火后方向盘被防盗锁锁住（轻微转动方向盘同时拧钥匙即可解锁）是正常现象，非故障。",tip:"口诀：行驶中方向盘锁死=极罕见但致命。急刹停车！和停车后防盗锁死是两码事。"},
{id:1444,cat:"emergency",type:"choice",q:"在驾驶过程中，手机电量耗尽且车载充电器损坏，同时又遇到紧急情况需要报警求助，以下做法正确的是？",opts:["拦路过的车辆借用电话","使用车辆自带的SOS紧急呼叫系统（如车辆配备）、GPS定位装置发出求救信号、或到最近的服务区/收费站求助","什么都不做等待被发现","在行车道上挥手求助"],ans:1,exp:"现代车辆通常配备：SOS紧急呼叫按钮（车顶/中控台，按下自动拨打紧急电话+发送GPS位置至救援中心）、eCall系统（欧盟/中国标准，碰撞时自动呼叫）。无此功能：到服务区/收费站/加油站求助，或使用高速公路上的紧急电话（路侧每隔1-2km有黄色/橙色应急电话亭，直通监控中心）。不得在行车道上拦车。",tip:"口诀：手机没电=用车上SOS按钮+GPS定位。或到路边的黄色应急电话亭（高速每隔一两公里一个）。"},
{id:1445,cat:"emergency",type:"judgment",q:"在高速公路上遇到紧急情况需要求助，可以站在行车道上向过往车辆挥手示意。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"在行车道上挥手=极度危险（行车道车速100km/h+，行人无法安全站立）。应撤到护栏外侧使用应急电话或SOS系统求助。",tip:"口诀：高速求助=人到护栏外+用应急电话/SOS。别在车道里挥胳膊。"},
{id:1446,cat:"emergency",type:"choice",q:"同时出现多个紧急情况（例如：爆胎+刹车失灵+车辆起火），在无法全部处理的情况下，优先处置的排序原则是什么？",opts:["先处理最危险的问题","人员安全第一（撤离＞灭火＞控制车辆＞报警）","先报警","先灭火"],ans:1,exp:"多重紧急情况=按「人员安全」优先级排序：①确保人员安全（如起火=人员立即撤离到安全距离；如碰撞=确认人无伤亡）→②控制车辆（防止二次事故，如将车移至安全地带+放警告标志）→③报警求助→④后续处置。任何情况下人的生命>财产。",tip:"口诀：多个紧急同时来=人第一！先保命→再控车→再报警。车烧了能买新的，人没了就是没了。"},
{id:1447,cat:"emergency",type:"judgment",q:"车辆发动机舱冒烟或出现小火苗时，应立即打开发动机盖查看火源并用灭火器喷射。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"打开发动机盖=大量新鲜空气涌入→火势瞬间爆燃（Backdraft效应）。正确做法：发动机盖保持关闭→从进气格栅或散热器缝隙喷射灭火器（如可触及）→人员远离车辆→拨打119。发动机舱火势无法控制时，应弃车远离（至少30米以上，防止爆炸碎片伤人）。",tip:"口诀：发动机舱冒烟/小火=别开盖（一开盖子火\"轰\"地窜出来）。从缝隙喷灭火器+打119。"},
{id:1448,cat:"emergency",type:"choice",q:"在高速公路上车辆发生火灾（如引擎舱起火、车内起火），第一步应该做什么？",opts:["打开引擎盖","立即停车→车上所有人迅速下车撤离到护栏外安全地带→拨打119→如果火势很小且有灭火器可尝试灭火（但不打开引擎盖）","尝试灭火","收拾车内贵重物品"],ans:1,exp:"车辆起火=人员立即撤离是第一（车辆油箱/电池可能爆炸）→撤离距离至少30米以上（高速公路上撤到护栏外并远离起火车辆）→拨打119→火势很小且有条件才尝试灭火。不要为了拿车内物品返回起火车辆。",tip:"口诀：车着火=人先跑远（至少30米/护栏外）→119→火小才尝试灭火。别为包包手机回去。"},
{id:1449,cat:"emergency",type:"judgment",q:"在车内备有灭火器的车辆，灭火器应放在后备箱方便取用的位置。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"灭火器应放在驾驶舱内随手可及的位置（如副驾驶座位下方、中控台侧、驾驶座下方固定支架），而非后备箱——紧急情况下没有时间去后备箱翻找。部分车型在驾驶座下方有专用灭火器固定架。",tip:"口诀：灭火器放驾驶舱（随手拿得到），别放后备箱。着火了你还去后备箱翻？"},
{id:1450,cat:"emergency",type:"choice",q:"车上乘客突发急产（孕妇突然分娩），作为驾驶人应该怎么做？",opts:["继续开往医院","立即安全停车→拨打120急救电话→在急救中心指导下协助产妇（如有电话指导条件）→如情况紧急且无电话指导，按基本分娩知识协助","让产妇自己处理","加速行驶"],ans:1,exp:"急产处理：安全停车（开双闪）→拨打120（急救中心可电话指导分娩）→协助产妇平躺，垫高头部→准备好干净的布/衣物包裹新生儿→不要试图阻止胎儿娩出，也不要用暴力拉扯→胎盘娩出后保留（医生需要检查）→新生儿保暖（用干净布包裹，放在母亲胸前体温传递）→等待专业急救人员。",tip:"口诀：车上生娃=靠边停→120电话指导→平躺+准备干净布+别硬拽娃。急救中心会电话教你。"},
{id:1451,cat:"emergency",type:"judgment",q:"车上有人发生严重过敏反应（过敏性休克，如呼吸困难、面部肿胀、全身荨麻疹），如果情况紧急且附近有药店，可以停车去药店购买抗过敏药后继续等待缓解。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"过敏性休克是危及生命的急症（喉头水肿可能导致气道完全堵塞数分钟内死亡）——应立即停车→拨打120→如有肾上腺素自动注射笔（EpiPen）且知道如何使用，协助大腿外侧注射→让患者平躺+抬高腿部。不要离开患者去买药，时间就是生命。",tip:"口诀：过敏休克=停+120+如有肾上腺素笔用上。喉头肿了数分钟就窒息，别耽误。"},
{id:1452,cat:"emergency",type:"choice",q:"在驾驶中发生疑似中风/脑卒中（FAST症状：面部歪斜Face、手臂无力Arms、言语不清Speech、时间紧急Time），正确的处理是？",opts:["让患者喝水","立即停车→拨打120→让患者平卧、头偏向一侧（防呕吐物堵塞呼吸道）→不随意给水/食物/药物→记录症状开始时间告知急救人员","让患者下车活动","加速冲向医院"],ans:1,exp:"疑似脑卒中（中风）处理：安全停车→120（说清FAST症状和发病时间）→患者平卧、头偏一侧（防误吸+降低颅内压）→不要给水和食物（可能有吞咽功能障碍）→不要给任何药物（包括阿司匹林，可能是出血性脑卒中，阿司匹林会加重出血）→记录症状开始的确切时间（影响溶栓治疗的时间窗口，通常4.5小时内）。",tip:"口诀：疑似中风=FAST识别→120→平卧头侧偏→禁食水药（别给阿司匹林！可能是脑出血）。记住发病时间。"},
{id:1453,cat:"emergency",type:"judgment",q:"怀疑车上乘客发生脑卒中时，可以给患者服用阿司匹林来预防血栓进展。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"脑卒中分为缺血性（血栓堵塞）和出血性（血管破裂），两者症状在院外无法区分。阿司匹林可帮助缺血性脑卒中但会严重加重出血性脑卒中（导致更大的出血量）。在没有CT确诊前，绝对不要给阿司匹林。",tip:"口诀：中风分两种——缺血（堵了）和出血（破了）。不知道哪种不能乱吃药，阿司匹林可能火上浇油。"},
{id:1454,cat:"emergency",type:"choice",q:"冬季在车内长时间停车并关闭车窗开暖风（发动机怠速运转），最致命的风险是什么？",opts:["浪费燃油","一氧化碳（CO）中毒——排气管废气中含有的CO无色无味，可在不知不觉中使车内人员中毒死亡","车辆过热","电池亏电"],ans:1,exp:"发动机怠速+车窗关闭+长时间=一氧化碳中毒——CO通过车厢通风系统或缝隙进入车厢，与血液中血红蛋白结合能力是氧气的200-300倍→全身组织缺氧→头晕、恶心、意识丧失→死亡。每年冬季都有此类悲剧发生。绝对不要在密闭空间/静止车辆中长时间怠速开空调/暖风睡觉。",tip:"口诀：停车+关窗+怠速暖风=CO中毒套餐。无色无味，睡着就醒不来了。千万别在车里怠速睡觉。"},
{id:1455,cat:"emergency",type:"judgment",q:"在车内长时间怠速开空调取暖时，只需将空调模式调为内循环就可以防止一氧化碳中毒。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"内循环不能完全隔绝CO进入+车辆密封并非100%气密+CO可能通过底盘空隙、线束套管等进入。最安全的方法是不在静止车辆中长时间怠速开空调。如必须取暖，应开窗留缝通风+间歇启动。",tip:"口诀：内循环≠防CO。内循环不是气密舱门。怠速睡觉=危险，不管什么循环。"},
{id:1456,cat:"emergency",type:"choice",q:"如果车辆在高速公路上发生电器故障，同时出现刹车和油门踏板均失效的极端情况（行车电脑完全故障），最可行的做法是什么？",opts:["等待车辆自行停止","尝试将挡位挂入N挡（空挡）或低速挡→利用手刹（电子手刹持续拉/机械手刹缓慢拉）辅助减速→寻找上坡路段或避险车道","立即熄火","打开车门用脚刹"],ans:1,exp:"极端多重故障：设法挂低速挡利用发动机制动+手刹辅助（电子手刹长拉>3秒=紧急制动模式；机械手刹缓慢拉动，不要一下拉死导致抱死甩尾）+寻找避险车道。不要熄火（失去剩余控制可能）。此情况极其罕见但需要了解基本处置逻辑。",tip:"口诀：刹车油门双失灵=降挡（发动机拖）+手刹缓拉+冲避险车道。电子手刹长拉=紧急制动。"},
{id:1457,cat:"emergency",type:"judgment",q:"车辆高速行驶中，电子驻车制动（EPB电子手刹）长拉不放可以触发紧急制动功能，帮助减速。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"现代车辆的EPB（电子手刹）设计有紧急制动模式：行驶中持续拉起EPB开关（约3秒以上），系统将通过电子稳定程序（ESP）以最大制动力对所有四个车轮进行液压制动（非机械手刹仅刹后轮）。这是为刹车系统完全失效设计的备用制动手段。",tip:"口诀：电子手刹长拉（3秒以上）=紧急制动。刹车没了就靠它救命。"},
{id:1458,cat:"emergency",type:"choice",q:"车辆在高速行驶中突然发生侧翻征兆（如车辆一侧翘起即将侧翻），应如何应对？",opts:["向翘起方向打方向","向翘起的反方向打方向（即向地面侧打方向），同时松油门，利用重力和转向力抵抗侧翻","紧急制动","加速抵抗侧翻"],ans:1,exp:"侧翻即将发生：向地面侧（即车将要倒下的反方向/低的一侧）打方向——利用转向产生的离心力抵抗侧翻力矩+松油门降低速度（减速减少离心力）。向高处打方向=加倍侧翻力矩=加速翻车。紧急制动=进一步增加翻车力。",tip:"口诀：车要往右边翻了就往右打方向（往要倒的方向打，用离心力顶回去）+松油。别刹车。"},
{id:1459,cat:"emergency",type:"judgment",q:"SUV和MPV等重心较高的车辆比轿车更容易发生侧翻，因此在高速公路弯道和紧急避让时应更加谨慎。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高重心车辆（SUV/MPV/皮卡/货车）侧翻阈值（SSF/静态稳定系数）低于轿车，同等条件下更容易侧翻——弯道速度过快或急打方向躲避障碍物时尤其危险。驾驶高重心车辆应：弯道速度比轿车更低、避免任何急打方向动作。",tip:"口诀：SUV/MPV=高个子，弯道容易翻。比轿车更怕急打方向。"},
{id:1460,cat:"emergency",type:"choice",q:"车辆坠入深水（如河流、湖泊），在水面下沉过程中和水下逃生，正确的步骤是什么？",opts:["等待救援","利用车辆刚入水还浮在水面的短暂时间（约30-120秒）立即解开安全带→打开车窗/天窗逃生→如车窗无法打开，用破窗器击碎侧窗玻璃（非挡风玻璃）→从窗户逃出→如已全部沉没，等车内几乎被水充满、内外压力平衡后尝试打开车门","立即打开车门","用头撞挡风玻璃"],ans:1,exp:"车辆落水逃生黄金时间：刚入水车辆漂浮（约30-120秒）——立即解开安全带+开窗/天窗逃出（此时车窗还能操作）。如已下沉：不要试图打开车门（外部水压巨大，开不了）→用破窗器（弹簧式破窗器>安全锤，水中有阻尼）击碎侧窗四角→等车内几乎充满水、内外压平衡时车门可打开→最后深吸一口气潜出。挡风玻璃是夹层玻璃，极难打碎，打侧窗。",tip:"口诀：车落水=刚浮着的时候最快开窗跑！来不及就破窗（侧窗，不破前挡）→等水快灌满→开门潜出。破窗器买弹簧式的。"},
{id:1461,cat:"emergency",type:"judgment",q:"车辆落水后，挡风玻璃是最容易打破的逃生窗口。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"挡风玻璃=夹层安全玻璃（两层玻璃夹PVB膜），即使碎裂也不会散开——极难打破也极难推开。侧窗=钢化玻璃（碎裂后散成小块），使用破窗器击碎四角（不要击中心）即可破除。侧窗才是正确的逃生窗口。",tip:"口诀：逃生破侧窗，别跟前挡风较劲。前挡=夹层的（打不破），侧窗=钢化的（击四角就碎）。"},
{id:1462,cat:"emergency",type:"choice",q:"车辆发生碰撞后发动机舱开始冒烟并有电火花，这可能是什么情况？",opts:["正常现象","电路短路导致电气火灾——应立即关断电源（拔钥匙/按熄火按钮），人员撤离，使用灭火器（非水基型）灭火","洗车残留水分蒸发","空调正常排热"],ans:1,exp:"碰撞后发动机舱冒烟+电火花=电池线路短路→电气火灾前兆。应对：关断全车电源→人员撤离至安全距离（>15米）→用灭火器（干粉/CO2灭火器，不可用水灭火——水导电会加重短路和电击风险）→拨打119。电动车碰撞后电气火灾风险更高。",tip:"口诀：碰撞后冒烟+火花=电气火灾。断电→人撤→干粉灭火（别用水浇电火）→119。"},
{id:1463,cat:"emergency",type:"judgment",q:"使用灭火器扑救车辆电气火灾时，应使用水基型灭火器，因为水可以快速降温。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"电气火灾（电路、电池）=严禁用水（水导电→电击扑救人员+加重短路）。应使用干粉灭火器（ABC型/BC型）或二氧化碳（CO2）灭火器。水基灭火器仅适用于普通可燃物（纸张、木材、纺织品等）火灾。",tip:"口诀：电气火灾=干粉或CO2灭火器。水=电死自己。分清楚火源选灭火器。"},
{id:1464,cat:"emergency",type:"choice",q:"车辆运输危险货物（如小型气瓶、化学品样品等）发生泄漏，以下做法最正确的是？",opts:["自己尝试堵漏","立即停车熄火→人员撤离至上风方向的远处安全地带→拨打119/122→告知危险品种类和UN编号（包装上的4位数字）","用水冲洗","继续行驶到目的地再处理"],ans:1,exp:"危化品泄漏=人先撤（往上风方向撤，避免吸入/接触）→拨打119告知危化品名称和UN编号（国际通用的危险品识别号，4位数字，写在货物包装菱形警示牌中间）→封锁区域禁止明火。千万不要自行处理泄漏（缺乏防护装备和专业知识），也不要开车继续行驶（泄漏扩散危害更多人）。",tip:"口诀：危险品泄漏=人跑上风方向→打119说清是什么东西（UN编号4位数）→远离明火。别自己处理。"},
{id:1465,cat:"emergency",type:"judgment",q:"大型客车在高速公路上发生事故或故障需要疏散乘客时，乘客应当留在车内等待救援以确保安全。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"客车（尤其大客车）事故/故障=乘客必须立即有序撤离到护栏外侧安全区域。车内等待=二次事故风险（可能被后方车辆追尾撞击）。乘客应通过车门和应急出口有序撤离，在护栏外集中等待接驳车辆。",tip:"口诀：大客车高速出事=全车人下车撤护栏外。别待在车里（后车可能追上来）。"},
{id:1466,cat:"emergency",type:"choice",q:"车辆在高速公路上撞上缆索护栏（Cable Barrier/钢索护栏）或波形护栏（W-beam Guardrail）后，正确的做法是？",opts:["继续行驶","停车检查车辆损伤情况→如车辆仍可安全行驶，开到出口/服务区进一步检查；如车辆严重受损，按故障车程序处理（双闪+警告牌+人员撤离+报警）","不管损伤程度","试图修复护栏"],ans:1,exp:"撞护栏后：护栏本身可能已受损并突出侵入车道（对后续车辆构成威胁）。应停车检查车辆损伤（是否漏油/冷却液、轮胎是否完好、方向系统是否正常）。如车可安全行驶→缓慢行驶至最近出口/服务区→报警报告护栏受损位置（以便养护单位修复）。如车不能开→故障车标准程序：双闪+150米警告牌+人撤+报警。",tip:"口诀：撞了护栏=停车检查→车能开就到服务区再查→报警说清护栏位置（方便修复）。不能开=故障车流程。"},
{id:1467,cat:"emergency",type:"judgment",q:"在高速公路上撞到护栏后，如果车辆还能行驶，就不需要报警了。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"撞护栏属于单方事故，损坏公共设施（护栏）——必须报警（122），保险公司理赔也需要交警出具事故认定书。不报警逃逸=交通肇事逃逸（即使是单方事故损坏公共设施也属于）。",tip:"口诀：撞了护栏必报警——损坏公共设施。跑了算逃逸。"},
{id:1468,cat:"emergency",type:"choice",q:"车辆在高速公路高架桥上段发生故障，需要从高架桥下到地面，以下哪项做法正确？",opts:["翻越护栏爬下去","在车内等待直升机救援","如果车还能移动，缓慢行驶至最近出口或临时停车带；如完全无法移动，按故障车程序处理，人员撤离至护栏外侧（注意高架桥上距离地面可能数十米，找到安全的撤离位置）","让乘客下车步行下桥"],ans:2,exp:"高架桥上故障：车可动=缓慢开至出口（开启双闪）。车不可动=双闪+150米（或根据能见度适当加大）警告牌+人员撤离至护栏外（人员必须远离行车道，但高架桥上护栏外可能是窄路肩或陡坡——尽量找到相对安全位置）+拨打122/12122。绝对不要让人员在高架桥上行走（汽车+高速+高空=三倍危险）。",tip:"口诀：高架桥故障=车能动就慢慢开下去→不能动就双闪+警示牌+人撤到护栏外。人别在高架桥走路。"},
{id:1469,cat:"emergency",type:"judgment",q:"在高速公路上碰到突然窜出的大型动物（如鹿、牛、野猪等），应紧急打方向躲避。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速+紧急打方向躲避动物=翻车或撞护栏（可能比撞动物后果更严重）。安全策略：①如果车速较低且周围无其他车辆，确认安全后可小幅度避让；②如果车速高（>80km/h），握稳方向盘+紧急制动（保持方向直线）——即使撞上动物也比翻车好。③撞击后停车按故障车程序处理→报警（告知动物位置以便清除尸体，防止后续事故）。",tip:"口诀：高速遇动物窜出=握稳方向+直线刹车（别猛打方向躲）。翻车/撞护栏比撞动物的后果严重。"},
{id:1470,cat:"emergency",type:"choice",q:"在高速公路上行驶时，前方相邻车道的车辆突然有车轮飞脱并朝你的方向滚来，正确的应对是？",opts:["紧急打方向躲避","握稳方向盘，轻柔减速，如果车轮确实即将撞击你的车辆，保持方向直线（正面撞击优于侧面撞击）","加速逃开","关闭眼睛等待撞击"],ans:1,exp:"高速飞来的车轮=巨大的动能撞击物。应对：紧握方向盘（做好撞击准备）→轻柔减速（不紧急制动以免失控）→保持方向直线（正面撞击由发动机舱/保险杠吸收能量，远优于侧面撞击——车门无法抵抗这种冲击力）→撞击后稳定车辆→靠边停车。",tip:"口诀：对向飞来大轮胎=握死方向+轻减速+直线迎接（正面撞好过侧面撞）。发动机舱能吸能，车门不能。"},
{id:1471,cat:"emergency",type:"judgment",q:"在高速公路上遇到前方车辆突然掉落的货物砸向挡风玻璃，应下意识闭眼低头躲闪。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"闭眼低头=失去方向控制。正确反应：保持眼睛睁开（挡风玻璃可能能挡住或部分挡住）+握稳方向盘+松油门+轻柔刹车。挡风玻璃是夹层玻璃，即使碎裂也不会散开穿透（小物品通常能挡）。失去方向控制比被玻璃碎粒划伤的风险大得多。",tip:"口诀：东西飞来砸玻璃=睁眼+握方向+松油。别闭眼躲——闭眼等于失控。"},
{id:1472,cat:"emergency",type:"choice",q:"车辆在高速公路上发生翻车，车辆四轮朝天（倒置状态），车内人员如何安全逃生？",opts:["立即解开安全带（会摔落车顶受伤）","等待救援不采取行动","先确认身体无严重受伤→用一只手撑住身体（防止安全带解开后跌落伤颈）→用另一只手解开安全带→从破碎的侧窗或车门爬出（车门打不开用破窗器）","从天窗爬出"],ans:2,exp:"翻车后倒置状态：不要急于解开安全带（解开后人会摔到车顶，可能导致颈椎/头部二次伤害）→先用手或腿撑住身体→再解开安全带→缓慢降到车顶（现在的车顶）→观察周围安全→爬出。天窗如有可从此出，侧窗是主要通道。",tip:"口诀：翻车倒悬=别急着解安全带（会摔下来）。先撑住身体→再解→慢慢落到\"车顶上\"→爬出来。"},
{id:1473,cat:"emergency",type:"judgment",q:"发生翻车事故后，如果闻到汽油味，应立即发动车辆尽快驶离以防爆炸。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"翻车后闻到汽油味=油箱/油管泄漏→极度火灾危险。应：绝对不要发动车辆（火花可能点燃油气）→不准使用打火机、手机远离（虽手机引发火灾概率极低，但安全起见远离泄漏区再拨打）→人员远离车辆（>30米）→拨打119。",tip:"口诀：翻车闻到汽油=离远点+别打火+别用火+119。油气遇火花=爆炸。"},
{id:1474,cat:"emergency",type:"choice",q:"车辆碰撞导致机油/燃油/冷却液泄漏到路面，以下哪种后续处置最正确？",opts:["不管继续开","用水冲洗","开启双闪→设置警示牌→人员撤离→报警→告知有液体泄漏（以利于后续路面清理和防止其他车辆打滑）","用沙土覆盖后离开"],ans:2,exp:"液体泄漏=路面变得极其滑（油类+水或防冻液=极低附着力），对其他车辆构成连锁威胁。应报警报告泄漏位置和液体种类（机油/燃油/防冻液）→公路养护单位会用专业吸收材料处理→事故处理完成前，警告牌留在现场警示后车。",tip:"口诀：撞车漏油=路面变冰场。报警+说清漏什么→留给专业的人清理→警示牌先留着。"},
{id:1475,cat:"ev",type:"choice",q:"纯电动汽车在-10°C低温环境下续航里程通常比常温（20-25°C）下降约多少？",opts:["几乎不降","约10-20%","约30-50%（取决于车型、电池技术、是否使用热泵空调等）","80%以上"],ans:2,exp:"低温对纯电续航影响显著：锂电池在低温下内阻增大+电解液粘度增加→可用容量降低；同时暖风制热（PTC加热尤其费电，热泵空调节省约40%制热电耗）。综合因素下续航下降30-50%是常见范围。部分车型配备电池预加热系统（在充电时将电池加热到工作温度）可缓解此问题。",tip:"口诀：冬天电车续航打5-7折（降30-50%）。热泵空调比PTC省电，电池预加热可缓解。"},
{id:1476,cat:"ev",type:"judgment",q:"纯电动汽车在夏季高温（35°C+）环境下续航不受影响，因为不需要开空调。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高温同样影响续航：①电池热管理系统需要耗电散热（电池最佳工作温度20-40°C，超过需要主动冷却）；②空调制冷耗电（压缩机+冷凝风扇+鼓风机）。高温续航下降幅度通常比寒冷小（约10-20%），但不可忽视。",tip:"口诀：夏天电车续航也降（降10-20%）。空调制冷和电池散热都在耗电。"},
{id:1477,cat:"ev",type:"choice",q:"冬季低温充电时，正确的做法是什么？",opts:["随到随充","如果车辆支持电池预加热功能（Battery Preheating/Preconditioning），在导航到充电站时启用此功能→电池被加热到适合快充的温度（约25-35°C）→大幅提高充电速度","低温时必须使用慢充","不要充电"],ans:1,exp:"低温下直接快充：电池温度低→充电电流受限→充电速度极慢且可能析锂损伤电池。电池预加热功能（大多数2024+电动车配备）在前往充电站途中加热电池至适合快充的温度→充电功率可达峰值。无此功能：低温时优先慢充（家用慢充自动温和充电），或先行驶一段时间让电池自发热后再快充。",tip:"口诀：冬天快充前先预热电池（导航到充电站自动预热）。冷电池直接快充=又慢又伤电池。"},
{id:1478,cat:"ev",type:"judgment",q:"电池健康状态SOH（State of Health）低于80%时，表示电池已严重衰退，需要更换。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"SOH=当前电池最大可用容量占出厂容量的百分比。行业标准：SOH<80%视为动力电池寿命终结（需要更换），大多数厂家提供8年/12-16万公里SOH≥70%或80%的质保。SOH的下降是渐进过程，0-80%时缓慢下降，80%以下通常加速衰退。",tip:"口诀：SOH低于80%=电池该换了。厂家一般保8年/12-16万公里≥70-80%。"},
{id:1479,cat:"ev",type:"choice",q:"电动汽车充电口盖无法电动/手动打开（电子故障或机械卡死），紧急情况下如何打开？",opts:["撬开","查阅车辆说明书——通常有紧急手动释放拉索（位于后备箱/手套箱/充电口附近隐蔽处），拉动后机械解锁充电口盖","放弃充电","用工具暴力破坏"],ans:1,exp:"充电口盖通常为电子锁止，没电或故障时通过紧急手动拉索打开——拉索位置各车型不同（常见位置：后备箱内充电口侧饰板后方、手套箱内、前舱内），需查阅车辆说明书。不要暴力撬开（可能损坏充电口+车漆+电子锁止机构）。",tip:"口诀：充电口打不开=找紧急拉索（手册写的）——一般在后备箱充电口那侧的饰板后面。别撬。"},
{id:1480,cat:"ev",type:"judgment",q:"电动汽车发生碰撞后，高压电池系统会自动切断（Pyrofuse/高压保险断开），确保救援安全。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"电动汽车碰撞传感器检测到碰撞（安全气囊展开级别）→自动触发高压电池断开（Pyrofuse或高压接触器断开）→高压系统与电池隔离→防止触电和短路起火。但需要注意：即使系统断开，电池内部仍有高压存在——救援人员仍需按照高压安全规则操作。",tip:"口诀：撞车后高压电自动断（Pyrofuse炸断）。但电池里面还有电，救援仍要按高压安全来。"},
{id:1481,cat:"ev",type:"choice",q:"消防员/救援人员处理电动汽车事故时，首先要做什么？",opts:["直接用水冲","确认车辆类型→切断12V低压电源（低压断电后高压接触器断开）→识别并避免接触高压橙色线束和部件","撬开电池","不管类型直接破拆"],ans:1,exp:"EV事故救援标准步骤：①确认车辆是电动/混动（车身标识、无排气管等）；②找到12V蓄电池→断电（拔负极）→高压系统接触器断电→等待数分钟电容放电；③避开橙色高压线束（>60V DC）和高压电池组；④可用大量水扑救电池火灾（降温>灭火，水和锂会发生剧烈反应但水量大时可以散热阻止热失控蔓延）。",tip:"口诀：EV事故救援=先断12V低压电→等几分钟→避开橙色高压线→可用大量水给电池降温。"},
{id:1482,cat:"ev",type:"judgment",q:"电动汽车的高压线束通常为橙色，以区别于12V低压线路。非专业人员不得触摸或切割橙色线束。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"电动车高压线束统一规范为橙色（国际标准ISO 6469），电压范围通常200-800V DC（远高于安全电压60V）。非专业人员严禁接触橙色线束，严禁切割（即使车辆看起来已断电）。只有经过专业培训的救援人员可以按安全程序操作。",tip:"口诀：橙色线=高压（200-800V），会电死人的。非专业人员别碰。"},
{id:1483,cat:"ev",type:"choice",q:"电动汽车电池冷却系统（Battery Thermal Management System, 电池热管理系统）通常使用什么冷却方式？",opts:["仅风冷","液冷（防冻液循环）为主（部分低端车用风冷），通过散热器散热，是电池安全的关键系统","不需要冷却","仅靠自然散热"],ans:1,exp:"主流电动车电池采用液冷（防冻液/冷却液）循环系统，与空调系统联动（Chiller冷却器在制冷模式下冷却冷却液）。液冷效率远高于风冷，是确保电池安全、延长寿命、支持快充的关键。电池热管理系统故障=可能限功率、限充电速度、甚至引发热失控。需定期检查冷却液位和管路。",tip:"口诀：电池散热=液冷为主（防冻液循环）。冷却液位要定期检查，热管理系统坏了=电池危险。"},
{id:1484,cat:"ev",type:"judgment",q:"电动汽车的12V辅助蓄电池（小电瓶）亏电时，车辆即使是满电状态也可能无法启动（无法接通高压系统）。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"电动车有两个电气系统：高压（动力电池，驱动电机和空调等）和12V低压（辅助电池，供电给ECU、中控屏幕、灯光、门锁、高压接触器控制等）。12V电池亏电→高压接触器无法吸合→即使动力电池满电也无法启动（类似油车的启动电池亏电发动机无法点火）。需要跨接搭电或更换12V电池。",tip:"口诀：电车也有12V小电瓶=车的\"大脑供电\"。小电瓶没电=大电池有电也启动不了。需要搭电。"},
{id:1485,cat:"ev",type:"choice",q:"电动汽车的驾驶模式（Eco/Normal/Sport/雪地模式等）中，Eco模式（经济模式）的典型特点是什么？",opts:["提供最大动力输出","限制电机功率输出、降低空调能耗、调整能量回收强度（通常增强回收）以延长续航里程","用于高速赛车","关闭所有电子辅助"],ans:1,exp:"Eco模式=以续航最大化为目标：电机输出功率受限（加速踏板响应变「软」）、最高车速可能降低、空调压缩机和暖风功率降低、能量回收（Regen）通常增强、油门踏板阻尼感增强以阻止激烈驾驶。适合市区代步和电量低时使用。Sport模式则相反——全力输出。",tip:"口诀：Eco=省电模式。油门变\"肉\"、空调变弱、回收变强。电量低时用Eco撑里程。"},
{id:1486,cat:"ev",type:"judgment",q:"电动汽车的「单踏板驾驶模式」（One-Pedal Driving, 松开油门即强能量回收减速至停止）可以完全替代刹车踏板，驾驶时不需要使用刹车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"单踏板模式≠不需要刹车。①紧急情况下能量回收的制动力不足（最大约0.2-0.3G，机械刹车可达1.0G以上）→仍需踩刹车；②低温或满电时能量回收可能受限或关闭→松油门没有制动力（驾驶人不适应导致追尾）；③倒车和极低速蠕行时通常不适用单踏板。刹车踏板始终是最终的制动保证。",tip:"口诀：单踏板≠没刹车。紧急情况回收力不够，还靠刹车踏板。尤其冬天/满电时回收可能失灵。"},
{id:1487,cat:"ev",type:"choice",q:"电动汽车的能量回收系统在什么情况下不工作或受到限制？",opts:["总是工作","电池已满电（SOC=100%或接近满电）时回收受限（电能无处储存）和电池温度过低时（低温限制充电功率）","只在高速时不工作","只在低速时不工作"],ans:1,exp:"能量回收受限条件：①电池充满或接近满（SOC>95%）→回收的电能无法充入电池（BMS限制充电功率）→松油门无回收减速力（驾驶人需注意用刹车）；②电池温度极低（<0°C）→锂电池低温充电会析锂损伤电池→BMS限制或关闭回收直到电池温度上升。这两种情况下需要多用机械刹车。",tip:"口诀：回收不工作=满电（没地存电）或太冷（伤电池）。这两种情况得多用刹车，别习惯性松油门等它减速。"},
{id:1488,cat:"ev",type:"judgment",q:"驾驶电动汽车长途出行时，只需关注充电站位置即可，无需考虑充电功率和充电接口兼容性。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"长途电车出行需综合考虑：充电站位置（沿路分布）、充电功率（快充桩功率是否匹配车辆最高充电功率，60kW桩给150kW的车充电=速度减半）、接口类型（国标GB/T DC、特斯拉NACS/CCS存在兼容问题，需确认适配器）、充电站可用状态（APP上确认是否故障/被占用）、备选充电站计划（防止主选站无法使用）。",tip:"口诀：电车出远门=查充电站+查功率匹配+查接口兼容+查是否可用+备选方案。不是看见充电桩就能充。"},
{id:1489,cat:"ev",type:"choice",q:"关于电动汽车的「双向充电」（Bidirectional Charging）技术，以下哪项说法正确？",opts:["只能从电网充电","V2L（Vehicle to Load，车辆向外部电器供电，如露营用电）、V2G（Vehicle to Grid，车辆向电网回馈电能）、V2V（Vehicle to Vehicle，车对车充电），根据车型和地区不同支持的功能不同","所有电动车都支持V2G","V2L只能用于给手机充电"],ans:1,exp:"双向充电三种模式：V2L=通过专用适配器从充电口输出220V交流电，给外部电器供电（如露营、工地用电）；V2G=车辆在用电高峰时将电力回售电网；V2V=车对车充电（如用一辆车给另一辆没电的车充电）。并非所有电动车都支持这些功能，具体以车型配置为准。",tip:"口诀：双向充电=车上电可以反过来用——V2L（给电器供电）、V2G（卖电给电网）、V2V（给别的电车充电）。看车型支不支持。"},
{id:1490,cat:"ev",type:"judgment",q:"电动汽车没电抛锚时，可以像燃油车一样用普通拖车绳拖到充电站。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"多数电动车禁止四轮着地拖车（车轮旋转=驱动电机被动旋转=产生反向电动势=可能损坏电机控制器和逆变器）。正确方法：平板拖车（整车抬上平板）或部分车型允许前/后轮着地拖行（需查阅手册确认并遵循正确程序，通常需将挡位置于N挡并遵守速度/距离限制）。错误拖车方式可能导致电机和电气系统永久损坏。",tip:"口诀：电车没电=叫平板拖车（整车装上去）。不能用绳拖着走（四个轮子转→发电机逆转→烧控制器）。"},
{id:1491,cat:"ev",type:"choice",q:"关于电动汽车动力电池的质保政策，以下描述正确的是？",opts:["没有质保","国家规定不低于8年或12万公里（以先到为准），各厂家可能提供更高的质保（如终身质保/不限里程），质保范围通常覆盖电池容量衰减至<70-80%","只保1年","仅保电池起火"],ans:1,exp:"国家规定：新能源车动力电池、电机、电控系统质保期不低于8年/12万公里（2026年标准）。多数厂家在此基础上提供更优质保（如8年/16万公里、首任车主终身质保等），但需注意终身质保的细则条款（仅限首任车主、限定年行驶里程、限定保养必须在授权店等）。电池衰减至标称容量70-80%以下通常触发质保更换。",tip:"口诀：三电（电池电机电控）强制保8年/12万公里。电池掉到70-80%以下可换。终身质保权限首任车主+在4S保养。"},
{id:1492,cat:"ev",type:"judgment",q:"氢燃料电池汽车（FCEV）的排放物只有水，因此它在所有方面与传统燃油车相同。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"FCEV排放物仅为水，但驾驶和使用与传统燃油车有区别：①氢气是高压（70MPa/700bar）储存的易燃气体，须遵守氢气安全规则（加氢站操作规范、停放通风、隧道通行可能有特殊限制）；②FCEV也有高压电池（小容量），相关高压安全规则同样适用；③加氢站数量少，长途出行需规划加氢路线。",tip:"口诀：氢车排出的是水，但氢气高压易燃有特殊规矩。加氢站少，跑长途要规划。"},
{id:1493,cat:"ev",type:"choice",q:"电动汽车进入自动洗车机（隧道式/滚刷式洗车）前，正确的准备是什么？",opts:["无需任何准备","挂入N挡（空挡）、关闭自动雨刮（防洗车机滚刷触发雨刮损坏）、折叠后视镜、关闭自动驻车（Auto Hold）、确保充电口盖关好、关闭车窗天窗","挂P挡","熄火"],ans:1,exp:"EV进自动洗车机准备：挂N挡（熄火状态下需确认N挡可用，部分车需保持「Ready」状态挂N挡；传送带式洗车机可能需要熄火挂N挡两者配合）→关闭Auto Hold（防洗车过程中自动拉手刹）→关闭自动雨刮（洗车机滚刷触发雨刮可能损坏）→折叠后视镜→关闭车窗天窗→确认充电口盖严密关闭（水进入充电口=危险）。部分车辆有「洗车模式」一键完成上述操作。",tip:"口诀：电车洗车=挂N挡→关自动雨刮→关自动驻车→折后视镜→关窗→确认充电口盖紧。有洗车模式的一键搞定。"},
{id:1494,cat:"ev",type:"judgment",q:"对电动汽车进行任何涉及高压系统的改装（如改装音响、更换大灯、加装用电器等）可以由普通汽车改装店完成。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"电动汽车高压系统改装和维修须由具有电动汽车维修资质的专业人员和设备执行。触碰高压系统（尤其橙色线束）的改装=极高风险。即使改装12V低压系统（如加装行车记录仪、音响等），不当的接线可能干扰整车电气系统——应在专业门店进行并确认不影戏BMS/VCU等核心系统。改装不当可能失去原厂质保。",tip:"口诀：电车改装=找有资质的专业门店（搞不好烧车+失质保+电死人）。别让路边店碰高压系统。"},
{id:1495,cat:"ev",type:"choice",q:"蔚来等品牌的「换电模式」（Battery Swap）具有什么特点？",opts:["和充电一样慢","在换电站3-5分钟内完成满电电池更换，电池所有权通常与车身分离（车电分离/BaaS模式），可在换电站网络内换用不同健康状态的电池","只适用于特定城市","换一次电需要1小时"],ans:1,exp:"换电模式=无需等待充电，直接更换整块电池（3-5分钟完成）。车电分离（BaaS, Battery as a Service）：购买车辆时不包含电池（降低购车价格），电池以租赁/订阅方式使用，可随时在换电站更换，解决了电池衰减焦虑（换上的电池都经过检测满足标准）。目前主要为换电体系品牌（蔚来等）使用。",tip:"口诀：换电=3-5分钟满电走人。电池不用买（租的），衰减了换一块就行了。"},
{id:1496,cat:"ev",type:"judgment",q:"插电式混合动力汽车（PHEV）的电池电量耗尽后，车辆的动力和油耗表现与普通燃油车完全相同。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"PHEV电池亏电后：发动机不仅要驱动车辆还要负载较重的电池组（200-350kg）→亏电油耗通常高于同款纯燃油车→同时动力响应变差（电池不能辅助输出）。PHEV的优势在于有电时短途零油耗+无续航焦虑——日常应多充电用电行驶，而不是当燃油车开。",tip:"口诀：PHEV没电了≠普通油车。背着几百公斤电池跑=比油车还费油。要充电用，别当油车开。"},
{id:1497,cat:"ev",type:"choice",q:"电动汽车直流快充（DC Fast Charging）的充电曲线（Power vs SOC）通常是什么形状？",opts:["一直保持最高功率","开始阶段功率最高（电池低SOC时）、中间阶段功率下降（SOC 50-80%）、末尾阶段功率大幅降低（SOC>80%后），即「快→慢→更慢」的曲线","功率一直递增","功率恒定不变"],ans:1,exp:"锂电池快充曲线：低SOC（<20%）→预热至合适温度后功率爬升→20-80%SOC区间以峰值功率充电→80%后为保护电池功率大幅降低（涓流充电阶段，SOC>80%后充电速度断崖式下降）。因此长途路上不建议把电充满——充到80%即可继续上路（80%到100%的时间和10%到80%差不多）。",tip:"口诀：快充像吃饭——前面大口吃（低SOC充得快），八分饱以后细嚼慢咽（80%后慢如蜗牛）。长途路上充到80%就走。"},
{id:1498,cat:"ev",type:"choice",q:"电动汽车在公共充电桩充电时，关于充电枪插入的正确说法是？",opts:["充电枪必须完全插入并锁止（听到咔嗒声），未完全插入会导致接触电阻大、发热甚至起火","充电枪不需要完全插到底","半插入也能安全充电","插入深度不影响充电安全"],ans:0,exp:"充电枪必须完全插入锁止（听到咔嗒声且充电桩/车辆显示已连接），未完全插入=接触电阻大=发热=插头熔化甚至起火。插入后还应确认充电桩/APP显示正在充电。",tip:"口诀：充电枪要插到底听到咔嗒锁住。半插=接触不良=发热=烧插头。"},
{id:1499,cat:"ev",type:"choice",q:"2026年关于低速电动车（老年代步车/低速电动四轮车）的管理规定正确的是？",opts:["可以无证无牌上路","应纳入机动车管理，需登记上牌、驾驶人需持有相应驾驶证、购买交强险","只限制城市","可以在高速公路上行驶"],ans:1,exp:"2026年新规将低速电动车纳入机动车规范化管理：须经工信部公告车型目录登记上牌（悬挂专用号牌）、驾驶人需持有C3或以上驾驶证、须购买交强险、仅限在规定的道路上行驶（不得进入高速公路和城市快速路）。无证无牌上路将面临处罚。",tip:"口诀：低速电动车=也要上牌+有驾照+交强险+禁上高速。不是以前的三不管地带了。"},
{id:1500,cat:"ev",type:"judgment",q:"电动汽车在充电过程中，如果发现充电枪或充电口持续异常发热、有烧焦味或冒烟，应立即按下充电桩急停按钮并拔掉充电枪。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"充电异常=先按充电桩的「紧急停止」按钮（红色蘑菇头按钮，切断充电桩供电）→不要直接用手拔发热/冒烟的充电枪（可能烫伤/触电）→拨打充电桩运营方电话和119（如有明火或浓烟）→人员远离等待。先断电再考虑拔枪——通电状态下拔可能产生电弧。",tip:"口诀：充电异热/冒烟=先按急停按钮（红蘑菇头）断电→再想办法拔枪（别直接上手）。通电拔=电弧。"},
{id:1501,cat:"ev",type:"choice",q:"关于增程式电动车（EREV/REEV）的正确描述是？",opts:["只能充电不能加油","车辆由电动机直接驱动，发动机仅作为发电机给电池充电（不直接驱动车轮）；有电时用电，电量低时发动机启动发电→延长续航","发动机直接驱动车轮","和纯电动车完全一样"],ans:1,exp:"增程式电动车=电动机驱动车轮+发动机仅作发电机（工作时向电池充电或直接供电电机，发动机不连接传动轴）。有电=纯电行驶（零油耗）；电量低→发动机启动发电（油耗约5-8L/100km）→续航可达800-1000km+。是纯电车和燃油车的折中方案，城市用电、长途用油。",tip:"口诀：增程=发动机只发电（不驱动轮子），电机负责跑。有电用电，没电发动机发电带电机继续跑。"},
{id:1502,cat:"ev",type:"judgment",q:"电动汽车涉水能力不如燃油车，因为电池和高压系统一旦进水就会短路损坏。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"恰恰相反——多数电动车（尤其SUV平台电动车）的电池和高压系统具有IP67甚至IP69K防水等级（可浸入1米水深30分钟），涉水能力通常优于燃油车（燃油车有进气道，水进入发动机会「顶缸」损坏）。但涉水深度仍受限于：①门封和车内电子设备（非高压部分防水差）；②涉水后应尽快到4S店检查电池包和高压连接器是否有水气渗入。",tip:"口诀：电车涉水能力≥油车（电池密封好，没进气道）。但车舱电子设备不防水，涉水后还是要去检查。"},
{id:1503,cat:"ev",type:"choice",q:"电动汽车长时间不使用（超过1个月），应如何正确存放以保护电池？",opts:["充满电存放","保持电池电量在50-80%（最佳存放SOC约50-60%），每隔1-2个月检查并补充电量至该范围，存放环境温度适中（10-30°C最佳）","完全放空存放","不需任何处理"],ans:1,exp:"锂电池长期存放最佳条件：SOC保持在50-60%（过高=加速正极氧化和电解液分解；过低=电池自放电至0V→过放电→不可逆损坏）→每1-2个月检查电量→存放温度5-25°C（不要暴晒或严寒）→如有条件，连接随车充电器保持电池恒温管理系统运行。12V小电瓶也应断开负极或使用维护充电器。",tip:"口诀：电车长放=电量留一半（50-60%）→每个月检查→别暴晒别冻。满电或空电存放都伤电池。"},
{id:1504,cat:"ev",type:"choice",q:"电动汽车的电耗（百公里耗电量）受什么因素影响？",opts:["受驾驶风格显著影响——激烈驾驶和高速行驶可增加电耗30-50%","只与车辆本身有关，不受驾驶风格影响","只受温度影响","只受载重影响"],ans:0,exp:"驾驶风格对电耗影响重大：激烈加速+高速行驶（>100km/h后空气阻力剧增）+频繁加减速→电耗可增加30-50%。节能驾驶技巧：平稳加速（功率表保持在绿色ECO区）、预判路况提前松油门利用能量回收减速、高速巡航车速≤100km/h。",tip:"口诀：猛踩电门=猛掉电。稳着开、用回收、高速别超100码，续航多30-50%。"},
{id:1505,cat:"ev",type:"choice",q:"关于固态电池（Solid-State Battery, 下一代电池技术）相比液态锂电池的优势，以下哪项说法正确？",opts:["没有优势","能量密度更高、安全性更好（不可燃固态电解质替代可燃液体电解质）、充电速度更快、低温性能改善等，2026年部分高端车型已开始搭载","成本更低","仅存在于实验室"],ans:1,exp:"固态电池用固态电解质（硫化物/氧化物/聚合物）替代液态有机电解液：能量密度提升30-50%（同等重量续航更长）、本质安全（无易燃有机液，热失控温度大幅提高）、快充能力提升（电流密度更大）。2026年已进入小批量装车阶段（部分高端车型）。但成本仍高、大规模量产仍在推进中。",tip:"口诀：固态电池=更安全（不燃）+更有劲（能量密度高）+充更快。2026年已少量装车，未来方向。"},
{id:1506,cat:"ev",type:"judgment",q:"电动汽车的空调制热（暖风）在冬季对续航的影响大于制冷（冷气）在夏季对续航的影响。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"制热比制冷更费电——制冷（压缩机制冷）约消耗1-3kW；制热如采用PTC（Positive Temperature Coefficient/电阻加热，类似吹风机发热原理）消耗3-6kW甚至更高→冬季暖风对续航的影响远大于夏季冷气。配备热泵空调的车型可将制热电耗降低约40-60%（热泵=反向制冷，从外界空气中抽取热量送入车内），但仍比制冷费电。",tip:"口诀：冬天开暖风比夏天开冷气更费电。PTC制热像吹风机——巨费电。热泵空调省40-60%。"},
{id:1507,cat:"ev",type:"choice",q:"电动汽车在涉水后出现故障指示灯亮起（如绝缘报警/电池报警），正确的做法是？",opts:["继续行驶观察","立即安全停车→断开电源→联系专业维修人员进行高压系统绝缘检测","自行检查电池","用水冲洗电池组"],ans:1,exp:"涉水后绝缘报警=高压系统可能进水→绝缘电阻下降→漏电风险。应：立即停车→断开车辆电源→不要触碰任何金属部件→联系专业人员拖车检修。继续行驶可能导致高压短路起火或电击。",tip:"口诀：涉水后跳绝缘报警=高压可能进水漏电了。停车→断电→别碰→叫拖车。别继续开。"},
{id:1508,cat:"ev",type:"judgment",q:"电动汽车充电时可以在车内等待（开着空调/暖风），没有任何安全风险。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"充电时在车内=低概率但有风险：①电池/充电系统故障可能导致起火（虽然概率极低——约燃油车起火率的1/10-1/100，但一旦发生热失控逃逸时间极短<30秒）；②电磁场暴露（虽然符合安全标准但部分人群不建议长时间暴露）。建议：充电时在车外活动（服务区休息），特别是使用老旧/维护不良的充电桩时。",tip:"口诀：充电时能不在车里待就别待——万一热失控跑都来不及（<30秒）。趁充电下车活动活动。"},
{id:1509,cat:"ev",type:"choice",q:"关于电动汽车电池「热失控」（Thermal Runaway）的描述，以下哪项正确？",opts:["热失控没有危害","电池内部短路或过热引发连锁放热反应（温度迅速升高+气体释放+可能起火），热失控前可能没有任何明显征兆（或仅有非常短暂的白烟/异味），热失控不可逆且传播极快（整块电池可能在数十秒内全部热失控）","热失控过程很慢","热失控只发生在充电时"],ans:1,exp:"热失控=电池内部一旦触发不可逆的自加热链式反应→温度可迅速升至500-1000°C→产生大量可燃气体和有毒烟气→可能爆炸→并从一个电芯传播到相邻电芯（热蔓延）。热失控前兆（不一定有）：白烟/灰烟（电解液蒸气）、异味（溶剂味）、充电异常（突然停止+高温）。一旦热失控=立即弃车跑远（>30米，防爆裂碎片）+打119。",tip:"口诀：热失控=电池\"不可逆的发疯\"——几秒冒烟、几十秒全烧。看见白烟+异味=跑（>30米）+119。"},
{id:1510,cat:"smart",type:"choice",q:"高级驾驶辅助系统（ADAS）中的「传感器融合」（Sensor Fusion）是指什么？",opts:["只用摄像头","将来自多种传感器（摄像头+毫米波雷达+激光雷达+超声波传感器）的信息整合处理，利用各传感器优势互补（如：摄像头识别颜色和文字但怕暗光；雷达测距测速精准但分辨率低；激光雷达三维建模精准价高），提高对环境的感知准确度和冗余度","只用雷达","只用GPS"],ans:1,exp:"传感器融合=各取所长——摄像头：颜色、文字识别（交通标志、车道线颜色）但怕强光/暗光/雨雾；毫米波雷达（Radar）：精准测距测速、全天候、不怕光但分辨率低、识别不出静止物体大小；激光雷达（LiDAR）：高精度3D环境建模、夜间有效但贵、怕雨雾。三者融合=互为冗余、综合识别更可靠。",tip:"口诀：传感器融合=摄像头（看颜色文字）+雷达（测距测速全天候）+激光雷达（三维立体建模）。三个臭皮匠顶个诸葛亮。"},
{id:1511,cat:"smart",type:"judgment",q:"在ADAS传感器中，摄像头可以识别交通标志的颜色和文字，但受光线条件（强光/暗光/逆光）和天气（雨/雪/雾）影响很大。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"摄像头的强项=颜色识别（红绿灯、白黄车道线、红蓝标志）、文字/形状识别（限速牌数字、警告标志形状）。弱项=光线敏感（阳光直射/夜间暗光/隧道光差导致\"失明\"）、天气敏感（镜头被雨雪/泥污遮挡=完全失效）、无法直接测距（需计算图像生成距离，精确度不如雷达）。",tip:"口诀：摄像头=会\"看\"但怕光、怕脏、怕天气。像个近视眼，晚上/大雾/下雨就不灵了。"},
{id:1512,cat:"smart",type:"choice",q:"毫米波雷达（mmWave Radar, 常用77GHz）在ADAS中的主要优势是什么？",opts:["识别交通标志颜色","精准测量目标距离和相对速度（多普勒效应），全天候工作（不受光线和一般雨雾影响），但对静止物体识别能力有限","识别行人面部","生成高清3D图像"],ans:1,exp:"雷达优势：精准距离和速度测量（利用多普勒效应计算相对速度误差<0.1m/s）、全天候（雨/雪/雾/暗光不影响77GHz电磁波传输）、探测范围大（目前最长可>250米）、价格适中。劣势：分辨率低（无法识别物体类别和形状）、静止物体过滤（为防止护栏等误报，静止物体可能被忽略=无法识别前方完全停住的车辆）、无颜色和文字信息。",tip:"口诀：雷达=测距测速王（多普勒效应），全天候不\"瞎\"。但看不清是啥东西+可能忽略静止物。"},
{id:1513,cat:"smart",type:"judgment",q:"ADAS系统的自动紧急制动（AEB）在任何速度和任何天气条件下都能100%避免碰撞。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"AEB有明确的工作范围和局限：①速度范围通常为5-85km/h（E-NCAP/CNCAP测试范围），通常在30km/h以下可完全避免碰撞，30km/h以上减轻碰撞程度；②恶劣天气（暴雪/浓雾/大雨）、弯道/路口等复杂场景有效性大幅下降；③对小目标（行人儿童<1.2m、自行车横穿、动物）识别困难；④可能误触发（如隧道入口/金属路牌/减速带被误判为障碍=幽灵刹车）。",tip:"口诀：AEB≠绝对保命。低速可靠（<30码能刹停）、高速减轻（刹不住但能降速）、恶劣天气不灵、可能误触发。还是靠自己。"},
{id:1514,cat:"smart",type:"choice",q:"ADAS系统的「误触发/假阳性」（False Positive, 系统错误地判断有危险并采取制动等措施）和「漏检/假阴性」（False Negative, 有真实危险但系统没有识别出来）哪个更考验系统设计？",opts:["两者都不重要","两者都重要——假阳性导致惊吓和可能引发后车追尾（幽灵刹车），假阴性导致本可避免的事故发生。系统设计需要在灵敏度和特异性之间取得平衡","只有假阳性重要","只有假阴性重要"],ans:1,exp:"ADAS两难：太灵敏→假阳性多（无危险的制动，后车追尾风险）；太不灵敏→假阴性（真正危险时不制动或制动太晚）。工程上需要在「召回率」（真实危险检测的覆盖率）和「精准度」（减少误报）之间调校平衡。驾驶人需理解系统有这个局限——不是所有危险都能检测到，偶尔会\"狼来了\"白刹一次。",tip:"口诀：ADAS会犯错——该刹车时没刹（漏了），不该刹时刹了（吓你一跳）。所以永远不能全靠它。"},
{id:1515,cat:"smart",type:"choice",q:"关于车辆空中升级（OTA, Over-The-Air软件更新），以下哪项说法正确？",opts:["OTA更新必须在车辆安全停放、电量充足、网络稳定时进行，严禁行驶中更新","OTA更新可以在高速公路行驶中进行","OTA更新不需要网络连接","OTA更新过程中可以正常驾驶车辆"],ans:0,exp:"OTA更新必须在车辆安全停放（P挡+手刹）、电量充足（通常>20%或连接充电器）、网络稳定的条件下进行——绝对不能行驶中更新（更新过程可能涉及刹车、转向、动力系统等核心控制器升级，可能导致车辆故障或失控）。大多数车辆OTA更新过程车辆无法使用（数分钟至数小时不等）。",tip:"口诀：OTA更新=车停好+电量足+网稳+耐心等。绝对不能开着车升级。"},
{id:1516,cat:"smart",type:"choice",q:"基于导航地图的ADAS功能（如高精度地图+传感器融合的领航辅助驾驶）具有什么优势？",opts:["不需要地图","可提前预知前方道路曲率、坡度、车道拓扑结构（如弯道、匝道、分叉口），提前规划行驶策略（如减速过弯、选择正确车道）——实现「预瞄」（Beyond Line of Sight, 超视距）能力","和普通定速巡航一样","只适用于市区"],ans:1,exp:"高精度地图+传感器融合=「预瞄」能力——在传感器还没看到弯道之前，地图已提前告知弯道半径和坡度→系统可提前调整速度和挡位。传感器+地图=「看得到的地方靠传感器，看不到的地方靠地图」。尤其适用于高速公路匝道、复杂立交等场景。",tip:"口诀：传感器看眼前，高精度地图看远方。有地图的ADAS=提前知道前方弯多大、匝道在哪，提前做准备。"},
{id:1517,cat:"smart",type:"judgment",q:"驾驶监控系统（DMS, Driver Monitoring System）通过车内摄像头监测驾驶人是否分心/疲劳/闭眼等，这些摄像头采集的数据不会上传或存储，只在本车处理。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"DMS摄像头的影像涉及驾驶人隐私（驾驶舱内部影像包括驾驶人面部和乘客），不同厂家的隐私政策不同——多数厂家声称\"仅在本车处理，不上传\"，但部分厂家可能采集匿名化数据用于算法改进。驾驶人应查阅车辆的隐私条款了解DMS数据的确切处理方式。",tip:"口诀：DMS摄像头对着你（监测疲劳分心），数据去哪了要看隐私条款。多数说不上传，但最好自己确认。"},
{id:1518,cat:"smart",type:"choice",q:"不同品牌的ADAS系统性能差异很大，作为驾驶人应该怎么做？",opts:["信任所有品牌的ADAS都一样","仔细阅读本车的用户手册中ADAS章节，了解各功能的适用范围、局限条件（速度/天气/道路类型）、可能无法正常工作的场景，不跨品牌经验\"迁移\"","不看说明书靠经验","相信所有功能都在任何条件下有效"],ans:1,exp:"不同品牌ADAS的性能差异巨大——取决于传感器配置（单目/双目/三目摄像头、有无激光雷达、雷达数量）、算法成熟度、测试验证投入等。同一功能的性能可能截然不同（如某品牌的AEB在弯道/夜间行人识别率差别很大）。驾驶人必须阅读本车手册，了解具体局限，不能把其他车的经验套过来。",tip:"口诀：不同品牌的ADAS=能力天差地别。读手册了解自己车的能力边界，别想当然。"},
{id:1519,cat:"smart",type:"judgment",q:"紧急车道保持（ELK, Emergency Lane Keeping）比标准车道保持辅助（LKA）多了什么能力？——多了主动反打方向防止车辆偏离车道进入对向车道或路肩等危险区域的功能。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"LKA=车辆即将偏离车道时轻微修正方向（辅助性质）。ELK=LKA的升级版——在车辆即将偏离到对向车道（可能迎面碰撞）或路肩外（可能翻滚/撞击护栏）时，主动大幅修正方向回到安全区域。ELK通常还包括对路沿（马路牙子/路肩线）的识别能力。",tip:"口诀：LKA=轻微帮你不跑偏；ELK=紧急情况下主动把你拉回来（防止冲到对面车道或翻下路肩）。"},
{id:1520,cat:"smart",type:"choice",q:"交通拥堵辅助系统（TJA, Traffic Jam Assist）通常在什么速度范围内工作？",opts:["全速","低速范围（通常0-60km/h），在拥堵走走停停的交通中自动跟随前车（含加速、制动、自动跟停和起步），是ACC自适应巡航+LKA车道居中保持的低速组合","仅高速","仅在停车时"],ans:1,exp:"TJA=低速（0-60km/h，部分系统扩展至80km/h）的高速公路/快速路拥堵场景下的综合辅助：自动跟随前车走停（Stop & Go）、保持车道居中——大幅减轻拥堵时驾驶人的反复操作疲劳。前车停止<3秒可自动起步，超过3秒可能需轻踩油门或按键确认恢复。注意：TJA只适用于有清晰车道线的结构化道路。",tip:"口诀：TJA=堵车神器（0-60码）。帮你在堵车时自动跟车走停，不用脚酸。注意前车停超3秒需要手动确认起步。"},
{id:1521,cat:"smart",type:"judgment",q:"远程泊车辅助（Remote Parking Assist, 用手机APP遥控车辆驶入/驶出狭窄车位）可以在车辆周围有运动物体时继续自动泊车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"远程泊车辅助有明确的安全要求：①驾驶人在车辆周围一定距离内（通常蓝牙/遥控距离<6米）保持对车辆直接目视观察；②系统检测到障碍物（包括运动物体如行人、宠物、自行车）时应立即自动停止；③APP的遥控操作有反应延迟和通信中断风险，驾驶人应做好随时释放遥控按钮（停止）的准备。",tip:"口诀：手机遥控泊车=人在车旁边看着+有障碍就停+随时准备松按钮。不是无人泊车。"},
{id:1522,cat:"smart",type:"choice",q:"更换挡风玻璃后，为什么通常需要对ADAS摄像头（前视摄像头/多功能摄像头模块）进行重新标定（Calibration）？",opts:["不需要标定","因为摄像头的光学对位极其精确（偏移1°=100米外偏差约1.7米），更换挡风玻璃可能造成摄像头角度微幅改变→将导致车道识别、目标检测等严重偏差→必须进行专业设备标定（静态标定或动态路试标定）","标定只是骗子收费的借口","保险公司要求"],ans:1,exp:"前视ADAS摄像头固定在挡风玻璃内侧，其安装俯仰角/偏摆角/侧倾角极为关键——角度偏差1°可导致100米外位置偏差约1.75米（足以将左侧车道上识别到右侧车道）。更换玻璃后必须使用专用标定板（静态/服务站内）或运行路试标定程序（动态/在标准车道线道路上行驶）重新校准摄像头。未标定=ADAS功能（AEB/LKA/ACC等）可能完全失准甚至危险。",tip:"口诀：换前挡风=ADAS摄像头必须重新标定。角度差1度=100米外偏1.7米。不标定=LKA/AEB乱来。"},
{id:1523,cat:"smart",type:"judgment",q:"车辆发生碰撞后进行车身维修（如更换保险杠、前格栅、翼子板等），这些部位的雷达传感器（毫米波雷达通常安装在前格栅/保险杠后方）也需要重新标定。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"前雷达模块（通常位于前保险杠/格栅后方）的安装角度同样需要精确标定——碰撞维修后雷达角度变化会导致ACC跟车选错目标、AEB误触发或漏触发。任何涉及雷达安装位置的维修后都必须重新标定（静态角反射器标定+动态路试验证）。",tip:"口诀：修保险杠/格栅=雷达也要重新标定。碰撞后角度歪了=ACC可能对着隔壁车道测。"},
{id:1524,cat:"smart",type:"choice",q:"「自主紧急转向」（AES, Autonomous Emergency Steering）是指什么？",opts:["自动泊车","当自动紧急制动（AEB）由于制动距离不够而无法避免碰撞时，且系统检测到相邻车道有安全空间，自动执行转向避让操作以避免或减轻碰撞","自动变道","自动漂移"],ans:1,exp:"AES是AEB的补充——当传感器判断「仅靠刹车无法避免碰撞，但旁边车道有空间可以避让」时，自主执行转向避让。AES是高阶ADAS功能（通常与ELK配合），需要传感器覆盖侧方和侧后方并精确判断安全空间。目前仅部分高端车型配备。驾驶人仍应优先尝试自主刹车和转向。",tip:"口诀：AES=刹车不够用了，旁边有路就帮你拐过去。是AEB的高级补充（刹车+转向避险）。"},
{id:1525,cat:"smart",type:"judgment",q:"夜视辅助系统（Night Vision/Night Vision Assist, 红外热成像）可以在完全无照明的情况下检测行人/动物并显示在仪表盘/HUD上，但驾驶人仍需要时刻观察路面实际情况。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"夜视系统（被动红外热成像）探测发热物体（行人、动物）的温度特征，在无照明/远光灯覆盖不到的黑暗中能\"看见\"活体存在（以亮白/亮黄色显示在屏幕上），大幅提高夜间行车安全性。但有其局限：①不发热物体（石头、轮胎、静止车辆未熄火）不可见；②雨雪雾会影响红外穿透；③不可替代驾驶人的肉眼观察。",tip:"口诀：夜视=看热源（人和动物是亮的），晚上多一双\"热眼\"。但冷的东西看不见（石头/静止的车），还是得自己看路。"},
{id:1526,cat:"smart",type:"choice",q:"交叉路口碰撞预警（ICW/FCTA/FCTB, Intersection Collision Warning/交叉路口预警）的主要功能是什么？",opts:["自动通过路口","检测交叉方向来车（如十字路口侧向闯红灯车辆）并在可能发生碰撞时警告驾驶人，常用于视野受限的无信号路口或大车遮挡的盲区路口","仅用于高速路口","仅在夜间工作"],ans:1,exp:"交叉路口碰撞预警=在接近路口时，利用车辆传感器（前侧向雷达、广角摄像头、V2X车路协同信号等）检测交叉方向接近的车辆和行人，当判断存在碰撞风险时发出声光警告。对视野受限的路口（建筑物/植物/大车遮挡）和闯红灯高风险路口特别有用。注意：仅警告，不自动制动。",tip:"口诀：路口预警=帮你\"看\"被遮挡的交叉来车（盲区里的车）。看到有危险警告你，但不替你刹车。"},
{id:1527,cat:"smart",type:"judgment",q:"逆向行驶警告系统（Wrong-Way Driving Warning）可以检测车辆是否正在逆向驶入高速公路出口或单向车道，并通过声光严重警告提醒驾驶人立即纠正。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"逆向行驶警告系统=基于摄像头识别禁止驶入标志和单向车道方向，结合GPS/导航地图判断车辆逆向行驶→发出强声光警告（仪表+声音+方向盘振动）→提醒驾驶人立即停车或调头（条件允许时）。该功能对防高速公路逆行事故具有重要意义。",tip:"口诀：逆行了系统会狂报警——逆向警告=救命提醒。听到警报马上停，确认方向。"},
{id:1528,cat:"smart",type:"choice",q:"驾驶人在使用自适应巡航控制（ACC）时，以下哪种做法是错误的？",opts:["保持注意力随时准备接管","将跟车距离设为最近（1挡）以节省燃油","根据路况调整跟车距离","在恶劣天气时暂时关闭ACC手动驾驶"],ans:1,exp:"ACC跟车距离设为最近（最小跟车距离）在任何速度下都是危险设置——碰撞前给驾驶人的反应时间被极大压缩。应选择安全跟车距离：高速>100km/h时跟车距离不少于3-4挡（约2秒车距），低速时不少于2挡。","tip":"口诀：ACC别贪近——跟车距离调到最近=最快追尾。高速上至少保持2秒以上车距。"},
{id:1529,cat:"smart",type:"judgment",q:"特斯拉的「FSD」（Full Self-Driving，完全自动驾驶能力）在中国市场上已经实现了无需驾驶人监管的L5完全自动驾驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"截至2026年，特斯拉FSD在中国仍属于L2+辅助驾驶系统（部分场景L2+），驾驶人必须时刻手握方向盘并保持注意力。全球范围内尚无量产车实现L5自动驾驶。「FSD」是商品名称（有误导性），不是工程意义上的「完全自动驾驶」。",tip:"口诀：FSD≠真正的无人驾驶。名字叫\"全自动驾驶\"但法规要求=必须握方向盘+随时接管。不要被名字忽悠。"},
{id:1530,cat:"smart",type:"choice",q:"关于ADAS系统的「人机共驾」原则，以下理解最准确的是？",opts:["ADAS系统完全取代驾驶人","驾驶人始终是车辆操作的最终责任人和决策者，ADAS系统是辅助工具——驾驶人应保持对路况的持续监控（Eyes on Road），随时准备接管（Hands on Wheel或Ready to Take Over），不可过度信任系统的能力","驾驶人可以睡觉","ADAS出错时驾驶人无责任"],ans:1,exp:"「人机共驾」=驾驶人负最终安全责任，ADAS提供辅助（减轻疲劳、提醒危险、帮助决策但不能替代决策）。驾驶人应保持：眼在路面（持续监控路况）、手在方向盘附近/手握方向（随时接管）、心在驾驶上（不分心）。过度依赖ADAS=最大的人机协同失败风险。",tip:"口诀：人机共驾=人是老板，系统是小秘。眼盯路+手备方向+心在开车。系统做不了主。"},
{id:1531,cat:"smart",type:"judgment",q:"使用LDW（车道偏离警告）时，如果系统频繁发出偏离警告，说明驾驶人驾驶姿势或车道保持有问题，应休息调整而不是关闭系统。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"LDW频繁警告≠系统烦人——而是提醒你车道保持有问题，可能因为疲劳、分心或技术水平不足。应：停车休息调整（最根本解决方案）、检查驾驶姿势和注意力水平。直接关闭警告（系统允许关闭）=把问题藏起来，事故风险仍在。",tip:"口诀：LDW老叫=你老跑偏。别怪系统烦，是你开车有问题。休息调整，别关了了事。"},
{id:1532,cat:"smart",type:"choice",q:"OTA升级后ADAS功能的行为可能会发生变化（如AEB触发灵敏度调整、LKA介入力度变化等），驾驶人应该怎么做？",opts:["不管它","每次OTA升级后仔细阅读更新日志（Release Notes/更新说明），了解哪些功能发生了变化，在驾驶中适应新的系统行为","拒绝所有OTA","尝试破解系统恢复到旧版本"],ans:1,exp:"OTA升级可能改变ADAS功能的行为特征——升级后系统可能更灵敏或更保守。驾驶人应：阅读更新日志了解变化→在安全环境下重新熟悉系统的新行为→不根据旧经验预判新系统的反应。这是OTA时代驾驶人的新素养。",tip:"口诀：OTA后ADAS可能\"性格\"变了。看更新日志+重新熟悉。上个月的驾驶经验可能已经过时。"},
{id:1533,cat:"smart",type:"judgment",q:"BSD（盲区监测系统，Blind Spot Detection/并线辅助）的警告灯（通常在后视镜上或内侧）亮起时，说明可以安全变道。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"BSD警告灯亮=有车在盲区=不能变道！警告灯不亮=系统未检测到（但不保证真没有——系统可能有漏检）。变道的最终判断仍应是驾驶人通过后视镜和回头检查（Shoulder Check）进行确认。",tip:"口诀：BSD灯亮了=盲区有车不宜变道。灯不亮≠绝对安全（可能漏检）。变道前还是要自己看一眼确认。"},
{id:1534,cat:"smart",type:"choice",q:"在使用ACC（自适应巡航）+LKA（车道居中保持）的高速公路路段，驾驶人双手短暂离开方向盘去拧瓶盖喝水，系统的典型反应是什么？",opts:["没有任何反应","系统会在检测到方向盘无操作数秒后发出警告（声音+仪表提示\"请握方向盘\"），如仍无操作→警告增强（方向盘振动）→最终系统退出并减速停车（Safety Stop）","系统会自动变道到应急车道","自动接通远程操作员接管"],ans:1,exp:"L2级ADAS=必须持续检测驾驶人在位（通过方向盘扭矩传感器/电容传感器/DMS摄像头）。手离方向盘→数秒后一级警告→持续警告后二级增强→最终三级=系统解锁（退出辅助驾驶）并缓慢制动停车（Safety Stop/安全停车）。这是为了防止驾驶人完全撒手不管的安全设计。",tip:"口诀：手离方向盘=系统三连警告→请握方向盘→方向盘振动→退出辅助+自动减速停车。别想撒手喝个水。"},
{id:1535,cat:"smart",type:"judgment",q:"装有HUD（抬头显示/Head-Up Display）的车辆，HUD可以将导航、车速、ADAS警告等信息投射到挡风玻璃上，驾驶人无需低头查看仪表。但HUD显示的信息不可调，固定在一个亮度一种颜色。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"HUD通常可调节：亮度（自动/手动）、显示位置高低（适应不同身高驾驶人）、显示内容（可选车速、导航、ADAS警告、来电等）、颜色（通常白/绿/红等多色标识）。驾驶人应调节至适合自己的位置和亮度——过亮会在暗光环境下产生炫光。",tip:"口诀：HUD能调——亮度、高低、显示内容都能自定义。调到看着舒服不刺眼。"},
{id:1536,cat:"smart",type:"choice",q:"2026年关于L3级有条件自动驾驶在中国高速公路上的应用，以下描述正确的是？",opts:["可以睡觉","在特定高速公路路段（经审批的L3运营路段），车辆以低于60km/h速度在拥堵场景下，系统可接管全部驾驶任务（驾驶人可暂时脱离驾驶任务但不睡觉），系统在需要时会提前≥10秒通知驾驶人接管。超出适用场景必须驾驶人全程驾驶","全国高速不限速自动驾驶","L3=完全无人驾驶"],ans:1,exp:"2026年中国L3定义：有条件自动驾驶（Conditional Automation）——在经审批的特定路段（部分试点高速）、特定条件（如≤60km/h的低速拥堵跟车场景）下，系统可临时接管全部驾驶任务，驾驶人可以看视频/阅读（但不能睡觉，因为必须能在系统请求时接管）。系统需提前≥10秒发出接管请求（Take Over Request, TOR），驾驶人在此时间内接管。超出此场景（如速度>60km/h、非审批路段）=仍是L2级，驾驶人必须全程驾驶。",tip:"口诀：L3=有条件\"放手\"——仅限特定高速+低速拥堵+经审批路段。系统喊接管必须10秒内接手。别的地方还是L2。"},
{id:1537,cat:"smart",type:"judgment",q:"L3级自动驾驶系统发出接管请求（TOR, Take Over Request）后，AEB（自动紧急制动）等安全功能仍会继续工作，作为安全兜底。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"L3系统即使进入L3驾驶模式，底层安全功能（AEB、ELK等）仍时刻在线——如果驾驶人在TOR后没有及时接管且危险迫在眉睫，这些安全功能仍会触发作为最后的安全兜底（Safety Net）。但安全兜底不应被视为常规策略——驾驶人的及时接管才是设计和法规要求的。",tip:"口诀：L3=安全兜底还在（AEB紧急刹车等），但别靠这个——喊接管就得赶紧接。"},
{id:1538,cat:"newsigns",type:"choice",q:"智慧高速公路上的「车道状态指示灯」（车道上方龙门架上的红×和绿箭标志）中，黄色箭头指向斜下方表示什么？",opts:["加速","该车道前方即将关闭或汇入，请向黄色箭头所指方向变道","禁止通行","自由通行"],ans:1,exp:"车道状态指示灯：绿箭↓=通行；红×=此车道关闭；黄箭↘（斜向箭头）=车道前方即将结束/需并道，指示驾驶人在箭头所指方向变道并入相邻车道。黄色=警告/提示——前方情况有变，提前准备。",tip:"口诀：龙门架灯语——绿箭=走；红叉=停（别进来）；黄斜箭头=提前并道（前方此道没了）。"},
{id:1539,cat:"newsigns",type:"judgment",q:"「数字孪生道路标志」（Digital Twin Road Sign）是指将实体交通标志的信息通过V2X/5G直接发送到车内显示屏显示，可作为物理标志的补充或提前告知。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"数字孪生标志=物理标志的数字虚拟化——前方限速/施工/危险路段等信息通过V2X通信（车路协同）提前推送到车内HUD/仪表盘显示，让驾驶人提早获知前方路况（即使物理标志还没看见）。2026年在中国部分「车路协同示范区」已部署。数字孪生标志是物理标志的补充而非替代——物理标志仍为标配。",tip:"口诀：数字孪生=物理标志的\"分身\"，通过信号提前发到车里。人还没看到牌子，车已经显示前面有施工。"},
{id:1540,cat:"newsigns",type:"choice",q:"带有增强现实（AR）导航功能的HUD，在接近出口时通常会在挡风玻璃上显示什么图形引导？",opts:["没有任何图形","在挡风玻璃对应真实道路位置叠加虚拟箭头（如地面上\"画\"出变道方向/出口方向），AR导航箭头随着接近出口而逐渐变大","只显示文字","在仪表盘上显示静态地图"],ans:1,exp:"AR HUD导航=将导航信息（箭头、车道指引、出口名称）以增强现实方式「贴」在挡风玻璃对应真实道路位置上——如在眼看路面的同时看到地面上有虚拟箭头指示变道和出口位置（箭头随车速和距离动态变化）。大幅减少低头看导航屏幕的次数，提高安全性和直观性。",tip:"口诀：AR导航=箭头\"画\"在路上。不用低头看导航屏，挡风玻璃上箭头指示哪个方向走。"},
{id:1541,cat:"newsigns",type:"judgment",q:"基于5G/V2X的「车路协同预警标志」（如前方紧急制动预警、前方事故预警、前方拥堵预警等）会在车内仪表盘/HUD上显示信息，驾驶人可以完全依赖这些预警而不必自己观察路况。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"V2X预警是补充性信息（增加信息来源），不能替代驾驶人的视觉观察和判断。信号可能有延迟、覆盖盲区、误报或漏报。一个基本原则：任何电子警告都只是辅助参考——驾驶人自己的观察和判断仍是最核心的安全保障。",tip:"口诀：车路协同给的信息=参考。它没报≠安全。它报了=要注意。最终判断靠自己眼睛。"},
{id:1542,cat:"newsigns",type:"choice",q:"新型「实时停车位引导标志」（城市停车场引导系统电子屏）显示的内容可能不包括以下哪项？",opts:["停车场名称","剩余车位数","导航方向和距离","所有车主的姓名"],ans:3,exp:"实时停车引导标志（P标志+电子显示屏）显示：停车场名称、方向/距离、剩余可用车位数（如「XX广场停车楼 剩156位→500m」），部分还包括高度限制（如2.0m/2.2m）和收费标准、是否支持充电。是城市智慧停车系统的一部分。不会显示车主姓名——隐私保护。",tip:"口诀：停车引导屏=停车场名+剩余车位+方向距离。看到「P 156位」=还有车位，放心去。"},
{id:1543,cat:"newsigns",type:"judgment",q:"「基于空气质量指数的交通管控标志」（可变信息屏，AQI>特定阈值时限制部分高排放车辆进入某区域）已在部分城市实施。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"部分大城市已实施：当AQI（空气质量指数）达到特定阈值（如重污染天气橙色/红色预警）时，通过可变信息标志和短信/APP通知，限制高排放车辆（国三及以下柴油车等）进入指定区域。是环保+交通管控相结合的治理措施。",tip:"口诀：空气差时电子屏会显示——高排放车限行。看AQI信息屏，重污染天按规定出行。"},
{id:1544,cat:"newsigns",type:"choice",q:"「电气化公路/充电公路标志」（Electric Road System/ERS）指示的是什么？",opts:["普通公路","指示前方路段为架空接触网充电公路（供装有受电弓的电动货车使用）或感应式无线充电车道，为行驶中的电动汽车补充电能","自行车专用道","加油站"],ans:1,exp:"电气化公路（ERS）=架空接触网（类似无轨电车）或路面下铺设的感应充电线圈——配备受电弓/感应接收器的电动车辆可在行驶中充电（动态充电），补充续航。此类标志提示驾驶人前方路段有ERS设施及使用规则。2026年在中国部分示范路线（如高速公路特定路段）试运行。",tip:"口诀：充电公路=边走边充——架空线或路下感应充电。有专用标志，提示前方充电公路。"},
{id:1545,cat:"newsigns",type:"judgment",q:"「车联网示范路段标志」表示该路段提供V2X（车路协同/车联网）信号覆盖，装有V2X车载终端的车辆可接收道路侧设备发送的信息和预警。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"车联网示范路段/Connected Vehicle Corridor标志=提示驾驶人本路段有V2X信号覆盖（RSU/路侧单元），具备OBU/车载通信终端的车辆可获得实时路况信息、信号灯状态、事故预警、施工信息等推送。是车路协同技术的发展和应用标志。2026年在中国多城市和高速路段已部署。",tip:"口诀：车联网标志=这段路有\"WIFI\"——车能收到路发来的信息（红绿灯倒计时、事故预警等）。"},
{id:1546,cat:"newsigns",type:"choice",q:"「无人机交通监测区域标志」表示该路段使用无人机进行交通监控，以下理解正确的是？",opts:["无人机正在拍照","该路段为无人机交通监控覆盖区域（无人机用于违法抓拍、事故快速勘查、路况巡查等），驾驶人应遵守交规","禁止使用无人机","可以放飞无人机"],ans:1,exp:"无人机交通监测区域标志=提醒驾驶人此路段配备无人机监控——可能用于抓拍违法行为（占用应急车道、不系安全带、开车使用手机等）、快速处理事故（无人机勘查取证）、实时路况巡查。目的：提升执法效率和覆盖率，而非侵犯隐私。驾驶人只需遵守交规即可。",tip:"口诀：无人机监控标志=\"天眼\"在看着。别抱侥幸心理（应急车道/玩手机），无人机拍到一样罚。"},
{id:1547,cat:"newsigns",type:"judgment",q:"「智能人行横道」标志（Smart Crosswalk，配有行人检测传感器和地面LED警示灯带）提示驾驶人前方是智能化人行横道——当有行人通过时地面LED灯带会亮起红灯警告来车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"智能人行横道=普通斑马线+行人检测（摄像头/热成像）+嵌入路面的LED灯带（在行人踏上斑马线时自动亮起红色闪烁灯，提示来车减速）+声光警告（语音提示行人注意车辆）。是智慧交通的组成部分，尤其在夜间和视距受限路口大幅提高行人安全。驾驶人看到地面红光闪烁=有行人过街=必须停车让行。",tip:"口诀：智能斑马线=地面会亮红灯（有人过街时）。看到地面闪红光=必须停车让行。"},
{id:1548,cat:"newsigns",type:"choice",q:"「公交优先信号标志」（TSP, Transit Signal Priority）的作用是什么？",opts:["公交永远绿灯","当公交车接近路口时，交通信号灯系统适当延长绿灯时间或缩短红灯时间，优先确保公交车通过，提高公交运营效率和准点率","禁止公交以外的车通行","公交专用信号灯"],ans:1,exp:"公交优先信号（TSP/BSP, Bus Signal Priority）=公交车载发射器与路口信号机通信→信号系统根据公交运行时刻表（是否晚点）和当前信号相位，在不过度影响整体交通的情况下微调信号时间（绿灯延长数秒/红灯提前结束数秒）→让公交车更顺畅通过路口。是公共交通优先策略的技术实现。",tip:"口诀：公交优先信号=公交车靠近，绿灯多亮几秒让它过。不是永远绿灯，是微调优化。"},
{id:1549,cat:"newsigns",type:"judgment",q:"「紧急车辆优先信号标志」（Emergency Vehicle Preemption/EVP, 消防/救护/警车优先通过信号）允许特种车辆强行闯红灯，其他车辆不用避让。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"紧急车辆优先信号=特种车辆（消防/救护/警车）使用专用发射器→路口信号机接收后调整信号灯（如将所有方向变为红灯、或为特种车辆方向变为绿灯）→确保特种车辆安全快速通过路口。其他车辆应：听到警笛+看到信号变化→向两侧让路+按照信号指示行驶（给自己方向的绿灯变红灯也要停，给特种车创造安全通行空间）。",tip:"口诀：消防/救护车优先信号=红绿灯为它让路。你看到信号变了就配合避让（不管是红变绿还是绿变红）。"},
{id:1550,cat:"newsigns",type:"choice",q:"「可变限速标志」（Weather-Responsive Speed Limit Sign/Variable Speed Limit）与常规固定限速标志的区别是什么？",opts:["完全相同","可变限速标志的限速值可以根据实时天气/交通/事故等条件动态变更（电子数字显示），常规固定限速标志的限速值是固定的","可变限速标志不具法律效力","可变限速只在高速上有"],ans:1,exp:"可变限速标志=电子LED显示屏（或翻转式数字牌），显示的限速数值可据实时条件（大雾/暴雨/大风/事故/施工）变为不同于常规限速的值——且具有法律约束力。常见于高速、隧道、跨海大桥等天气敏感的特定路段。驾驶人应时刻关注并及时响应变化。",tip:"口诀：可变限速=电子屏的数字会变——天不好限速就调低。显示多少开多少。"},
{id:1551,cat:"newsigns",type:"judgment",q:"「自动驾驶泊车区标志」（Automated Valet Parking Zone/AVP Zone）表示该停车区域允许具备AVP功能的车辆在无人驾驶的情况下自动寻找车位并泊入。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"AVP（Automated Valet Parking/自动代客泊车）=进入停车场后，驾驶人在指定下车区（Drop-off Zone）下车，车辆通过场端传感器引导（激光雷达、摄像头、UWB定位等）和/或车端自动驾驶系统，自动寻找车位并泊入。取车时通过APP召唤，车辆自动从车位驶到上车区（Pick-up Zone）。2026年部分新建智能停车场已承担AVP功能。需车辆支持AVP功能且停车场已部署配套设施。",tip:"口诀：自动泊车区=下车走人，车自己找位停好。召唤取车时车自己开出来。需车+停车场都支持。"},
{id:1552,cat:"newsigns",type:"choice",q:"「MaaS出行即服务枢纽标志」（Mobility-as-a-Service Hub）通常指示什么？",opts:["加油站","综合交通换乘枢纽——集聚了共享汽车/共享单车/网约车上客点/公交站/地铁站/充电站/停车场等多种出行方式的无缝换乘点","普通公交站","停车场入口"],ans:1,exp:"MaaS枢纽（出行即服务）=将多种出行方式（地铁+公交+共享单车+网约车+共享汽车+充电桩+停车场）整合在一个地点，通过APP统一预约和支付。标志帮助驾驶人和出行者识别可进行多模式换乘的节点——如驾车至此换乘地铁进入拥堵城区（P+R, Park & Ride模式）。",tip:"口诀：MaaS枢纽=出行\"超市\"——各种出行方式（车/公交/地铁/单车/网约车）一站式换乘。P+R=车停这换地铁进城。"},
{id:1553,cat:"newsigns",type:"judgment",q:"「V2V车车通信预警标志」（车辆间通信区域标志）提示本路段内支持V2V（车辆对车辆）直接无线通信，车辆间可交换位置、速度、制动状态等信息，提高协作安全性。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"V2V（Vehicle-to-Vehicle）通信=在V2V覆盖区域，装配了通信设备的车辆之间可以不经过基站直接交换行驶数据（位置、速度、方向、加速度、制动状态、故障警告等）→实现协作式安全预警（如前方视线外有急刹车→后车即使看不到也收到信息提前减速）。是V2X技术的一个重要组成部分。",tip:"口诀：V2V=车和车\"聊天\"——前面急刹了，即使你看不到，你的车已收到消息。像车队内部的对讲机。"},
{id:1554,cat:"newsigns",type:"choice",q:"2026年新国标中新增的「电动自行车充电站」标志的主要特征是什么？",opts:["和汽车充电站标志一样","带有电动自行车轮廓图形+充电插头符号的组合标志，区别于汽车充电站标志","只有文字","不需要标志"],ans:1,exp:"随着电动自行车充电需求大增（尤其外卖/快递小哥的换电站和集中充电桩），2026年新国标新增了电动自行车专用充电/换电站标志——包含电动自行车轮廓+充电/换电符号（区别于汽车充电站的\"汽车轮廓+插头\"标志）。提示此类充电设施仅适用于电动自行车，不具备汽车充电能力。",tip:"口诀：电动自行车充电标志=电动车轮廓（小）+插头。和汽车充电站标志不同——别开车过去才发现只充两轮的。"},
{id:1555,cat:"newsigns",type:"judgment",q:"「潮汐车道」标志通常结合可变LED标志使用——根据高峰车流方向显示不同的通行方向。进入潮汐车道前，必须确认当前允许的通行方向。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"潮汐车道（可逆车道/Reversible Lane）=根据早晚高峰车流方向变化（早高峰进城流量大→车道设为进城方向；晚高峰出城流量大→车道设为出城方向），通过在龙门架上设置可变LED箭头标志（白色箭头=可通行，红×=禁止通行）指示当前方向。进入前必须看清当前指示方向，驶入错误方向=逆向行驶=12分。",tip:"口诀：潮汐车道=方向会变的车道（早晚不同）。进去前一定看清龙门架上的灯——绿箭头=能走，红叉=不能走。"},
{id:1556,cat:"newsigns",type:"choice",q:"「HOV车道标志」（High Occupancy Vehicle Lane/多乘员车道/HOV 2+）表示什么？",opts:["超车道","要求车内乘坐人数≥标志标注人数（如2+或3+）的车辆才可以使用该车道，旨在鼓励合乘、减少单人驾驶车辆、缓解拥堵","应急车道","公交车专用道"],ans:1,exp:"HOV车道（多乘员车道/合乘车道）=车内乘坐人数达到规定标准（HOV 2+=至少2人含驾驶人，HOV 3+=至少3人）才可通行的专用车道。单人车辆（只有驾驶人自己）不得驶入HOV车道。HOV车道标志通常为菱形+人数标注。驶入HOV车道的单人车辆将被处罚（利用热成像/摄像头检测车内人数）。",tip:"口诀：HOV 2+=车里至少坐2个人才能走。一个人开车别进这条道。"},
{id:1557,cat:"newsigns",type:"judgment",q:"「自动驾驶专用车道」标志（2026年新增）表示该车道仅供具有自动驾驶功能的车辆使用（需满足指定的自动驾驶等级要求），普通车辆不得驶入。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"随着L3/L4自动驾驶车辆的增加，2026年新增「自动驾驶专用车道」标志（如Robotaxi专用车道/自动驾驶物流车专用车道），仅供已注册/满足指定自动驾驶等级的车辆使用。普通车辆驶入将被电子警察抓拍处罚。设置自动驾驶专用车道的目的是在自动驾驶技术普及初期为不同能力的车辆进行物理安全隔离。",tip:"口诀：自动驾驶专用道=给有自动驾驶资质的车用的。普通车别进去，进去就罚。"},
{id:1558,cat:"newsigns",type:"choice",q:"关于「车载显示屏（仪表盘/中控屏）」上显示的数字孪生标志与实体交通标志的关系，以下说法正确的是？",opts:["车机屏幕的可以完全取代实体标志","车机屏幕的交通标志识别（TSR, Traffic Sign Recognition）是辅助信息，实际标志仍为法定依据，TSR可能出现识别错误（如误读路侧货车身上的限速贴纸、漏读被遮挡的标志），驾驶人仍应以观察实体标志为主","两者完全无关","TSR识别比实体标志更权威"],ans:1,exp:"交通标志识别（TSR）通过摄像头识别限速牌等交通标志→在仪表盘显示（如限速120图标）作为提醒。但TSR有局限：①可能被遮挡或脏污的摄像头捕捉导致识别不准；②可能误识别（如将公交车后部的限速贴纸当成交通标志——「120」的公交车尾贴纸导致TSR显示限速120km/h，但实际限速60km/h）；③对外国驾驶人不同国家标准的标志也可能识别错误。实体标志始终是法定依据，TSR只是备忘录功能。",tip:"口诀：TSR识别=辅助备忘（别当权威）。路边实体标志才是真限速。摄像头可能看错（比如把货车身上的\"120\"当限速牌），自己看最靠谱。"},
{id:1559,cat:"newsigns",type:"judgment",q:"2026年新国标交通标志中，「合并式标志」将多个标志信息整合到一个牌面上（如限速+禁止超车+注意横风三者合并），可以减少路侧标志牌的密度，驾驶人需要阅读完整牌面获取全部信息。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"合并式标志（Combination Sign）=将多个关联的交通标志整合在同一块牌面上（如：上面是限速80+下面是注意横风+再下面是禁止超车），一行一行排列，驾驶人需阅读完整牌面获取所有信息。此设计减少标志牌杆数量（更简洁美观）、减少信息分散。阅读顺序：从上到下，每个信息都是必须遵守的。",tip:"口诀：合并标志=一牌多信息（上面限速+下面风向+再下面禁超车等）。每行都得看全。"},
{id:1560,cat:"supplementary",type:"choice",q:"驾驶机动车在道路上行驶，以下哪项行为同时涉及「违反禁令标志」和「危险驾驶行为」？",opts:["高速公路逆行","压白色实线变道","违章停车","未系安全带"],ans:0,exp:"高速逆行=违反禁令标志（禁止驶入/禁止逆行）+危险驾驶行为（极易导致正面碰撞）。多项违法可以叠加处罚——高速逆行记12分。注意：此题陷阱在于\"同时涉及多项违法\"——仔细分析每项违法涉及哪类违规。",tip:"口诀：高速逆行=多重违法（禁入+逆行+危险驾驶）。重上加重=12分。"},
{id:1561,cat:"supplementary",type:"choice",q:"机动车在设有注意儿童警告标志的路段，以下哪项做法正确？",opts:["应当减速慢行并提高警惕，即使目前没有看到儿童","如果没有看到儿童就可以正常速度通过","加速通过以减少在危险区域的时间","仅在有学校标识的路段才需要减速"],ans:0,exp:"警告标志的意义=提醒该路段存在该风险（即使目前没看到儿童）——如临近学校/幼儿园区域，随时可能有儿童突然横穿。驾驶人应在警告标志区域就减速观察，看到了儿童再减速可能已经来不及。",tip:"口诀：注意儿童标志=减速+警惕，不管有没有看到小孩。标志就是告诉你这是儿童出没区。"},
{id:1562,cat:"supplementary",type:"choice",q:"关于交通肇事逃逸的处罚，以下组合正确的是？",opts:["仅罚款","造成人员伤亡后逃逸尚不构成犯罪=记12分+罚款+可以拘留+吊销驾照；构成犯罪（交通肇事罪）=追究刑事责任+吊销驾照+终身禁驾","仅吊销驾照","仅拘留"],ans:1,exp:"肇事逃逸处罚等级：①仅财产损失逃逸尚不构成犯罪=记6分+罚款+可以拘留；②造成人员轻伤以上或死亡逃逸尚不构成犯罪=记12分+罚款+可以拘留+吊销驾照；③构成交通肇事罪（有伤亡+逃逸等）=追究刑事责任+吊销驾照+终身不得重新取得驾驶证。",tip:"口诀：逃逸处罚三级跳——小伤小损=6分；伤人了=12分+吊销；构成犯罪=坐牢+终身禁驾。"},
{id:1563,cat:"supplementary",type:"judgment",q:"在设有「停车让行」（八角形红底白字STOP/停）标志的路口，即使视野良好、确认无来车，也必须完全停车（车速减至0km/h），观察确认安全后方可通过。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"停车让行（STOP标志）=强制性要求完全停车（车速减至0km/h）→观察确认安全→再通过。这与「减速让行」（倒三角/让/YIELD标志，只需减速不必完全停车）有本质区别。在很多国家，STOP标志不停车直接通过是严重违章——中国同样执行此规定。",tip:"口诀：STOP（停）=必须停死（0km/h），不是慢点就行。和\"让\"标志不同——\"让\"可以慢行，\"停\"必须停。"},
{id:1564,cat:"supplementary",type:"choice",q:"以下哪项违法行为的记分在2022年新规中由12分降为9分？①未悬挂号牌或故意遮挡号牌；②驾驶与准驾车型不符的机动车；③高速公路违法停车",opts:["①和②都是由12分降为9分（③是从6分升为9分，不属于降分）","①②③均是由12分降为9分","只有②是由12分降为9分","只有③是由12分降为9分"],ans:0,exp:"2022年新规中：①未悬挂号牌/故意遮挡号牌：12分降为9分；②准驾不符：12分降为9分（如C1开摩托车）；③高速公路违法停车：6分升为9分（注意是升分不是降分）。所以由12分降为9分的只有①②两项，③是常见陷阱。",tip:"口诀：12→9分降分的有两项——遮真牌（12→9）和准驾不符（12→9）。高速违停是反过来升的（6→9）。"},
{id:1565,cat:"supplementary",type:"judgment",q:"在高速公路或城市快速路上，驾驶机动车拨打接听手持电话的一次记9分（2026新规加重），而在普通道路上拨打接听手持电话的一次记3分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026新规按道路危险级别区分处罚：高速/快速路开车玩手机=记9分（道路车速高、事故后果严重）；普通道路开车玩手机=记3分。手机支架+免提（不用手持）不在此处罚范围但使用蓝牙/免提也分散注意力——安全建议非必要不打电话。",tip:"口诀：开车打电话记分=看路——高速/快速路=9分，普通路=3分。手持是关键词（免提不算手持但也不安全）。"},
{id:1566,cat:"supplementary",type:"choice",q:"关于「速度类违法记分对照表」，以下组合正确的是？",opts:["超速10%以下不记分","超速20%-50%=记3-6分（因车型和道路类型不同）；超速50%以上=12分；在高速/快速路上超速20%以下不记分；普通道路超速20%-50%=记3分","超速任何百分比都记12分","超速只在高速上记分"],ans:1,exp:"2026年超速记分规则（2022新规延续）：普通道路超速20%-50%=记3分；高速/快速路超速20%-50%=记6分（普通车）/记12分（校车/客车/危化品车）；任何道路超速50%以上=记12分。超速20%以下=不记分（但可能罚款/警告）。",tip:"口诀：超速记分三段——20%以下不记分、20%-50%=3-6分（看路看车）、50%以上=12分（死刑）。"},
{id:1567,cat:"supplementary",type:"judgment",q:"「疲劳驾驶」在2026新规中，驾驶载货汽车连续驾驶超过4小时未停车休息或休息时间少于20分钟的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"载货汽车疲劳驾驶（>4小时未休息或休息<20分钟）=记3分。但载客汽车（含营运客车、校车）和危险品运输车疲劳驾驶=记9分（2026新规加重）。不同车辆类型疲劳驾驶处罚不同——载客车和危化品车处罚更重（涉及更多的人命安全）。",tip:"口诀：疲劳驾驶记分看车型——货车=3分，客车/危化品车=9分。拉了人或者危险品，疲劳驾驶罪加三等。"},
{id:1568,cat:"supplementary",type:"choice",q:"关于车辆「超载/超员」的记分规则，以下哪项的描述是正确的？",opts:["都记一样的分数","校车、公路客运、旅游客运汽车超员≤20%=记6分，超员>20%=记12分；7座以上载客汽车超员50%-100%=记9分，>100%=记12分；货车超载>30%=记3分，>50%=记6分等——不同类型的超载超员记分不同","超载不记分","小型客车超员同样记12分"],ans:1,exp:"超员记分区分车型：校车/公路客运/旅游客运（涉及公众安全）标准最严——超员未达20%即记6分，超员20%以上=12分。普通客车超员相对较轻。货车超载30%以下=记1分，30-50%=记3分，50%以上=记6分。",tip:"口诀：超员看车型——校车/客车=严（12分轻松满）；货车超载30%以上才记分（1-6分）。别搞混。"},
{id:1569,cat:"supplementary",type:"judgment",q:"饮酒后驾驶营运机动车比饮酒后驾驶非营运机动车的处罚更重——营运车酒驾=15日拘留+罚款5000元+吊销驾照+5年内不得重新取得。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"营运车驾驶人酒驾=对不特定多数公众安全的严重威胁→处罚远重于非营运车。营运车酒驾=拘留15日+罚款5000元+吊销驾照+5年内禁驾（含酒精含量20-80mg/100ml）。非营运车酒驾=暂扣6个月+罚款1000-2000元+记12分。",tip:"口诀：营运车酒驾=行业死刑——15天拘留+5000元+吊销+5年禁开。开了营运车就别碰酒。"},
{id:1570,cat:"supplementary",type:"choice",q:"在没有交通信号灯、交通标志和交通标线的交叉路口，同时有来自不同方向的车辆（A车从南向北直行、B车从东向西直行、C车从西向东直行、D车从北向南左转），按照通行规则，正确的先后通行顺序是？",opts:["同时随意通行","先直行后转弯——直行车（A、B、C）先通行（其中让右方来车先行：B让A、C让B），转弯车（D）在直行车之后通行","左转优先","谁先到谁先走"],ans:1,exp:"复杂无信号路口原则：①转弯让直行（D最后）→②直行车之间：让右方来车先行（中国道路靠右行驶，右边来车的驾驶人看到的是来车的左侧面，视线较差→右方来车优先）→③所以顺序：A（南向北=东方向看西方向来车的右方）最优先、其次B、然后C、最后D。具体推演麻烦，核心记住：直行>转弯，向同时直行=让右方来车。",tip:"口诀：无信号路口=直行先走（直>转），同时直行=让你右边来的车。右>左边。"},
{id:1571,cat:"supplementary",type:"choice",q:"驾驶机动车在夜间通过急弯、坡路、拱桥、人行横道时，应如何使用灯光？",opts:["交替使用远近光灯示意","一直使用远光灯","只使用近光灯即可","不需要特别使用灯光"],ans:0,exp:"夜间通过这些特殊路段应交替闪远近光灯来提醒其他道路使用者。这既是法律规定也是文明驾驶习惯。闪灯的频率和次数：通常闪2-3次即可，不要频繁闪烁（可能被误解为挑衅）。",tip:"口诀：夜间过特殊路口=闪灯（远近交替）。闪2-3下就够了，别一直闪。"},
{id:1572,cat:"supplementary",type:"choice",q:"驾驶人看到前方有「事故多发路段」警告标志后，以下哪项做法是不必要的？",opts:["降低车速","提高警惕，注意观察路面和周围情况","增加与前车安全距离","关闭所有车窗和音响"],ans:3,exp:"事故多发路段标志=提示前方路段事故率较高→驾驶人应：降速+提高警惕（观察路面和两侧）+拉大跟车距离+避免超车变道+双手握方向盘。关闭车窗和音响并非必要——但避免音响太大声掩盖其他车辆的喇叭警告声。",tip:"口诀：事故多发路段=减速+警惕+拉距离+不超车。关窗放音乐可以但别太大声（听不到外面的警告声）。"},
{id:1573,cat:"supplementary",type:"choice",q:"关于行车记录仪的作用，以下哪项说法正确？",opts:["拍摄的视频记录可以作为交通事故责任认定的法定证据","行车记录仪视频不能作为证据使用","行车记录仪只用于记录沿途风景","事故责任认定只依据交警现场判断"],ans:0,exp:"行车记录仪影像=法定电子证据之一（《民事诉讼法》规定电子数据可作为证据）。可提供给交警和保险公司进行事故责任认定。建议定期检查记录仪是否正常工作、存储卡是否正常——需要用到时才知它故障=无法提供关键证据。",tip:"口诀：行车记录仪=移动的证据。出事故时它帮你说话。定期检查它在不在工作，别等出事发现坏了。"},
{id:1574,cat:"supplementary",type:"choice",q:"在没有中心隔离设施或中心线的城市道路上，机动车遇相对方向来车时，夜间会车应当在多少米外改为近光灯？",opts:["50米","100米","150米","200米"],ans:2,exp:"无论城市道路还是公路，夜间会车均应在150米外改用近光灯。这一距离是《道路交通安全法实施条例》的统一规定。跟车行驶也一样——150米外改近光。",tip:"口诀：会车改近光=统一150米。不论城市/公路/高速，150米是标准线。"},
{id:1575,cat:"supplementary",type:"judgment",q:"学员在学习驾驶中有道路交通安全违法行为或者造成交通事故的，由教练员承担责任。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"学员在教练员随车指导下的学车过程中，教练员是车辆的实际控制人——违法行为和事故责任由教练员承担（除非学员故意或重大过失+教练员无法预见和制止）。独立驾驶考试时则由学员本人承担责任。",tip:"口诀：学员学车=教练负责。教练有副刹车，他是最终控制人。考试时考生自己负责。"},
{id:1576,cat:"supplementary",type:"choice",q:"机动车在哪些路段不得掉头？—①铁路道口；②人行横道；③桥梁；④急弯；⑤陡坡；⑥隧道；⑦容易发生危险的路段",opts:["只有①③⑤","①②③④⑤⑥⑦全部","只有①②","没有限制"],ans:1,exp:"以上7类路段全部禁止掉头——掉头时车速低、占用道路空间大、视线受限，在这些路段掉头极度危险。此外，有禁止掉头标志/标线的路段也不得掉头。",tip:"口诀：七禁掉头路段——道口+人行道+桥+弯+坡+隧道+危险路段。凡是不安全的地方都不能掉。"},
{id:1577,cat:"supplementary",type:"choice",q:"关于机动车购买保险，以下哪项说法正确？",opts:["交强险必须购买，商业险自愿购买，保险公司不得捆绑销售","商业险也是强制购买的","可以只买商业险不买交强险","交强险可以自愿选择买或不买"],ans:0,exp:"交强险（机动车交通事故责任强制保险）是法定强制险，必须购买。商业险（车损险/三者险等）是自愿购买。任何保险公司不得以不买商业险为由拒绝承保交强险。",tip:"口诀：交强险=强制必须买（不买不能上路），商业险=自愿。保险不能捆绑销售。"},
{id:1578,cat:"supplementary",type:"choice",q:"关于「酒驾/醉驾标准数值」的正确对应是？",opts:["饮酒驾车（酒驾）：血液酒精含量20mg/100ml到<80mg/100ml；醉酒驾车（醉驾）：≥80mg/100ml","酒驾：≥50mg/100ml","醉驾：≥20mg/100ml","酒后驾车没有标准"],ans:0,exp:"酒驾/醉驾的两个法定标准：酒驾=20≤酒精含量<80mg/100ml（记12分+暂扣驾照+罚款）；醉驾=≥80mg/100ml（危险驾驶罪=拘役+罚款+吊销驾照+5年内禁考）。0-20mg/100ml=不认定酒驾但也可能影响驾驶能力。",tip:"口诀：酒驾=20到80（不含80）；醉驾=≥80。醉驾直接入刑（犯罪）。"},
{id:1579,cat:"supplementary",type:"judgment",q:"驾驶证被吊销后，驾驶人需要等待5年以上才能重新申请驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"吊销禁考时限视吊销原因而定：酒驾/醉驾吊销=2年禁考（醉驾=5年）；交通肇事等犯罪吊销=不等年限；肇事逃逸致人死亡/其他恶劣情节=终身禁驾。不是所有吊销都等5年——具体看吊销原因和判决。",tip:"口诀：吊销≠统一等5年。一般酒驾等2年，醉驾等5年，恶劣情节=终身。"},
{id:1580,cat:"supplementary",type:"choice",q:"在高速公路隧道中行驶时，以下哪项做法是正确的？",opts:["开启远光灯","开启近光灯，严禁超车，与前车保持足够安全距离，遵守隧道限速","可以随意变道","隧道内可以掉头（在双黄线处）"],ans:1,exp:"隧道内行驶规则：开近光灯+不得超车/倒车/掉头/停车（紧急情况除外）+保持车距+遵守限速（通常80km/h或更低）。隧道内事故逃生和救援困难，违规行为后果极其严重。",tip:"口诀：隧道=近光+不超+不倒+不掉+不停+保持距离。隧道里出了事，外面的人难进来救。"},
{id:1581,cat:"supplementary",type:"judgment",q:"在没有禁止掉头标志的交叉路口，直行绿灯+允许左转绿灯时，车辆可以在停止线前方路口内掉头（前提是不妨碍其他车辆和行人通行且禁止掉头的标志/标线不存在）。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"允许掉头的路口条件：无禁止掉头标志/标线+不妨碍其他车辆行人通行+在虚线或路口区域（具体看路口设计和标线）+不影响对向和相交方向的正常通行。虚线一侧可以掉头（单边虚线），实线一侧不可以。",tip:"口诀：路口掉头=无禁止掉头标志+不妨碍别人+虚线或允许区域。实线不能压着掉头。"},
{id:1582,cat:"supplementary",type:"choice",q:"以下哪项不是2026年新增的交通违法行为记分项？",opts:["在城市快速路上倒车/逆行/穿越分隔带掉头（12分）","驾驶时用手持方式使用电子设备（9分/高速）","驾驶不达标排放标准车辆进入限行区（记3分，2026新增）","闯红灯（6分）"],ans:3,exp:"闯红灯一直是6分，不是2026年新增的。2026年新增的记分项/标准调整包括：城市快速路倒车逆行掉头=12分（之前仅高速12分，快速路比照高速）、驾驶时使用电子设备高速记分加重为9分、部分城市新增排放限行区记分等。题目考查区分\"旧有规则\"和\"新增/调整\"的能力。",tip:"口诀：闯红灯一直是6分（不是新加的）。新加的有：快速路逆行/倒车=12分、电子设备高速=9分、排放区超标=3分等。"},
{id:1583,cat:"supplementary",type:"choice",q:"驾驶人在高速公路上发生故障需要救援，应拨打哪个电话？",opts:["全国统一高速公路报警救援电话12122","只能拨打110","只能找保险公司拖车","等待路过的车辆帮忙"],ans:0,exp:"12122=全国高速公路报警救援电话（除部分省份使用110/122），提供交警处置+清障车拖车调度服务。打电话时需告知：高速公路名称/编号（如G15沈海高速）、行驶方向（如北上/南向）、大概位置（最近的里程桩号/出口编号/服务区名称）。",tip:"口诀：高速求救=12122（全国统一）。报什么？——高速名+方向+位置（公里桩号/出口编号）。"},
{id:1584,cat:"supplementary",type:"choice",q:"某驾驶人在没有交通信号的路口左转弯时，与对向直行的车辆发生碰撞，在这起事故中谁负有主要责任？",opts:["直行车辆","左转弯车辆（转弯未让直行）","双方同等责任","视车速决定"],ans:1,exp:"转弯让直行=本起事故左转车辆因未让行直行车辆负主要/全部责任。左转让直行是路口通行最核心的规则之一——左转车辆对直行车辆负有绝对的礼让义务（除非有信号灯控制的左转专用信号）。",tip:"口诀：转弯撞直行=转弯的全责/主责。左转必须让直行，这是铁律。"},
{id:1585,cat:"supplementary",type:"judgment",q:"驾驶人在行车途中突遇行人横穿马路（非人行横道处），无论何种情况驾驶人都应承担全部责任。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"行人违章横穿马路≠机动车全责。交通事故责任划分看各方过失大小：行人突然冲出+机动车正常行驶无法避免=行人主责（机动车可能承担≤10%的无过错赔偿责任）。如机动车有超速/分心等过失——责任划分会更复杂。但任何情况下，生命至上=即使行人违章，也应尽力避让。",tip:"口诀：行人乱穿马路≠开车的一定全责。但不管谁的责任，你是铁包肉他是肉包铁，能避让尽量让。"},
{id:1586,cat:"supplementary",type:"choice",q:"「学法免罚」指的是什么？",opts:["不用学习","对轻微交通违法行为（如违规停车），驾驶人在'交管12123'APP上观看交通安全教育视频并答题合格后，可免于罚款和记分（本质是警告处理）","交罚款","线下学法"],ans:1,exp:"学法免罚=2026年新规柔性执法措施之一：轻微违法行为（如违规停车、未系安全带等不涉及事故和严重违法的行为）可通过学法免罚处理——在APP观看教育视频+答题合格→免除罚款和记分，但会记录为警告。一个记分周期内最多使用2次（+2次首违警告=共4次免罚机会）。",tip:"口诀：学法免罚=看视频答题换免罚（只限轻微违法）。一年最多2次+搭配2次首违警告=共4次。"},
{id:1587,cat:"supplementary",type:"choice",q:"关于黄色网格线区域的规定，以下哪项说法正确？",opts:["任何情况下都不得停车（包括临时停车和等候信号灯）","短暂停车等待信号灯是允许的","夜间没有车辆时可以临时停车","只要打双闪就可以临时停车"],ans:0,exp:"黄色网格线=绝对禁停区（禁止以任何理由、在任何时间停车，包括临时停车和等候信号灯）。通常设在重要机关/消防站/医院急诊入口等需要时刻保持通道畅通的位置。在黄网格内停车=违反禁止标线=记1分+罚款。",tip:"口诀：黄色网格=一刻都不能停。等红灯也别停在黄网格上——绕过去或者停在网格外。"},
{id:1588,cat:"supplementary",type:"choice",q:"关于轮胎磨损极限和更换标准，以下说法正确的是？",opts:["用到爆胎再换","轮胎花纹深度磨损至1.6mm（法定最低）时必须更换；使用超过6年（无论花纹深浅）建议更换；轮胎侧面有鼓包/裂纹/异常磨损应立即更换","3年必须更换","不计花纹深度"],ans:1,exp:"轮胎安全=三大更换标准：①花纹深度<1.6mm（法定下限，到磨损标记时必须更换，此时湿地制动距离已显著增加）；②胎龄>6年（橡胶老化，即使花纹还有，裂纹和性能退化增加爆胎风险）；③侧面鼓包/割裂/异常磨损（随时爆胎隐患，立即更换）。",tip:"口诀：换轮胎三信号——花纹磨到1.6mm（看磨损标记）、用了6年+、鼓包/裂纹。满足一个就换。"},
{id:1589,cat:"supplementary",type:"choice",q:"夏季高温时在高速公路上行驶，关于轮胎安全的正确做法是？",opts:["控制速度，每1.5-2小时停车休息让轮胎散热，不要超速","降低胎压以防止高温爆胎","保持最高限速行驶减少暴晒时间","向轮胎洒水降温"],ans:0,exp:"夏季高速公路路面温度>60°C+长时间高速行驶=轮胎内部温度累积（轮胎反复形变产生热量）→胎压升高+橡胶性能下降→爆胎风险增加。建议：夏季高速行驶每1.5-2小时停车休息（人休息+轮胎散热）、不要超速、检查胎压（在冷胎时检查，热胎时胎压偏高是正常的，不要因此放气）。",tip:"口诀：夏天高速=路面60度+轮胎自己发热。每2小时歇一次给轮胎散热。别超速（速度越快轮胎越热）。"},
{id:1590,cat:"supplementary",type:"choice",q:"驾驶人在路口等待左转绿灯时，正确的方向盘姿势和位置是什么？",opts:["方向盘预先向左打","保持方向盘正位（车轮正直），待绿灯且确认安全开始转弯时再打方向","方向盘向右打","没有任何要求"],ans:1,exp:"等左转时方向盘应保持正直（车轮朝前）=如果此时被后车追尾碰撞，车辆只会被推向前方（沿着车道走），而不是被推到对向车道（与迎面来车发生更严重碰撞）。这是一个简单但重要的安全习惯。",tip:"口诀：等左转时别先打方向（轮子保持正）。万一后车追尾把你顶出去，车轮正=往前推（安全），轮子歪=推去对面车道（被迎头撞）。"},
{id:1591,cat:"supplementary",type:"choice",q:"出车前对车辆安全技术性能进行检查，以下哪项说法正确？",opts:["是驾驶人的法定义务，不得驾驶安全设施不齐全的机动车上路","只是建议，不是法律义务","只要感觉车况正常就不需要检查","只需要在长途行驶前检查"],ans:0,exp:"出车前检查=驾驶人的法定义务（不是建议）。包括：灯光、制动、转向、轮胎（胎压和花纹）、雨刮器、后视镜、号牌是否清晰完整。安全设施不全如灯光不亮、刹车异常、轮胎严重磨损等仍上路行驶=违反法律规定。",tip:"口诀：出车前绕车检查是法律义务。灯光/刹车/方向/轮胎/雨刮/号牌——缺一不可。"},
{id:1592,cat:"supplementary",type:"choice",q:"以下哪种情境属于典型的「防御性驾驶」（Defensive Driving）行为？",opts:["看到绿灯就加速通过路口，不管左右","接近路口时即使绿灯也减速观察左右（以防闯红灯车辆或行人），与前车保持足够\"逃生\"距离，让其他驾驶人的错误有被你补救的空间","紧跟大货车后面以减少风阻","疲劳时继续驾驶"],ans:1,exp:"防御性驾驶核心=假设其他道路使用者可能犯错并在自己的驾驶计划中留出应对空间。例如：绿灯通过路口也要减速观察（防闯红灯）、保持安全距离（给紧急情况留时间）、看到路侧有车突然停着=它可能突然开门或启动、看到球滚到路上=后面可能有孩子追出。6个基本习惯：注意力在前方+扫视两侧+检查后视镜+保持车距+预判危险+提前计划逃生路线。",tip:"口诀：防御性驾驶=把路上其他人当\"随时会犯错\"来看。留足反应时间、留出逃生空间、绿灯也瞄路口。"},
{id:1593,cat:"supplementary",type:"judgment",q:"驾驶机动车在道路上发生交通事故，车辆驾驶人应当立即停车，保护现场；造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"发生事故的法定程序：①立即停车→②有人受伤=立即抢救（拨打120+力所能及的急救，如止血、心肺复苏等——但不要移动可能有脊柱损伤的重伤员）→③保护现场（拍照+不挪动关键物证，除非必须移动车辆以免妨碍交通）→④立即报警（122或110）。逃逸=严重加重处罚。",tip:"口诀：事故四步走——停车→救人→保护现场→报警。有人受伤先120再122。千万别跑。"},
{id:1594,cat:"supplementary",type:"choice",q:"驾驶人在转急弯时发生车辆侧滑（甩尾），正确的处置方法是？",opts:["猛踩刹车","向侧滑方向（甩尾方向）反打方向盘，同时松油门，等车辆恢复抓地后缓慢回正","向侧滑的反方向打方向","加速通过"],ans:1,exp:"侧滑/甩尾时：前驱车和后驱车的处置有细微差异但基本原则相同——①松油门（不要刹车）；②向甩尾方向温和反打方向（如车尾向右滑，方向向右打）→\"向侧滑方向转向\"；③车辆恢复抓地后缓慢回正方向。急刹和猛打方向都会放大失控。",tip:"口诀：甩尾=松油+往甩尾方向打方向（车屁股往右甩就右打方向）。别刹、别慌、缓缓回。"},
{id:1595,cat:"supplementary",type:"choice",q:"以下哪种车辆不得进入高速公路？",opts:["三轮汽车、低速载货汽车、拖拉机等设计最高时速低于70km/h的车辆","所有小轿车","所有摩托车","皮卡车"],ans:0,exp:"设计最高时速低于70km/h的机动车（包括三轮汽车、低速载货汽车、拖拉机、轮式专用机械车等）和部分摩托车（最高车速低于70km/h的）均不得进入高速公路。高速公路最低限速60km/h——车速过低的车辆无法安全融入车流。",tip:"口诀：跑不过70码的车都不能上高速。三轮汽车/低速货车/拖拉机/慢摩托=高速门外。"},
{id:1596,cat:"supplementary",type:"choice",q:"以下关于「驾驶证审验」的说法，哪项是正确的？",opts:["所有驾驶人都需要每年审验","持有大型客车/重型牵引挂车/城市公交车/中型客车/大型货车驾驶证（A1/A2/A3/B1/B2）的驾驶人，应当在每个记分周期结束后30日内接受审验。但在一个记分周期内没有记分记录的，免予本记分周期审验","驾驶证不需要审验","审验=重新考试"],ans:1,exp:"驾驶证审验主要针对：AB证（大车证）持有者——每个记分周期结束后30日内审验（但无记分记录=免审）。C证（小型汽车）一般不需年度审验（仅换证时提交身体条件证明）。70周岁以上驾驶人也需每年提交身体条件证明。审验内容包括：交通违法和事故处理情况+身体条件+累计记分。",tip:"口诀：审验主要是AB证的事（大车司机）——有记分就审，没记分免审。C证一般人不用审（到期换证就行）。"},
{id:1597,cat:"supplementary",type:"choice",q:"在没有中心线的窄路上会车，以下哪项做法正确？",opts:["有让路条件的一方应主动让对方先行，相互礼让","双方同时加速通过","体型大的车辆优先通行","其中一方倒车退到宽处让对方"],ans:0,exp:"窄路会车=有让路条件的一方（有避让区域、路面较宽侧等）应主动给对方让路。如果没有划中心线且双方让路条件相同，通常靠边停车的车辆让对方先行。窄路会车的基本原则=相互礼让、确保安全。",tip:"口诀：窄路会车=有地方让的一方让。双方差不多=靠边停的让对方。窄路礼让是基本素养。"},
{id:1598,cat:"supplementary",type:"choice",q:"在城市道路上，机动车前后风窗玻璃（挡风玻璃）不得放置或悬挂妨碍驾驶人视线的物品。以下哪项符合规定？",opts:["在挡风玻璃上贴深色膜","在车内后视镜上挂大型装饰物","在仪表台上方放置不影响视线的小型物品（如挪车电话牌），且物品高度不超过挡风玻璃下缘","用窗帘遮挡后挡风玻璃"],ans:2,exp:"妨碍视线的物品=挂在内后视镜上的大挂件、挡风玻璃上的非原厂贴纸/膜、仪表台上方太高太大的摆件（影响前方视野）。正确的做法=仪表台物品保持低矮（低于挡风玻璃下缘）、内后视镜不挂任何物品、贴膜符合透光率规定（前挡风玻璃可见光透射率≥70%）。",tip:"口诀：车里的装饰别挡视线——挂件/大摆件/深色膜都违规。前挡玻璃透光率≥70%。"},
{id:1599,cat:"supplementary",type:"choice",q:"驾考答题中，以下哪种规律可供参考（非绝对）？",opts:["出现不得/严禁/应当等词语答案往往是正确，出现可以/随便等词语答案往往是错误","所有带不得的题目答案都是正确","答题规律完全可靠不需要学习具体知识","看到正确这个词的选项一定选它"],ans:0,exp:"驾考答题的一个经验规律（不是100%）:题目用可以随意、可以不、无需考虑等放任类词语=大概率错（交通安全管理严格，很少放任）；用不得、严禁、应当、必须等严格类词语=大概率对（法规规定了大量禁止和应当事项）。但少数情况下例外——关键还在知识本身，规律只是辅助。",tip:"口诀：答题规律参考——看到可以随便的=多是错的；看到不得/严禁的=多是对的。但不是100%灵，还得看具体知识。"},
{id:1600,cat:"supplementary",type:"choice",q:"（综合压轴题）一名驾驶人取得C1驾驶证刚满1年，想增驾C6驾驶证（轻型牵引挂车，用于拖挂房车），同时还想增驾D证（普通三轮摩托车）。按照规定，以下哪项说法正确？",opts:["C1满1年可以增驾C6，但需通过科目二和科目三道路驾驶技能考试（免考科目一和科目三安全文明驾驶）；C1增驾D证需通过全部科目（不能免考），且C1和C6/D记分捆绑——共用12分","C1满1年不能增驾任何车型","增驾全部免考","增驾D证也不需考试"],ans:0,exp:"综合考察增驾规定：①C1增驾C6——C1满1年可增驾→免考科一和科三安全文明驾驶（只考科二+科三路考）；②C1增驾D——C1满1年可增驾→需通过全部科目（D证为摩托车驾驶证，考试内容不同，不能免考）；③所有驾驶证共用同一12分周期——C1+C6+D若违法，都是扣这个12分。",tip:"口诀：C1满1年能增C6（拖房车，免文科）+增D（摩托，全考）。所有驾照共用12分——不是两张证24分。"}
);
